      "code": "class UnionFind {\npublic:\n    explicit UnionFind(int n) : parent(n), componentSize(n, singleNode) {\n        iota(parent.begin(), parent.end(), firstNode);\n    }\n\n    int find(int node) {\n        if (parent[node] != node) {\n            parent[node] = find(parent[node]);\n        }\n        return parent[node];\n    }\n\n    void unite(int first, int second) {\n        int firstRoot = find(first);\n        int secondRoot = find(second);\n        if (firstRoot == secondRoot) {\n            return;\n        }\n\n        if (componentSize[firstRoot] < componentSize[secondRoot]) {\n            swap(firstRoot, secondRoot);\n        }\n\n        parent[secondRoot] = firstRoot;\n        componentSize[firstRoot] += componentSize[secondRoot];\n    }\n\n    int sizeOf(int node) {\n        return componentSize[find(node)];\n    }\n\nprivate:\n    vector<int> parent;\n    vector<int> componentSize;\n\n    static constexpr int firstNode = 0;\n    static constexpr int singleNode = 1;\n};\n\nclass Solution {\npublic:\n    int minMalwareSpread(vector<vector<int>>& graph, vector<int>& initial) {\n        int n = static_cast<int>(graph.size());\n        vector<int> isInitial(n, cleanNode);\n        for (int node : initial) {\n            isInitial[node] = infectedNode;\n        }\n\n        UnionFind uf(n);\n        for (int node = firstNode; node < n; ++node) {\n            if (isInitial[node] == infectedNode) {\n                continue;\n            }\n            for (int neighbor = node + nextNode; neighbor < n; ++neighbor) {\n                if (isInitial[neighbor] == infectedNode) {\n                    continue;\n                }\n                if (graph[node][neighbor] == edgeExists) {\n                    uf.unite(node, neighbor);\n                }\n            }\n        }\n\n        vector<unordered_set<int>> rootsBySource(n);\n        vector<int> touchCount(n, noTouches);\n\n        for (int source : initial) {\n            for (int node = firstNode; node < n; ++node) {\n                if (isInitial[node] == infectedNode) {\n                    continue;\n                }\n                if (graph[source][node] == noEdge) {\n                    continue;\n                }\n                rootsBySource[source].insert(uf.find(node));\n            }\n\n            for (int root : rootsBySource[source]) {\n                ++touchCount[root];\n            }\n        }\n\n        int answer = *min_element(initial.begin(), initial.end());\n        int bestSaved = noSavedNodes;\n\n        for (int source : initial) {\n            int saved = noSavedNodes;\n            for (int root : rootsBySource[source]) {\n                if (touchCount[root] == oneSource) {\n                    saved += uf.sizeOf(root);\n                }\n            }\n\n            if (saved > bestSaved || (saved == bestSaved && source < answer)) {\n                answer = source;\n                bestSaved = saved;\n            }\n        }\n\n        return answer;\n    }\n\nprivate:\n    static constexpr int firstNode = 0;\n    static constexpr int nextNode = 1;\n    static constexpr int cleanNode = 0;\n    static constexpr int infectedNode = 1;\n    static constexpr int noEdge = 0;\n    static constexpr int edgeExists = 1;\n    static constexpr int noTouches = 0;\n    static constexpr int noSavedNodes = 0;\n    static constexpr int oneSource = 1;\n};"
