      "code": "class Solution {\npublic:\n    int minMalwareSpread(vector<vector<int>>& graph, vector<int>& initial) {\n        int n = static_cast<int>(graph.size());\n        vector<int> isInitial(n, cleanNode);\n        for (int node : initial) {\n            isInitial[node] = infectedNode;\n        }\n\n        vector<int> componentId(n, unvisitedComponent);\n        vector<int> componentSizes;\n        vector<unordered_set<int>> sourcesByComponent;\n\n        for (int start = firstNode; start < n; ++start) {\n            if (isInitial[start] == infectedNode) {\n                continue;\n            }\n            if (componentId[start] != unvisitedComponent) {\n                continue;\n            }\n\n            int id = static_cast<int>(componentSizes.size());\n            unordered_set<int> touchingSources;\n            int size = buildCleanComponent(\n                graph,\n                isInitial,\n                componentId,\n                start,\n                id,\n                touchingSources\n            );\n            componentSizes.push_back(size);\n            sourcesByComponent.push_back(move(touchingSources));\n        }\n\n        vector<int> savedBySource(n, noSavedNodes);\n        for (\n            int id = firstComponent;\n            id < static_cast<int>(componentSizes.size());\n            ++id\n        ) {\n            const unordered_set<int>& sources = sourcesByComponent[id];\n            if (static_cast<int>(sources.size()) != oneSource) {\n                continue;\n            }\n\n            int source = *sources.begin();\n            savedBySource[source] += componentSizes[id];\n        }\n\n        int answer = *min_element(initial.begin(), initial.end());\n        int bestSaved = noSavedNodes;\n        for (int source : initial) {\n            int saved = savedBySource[source];\n            if (saved > bestSaved || (saved == bestSaved && source < answer)) {\n                answer = source;\n                bestSaved = saved;\n            }\n        }\n\n        return answer;\n    }\n\nprivate:\n    int buildCleanComponent(\n        const vector<vector<int>>& graph,\n        const vector<int>& isInitial,\n        vector<int>& componentId,\n        int start,\n        int id,\n        unordered_set<int>& touchingSources\n    ) const {\n        int n = static_cast<int>(graph.size());\n        vector<int> stack{start};\n        componentId[start] = id;\n        int size = noNodes;\n\n        while (!stack.empty()) {\n            int node = stack.back();\n            stack.pop_back();\n            ++size;\n\n            for (int neighbor = firstNode; neighbor < n; ++neighbor) {\n                if (graph[node][neighbor] == noEdge) {\n                    continue;\n                }\n                if (isInitial[neighbor] == infectedNode) {\n                    touchingSources.insert(neighbor);\n                    continue;\n                }\n                if (componentId[neighbor] != unvisitedComponent) {\n                    continue;\n                }\n\n                componentId[neighbor] = id;\n                stack.push_back(neighbor);\n            }\n        }\n\n        return size;\n    }\n\n    static constexpr int firstComponent = 0;\n    static constexpr int firstNode = 0;\n    static constexpr int cleanNode = 0;\n    static constexpr int infectedNode = 1;\n    static constexpr int noEdge = 0;\n    static constexpr int noNodes = 0;\n    static constexpr int noSavedNodes = 0;\n    static constexpr int oneSource = 1;\n    static constexpr int unvisitedComponent = -1;\n};"
