      "code": "class Solution {\npublic:\n    long long countFairPairs(\n        vector<int>& nums,\n        int lower,\n        int upper\n    ) {\n        sort(nums.begin(), nums.end());\n\n        return countPairsWithSumAtMost(nums, upper)\n            - countPairsWithSumAtMost(\n                nums,\n                static_cast<long long>(lower) - 1\n            );\n    }\n\nprivate:\n    long long countPairsWithSumAtMost(\n        const vector<int>& nums,\n        long long limit\n    ) {\n        int left = 0;\n        int right = static_cast<int>(nums.size()) - 1;\n        long long pairCount = 0;\n\n        while (left < right) {\n            long long sum = static_cast<long long>(nums[left]) + nums[right];\n            if (sum <= limit) {\n                // nums[left] can pair with every index from left + 1 to right.\n                pairCount += right - left;\n                ++left;\n            } else {\n                // Even the smallest current left is too large with this right.\n                --right;\n            }\n        }\n\n        return pairCount;\n    }\n};"
