      "code": "class Solution {\npublic:\n    long long minimumCost(vector<int>& nums, int k, int dist) {\n        int neededStarts = k - fixedFirstStartCount;\n        if (neededStarts == noExtraStartsNeeded) {\n            return nums[firstSubarrayStart];\n        }\n\n        values = nums;\n        sort(values.begin(), values.end());\n        values.erase(unique(values.begin(), values.end()), values.end());\n\n        countTree.assign(values.size() + fenwickIndexOffset, emptyCount);\n        sumTree.assign(values.size() + fenwickIndexOffset, emptySum);\n\n        long long bestExtraCost = numeric_limits<long long>::max();\n        int left = firstCandidateStart;\n        int n = static_cast<int>(nums.size());\n\n        for (int right = firstCandidateStart; right < n; ++right) {\n            addValue(nums[right], addOneCopy);\n\n            while (right - left > dist) {\n                addValue(nums[left], removeOneCopy);\n                ++left;\n            }\n\n            if (right - left + windowSizeOffset >= neededStarts) {\n                bestExtraCost = min(\n                    bestExtraCost,\n                    sumSmallestValues(neededStarts)\n                );\n            }\n        }\n\n        return static_cast<long long>(nums[firstSubarrayStart]) + bestExtraCost;\n    }\n\nprivate:\n    void addValue(int value, int deltaCount) {\n        int index = compressedIndex(value);\n        long long deltaSum = static_cast<long long>(value) * deltaCount;\n\n        for (int i = index; i < static_cast<int>(countTree.size()); i += i & -i) {\n            countTree[i] += deltaCount;\n            sumTree[i] += deltaSum;\n        }\n    }\n\n    long long sumSmallestValues(int neededCount) const {\n        int index = emptyFenwickPrefix;\n        int countBefore = emptyCount;\n        long long sumBefore = emptySum;\n\n        for (int bit = highestPowerOfTwo(); bit > emptyFenwickPrefix; bit >>= 1) {\n            int next = index + bit;\n            if (\n                next < static_cast<int>(countTree.size())\n                && countBefore + countTree[next] < neededCount\n            ) {\n                index = next;\n                countBefore += countTree[next];\n                sumBefore += sumTree[next];\n            }\n        }\n\n        int valueIndex = index;\n        int remaining = neededCount - countBefore;\n        return sumBefore + static_cast<long long>(remaining) * values[valueIndex];\n    }\n\n    int compressedIndex(int value) const {\n        auto it = lower_bound(values.begin(), values.end(), value);\n        return static_cast<int>(it - values.begin()) + fenwickIndexOffset;\n    }\n\n    int highestPowerOfTwo() const {\n        int bit = firstFenwickBit;\n        while ((bit << bitShiftStep) < static_cast<int>(countTree.size())) {\n            bit <<= bitShiftStep;\n        }\n        return bit;\n    }\n\n    vector<int> values;\n    vector<int> countTree;\n    vector<long long> sumTree;\n\n    static constexpr int firstSubarrayStart = 0;\n    static constexpr int firstCandidateStart = 1;\n    static constexpr int fixedFirstStartCount = 1;\n    static constexpr int noExtraStartsNeeded = 0;\n    static constexpr int addOneCopy = 1;\n    static constexpr int removeOneCopy = -1;\n    static constexpr int windowSizeOffset = 1;\n    static constexpr int fenwickIndexOffset = 1;\n    static constexpr int emptyFenwickPrefix = 0;\n    static constexpr int emptyCount = 0;\n    static constexpr int firstFenwickBit = 1;\n    static constexpr int bitShiftStep = 1;\n    static constexpr long long emptySum = 0;\n};"
