      "code": "class Solution {\npublic:\n    vector<vector<int>> getAncestors(\n        int n,\n        vector<vector<int>>& edges\n    ) {\n        vector<vector<int>> reverseGraph(n);\n        for (const vector<int>& edge : edges) {\n            int from = edge[fromIndex];\n            int to = edge[toIndex];\n            reverseGraph[to].push_back(from);\n        }\n\n        vector<vector<int>> answer(n);\n        for (int node = 0; node < n; ++node) {\n            vector<bool> seen(n, false);\n            collectAncestors(node, reverseGraph, seen);\n\n            for (int ancestor = 0; ancestor < n; ++ancestor) {\n                if (seen[ancestor]) {\n                    answer[node].push_back(ancestor);\n                }\n            }\n        }\n        return answer;\n    }\n\nprivate:\n    static constexpr int fromIndex = 0;\n    static constexpr int toIndex = 1;\n\n    void collectAncestors(\n        int node,\n        const vector<vector<int>>& reverseGraph,\n        vector<bool>& seen\n    ) {\n        for (int parent : reverseGraph[node]) {\n            if (seen[parent]) {\n                continue;\n            }\n\n            // In the original graph, parent can reach node.\n            seen[parent] = true;\n            collectAncestors(parent, reverseGraph, seen);\n        }\n    }\n};"
