      "code": "class Solution {\npublic:\n    int countSubIslands(\n        vector<vector<int>>& grid1,\n        vector<vector<int>>& grid2\n    ) {\n        rowCount = static_cast<int>(grid2.size());\n        columnCount = static_cast<int>(grid2[0].size());\n\n        removeIslandsThatTouchGrid1Water(grid1, grid2);\n\n        int subIslandCount = 0;\n        for (int row = 0; row < rowCount; ++row) {\n            for (int column = 0; column < columnCount; ++column) {\n                if (grid2[row][column] != land) {\n                    continue;\n                }\n\n                ++subIslandCount;\n                sinkIsland(row, column, grid2);\n            }\n        }\n\n        return subIslandCount;\n    }\n\nprivate:\n    static constexpr int land = 1;\n    static constexpr int water = 0;\n    static constexpr int directionCount = 4;\n    inline static constexpr array<pair<int, int>, directionCount> directions = {{\n        {1, 0},\n        {-1, 0},\n        {0, 1},\n        {0, -1},\n    }};\n\n    int rowCount = 0;\n    int columnCount = 0;\n\n    void removeIslandsThatTouchGrid1Water(\n        const vector<vector<int>>& grid1,\n        vector<vector<int>>& grid2\n    ) {\n        for (int row = 0; row < rowCount; ++row) {\n            for (int column = 0; column < columnCount; ++column) {\n                bool grid2Land = grid2[row][column] == land;\n                bool grid1Water = grid1[row][column] == water;\n                if (grid2Land && grid1Water) {\n                    // One bad cell makes the whole grid2 island invalid.\n                    sinkIsland(row, column, grid2);\n                }\n            }\n        }\n    }\n\n    void sinkIsland(\n        int row,\n        int column,\n        vector<vector<int>>& grid\n    ) {\n        grid[row][column] = water;\n\n        for (const auto& [rowDelta, columnDelta] : directions) {\n            int nextRow = row + rowDelta;\n            int nextColumn = column + columnDelta;\n            if (!isInside(nextRow, nextColumn)) {\n                continue;\n            }\n            if (grid[nextRow][nextColumn] != land) {\n                continue;\n            }\n\n            sinkIsland(nextRow, nextColumn, grid);\n        }\n    }\n\n    bool isInside(int row, int column) const {\n        return row >= 0 && row < rowCount\n            && column >= 0 && column < columnCount;\n    }\n};"
