      "code": "class Solution {\npublic:\n    vector<TreeNode*> delNodes(TreeNode* root, vector<int>& to_delete) {\n        for (int value : to_delete) {\n            deletedValues.insert(value);\n        }\n\n        dfs(root, true);\n        return forest;\n    }\n\nprivate:\n    unordered_set<int> deletedValues;\n    vector<TreeNode*> forest;\n\n    TreeNode* dfs(TreeNode* node, bool parentDeleted) {\n        if (node == nullptr) {\n            return nullptr;\n        }\n\n        bool deleted = shouldDelete(node);\n        if (parentDeleted && !deleted) {\n            // The parent edge is gone, so this node starts a new tree.\n            forest.push_back(node);\n        }\n\n        node->left = dfs(node->left, deleted);\n        node->right = dfs(node->right, deleted);\n\n        if (deleted) {\n            // Tell the parent to cut its pointer to this node.\n            return nullptr;\n        }\n        return node;\n    }\n\n    bool shouldDelete(TreeNode* node) const {\n        return deletedValues.count(node->val) > 0;\n    }\n};"
