      "code": "class Solution {\npublic:\n    int subarraysWithKDistinct(vector<int>& nums, int k) {\n        int n = static_cast<int>(nums.size());\n        vector<int> atMostKCount(n + valueLimitPadding, noFrequency);\n        vector<int> atMostLessCount(n + valueLimitPadding, noFrequency);\n        int leftK = firstIndex;\n        int leftLess = firstIndex;\n        int distinctK = noFrequency;\n        int distinctLess = noFrequency;\n        int answer = noSubarray;\n        int lessLimit = k - oneDistinct;\n\n        for (int right = firstIndex; right < n; ++right) {\n            addValue(atMostKCount, nums[right], distinctK);\n            addValue(atMostLessCount, nums[right], distinctLess);\n\n            while (distinctK > k) {\n                removeValue(atMostKCount, nums[leftK], distinctK);\n                ++leftK;\n            }\n            while (distinctLess > lessLimit) {\n                removeValue(atMostLessCount, nums[leftLess], distinctLess);\n                ++leftLess;\n            }\n\n            // Starts from leftK to leftLess - 1 have exactly k values.\n            answer += leftLess - leftK;\n        }\n\n        return answer;\n    }\n\nprivate:\n    void addValue(\n        vector<int>& frequency,\n        int value,\n        int& distinct\n    ) const {\n        if (frequency[value] == noFrequency) {\n            ++distinct;\n        }\n        ++frequency[value];\n    }\n\n    void removeValue(\n        vector<int>& frequency,\n        int value,\n        int& distinct\n    ) const {\n        --frequency[value];\n        if (frequency[value] == noFrequency) {\n            --distinct;\n        }\n    }\n\n    static constexpr int firstIndex = 0;\n    static constexpr int noFrequency = 0;\n    static constexpr int noSubarray = 0;\n    static constexpr int oneDistinct = 1;\n    static constexpr int valueLimitPadding = 1;\n};"
