      "code": "class Solution {\npublic:\n    int maxSumAfterPartitioning(vector<int>& arr, int k) {\n        int n = static_cast<int>(arr.size());\n        vector<long long> dp(n + prefixPadding, emptySum);\n\n        for (int end = firstLength; end <= n; ++end) {\n            long long maxValue = noValue;\n            int maxLength = min(k, end);\n\n            for (int length = firstLength; length <= maxLength; ++length) {\n                int start = end - length;\n                maxValue = max(maxValue, static_cast<long long>(arr[start]));\n\n                // The last segment is arr[start..end - 1].\n                long long candidate =\n                    dp[start] + maxValue * length;\n                dp[end] = max(dp[end], candidate);\n            }\n        }\n\n        return static_cast<int>(dp[n]);\n    }\n\nprivate:\n    static constexpr int prefixPadding = 1;\n    static constexpr int firstLength = 1;\n    static constexpr long long emptySum = 0;\n    static constexpr long long noValue = 0;\n};"
