      "code": "class Solution {\npublic:\n    void duplicateZeros(vector<int>& arr) {\n        int n = static_cast<int>(arr.size());\n        int read = firstIndex;\n        int virtualLength = emptyLength;\n\n        while (read < n && virtualLength < n) {\n            if (arr[read] == zeroValue) {\n                virtualLength += slotsForDuplicatedZero;\n            } else {\n                virtualLength += slotsForNormalValue;\n            }\n            ++read;\n        }\n\n        int write = n - lastIndexOffset;\n        --read;\n\n        if (virtualLength > n) {\n            arr[write] = zeroValue;\n            --write;\n            --read;\n        }\n\n        while (read >= firstIndex && write >= firstIndex) {\n            int value = arr[read];\n            arr[write] = value;\n            --write;\n\n            if (value == zeroValue && write >= firstIndex) {\n                arr[write] = zeroValue;\n                --write;\n            }\n            --read;\n        }\n    }\n\nprivate:\n    static constexpr int firstIndex = 0;\n    static constexpr int emptyLength = 0;\n    static constexpr int lastIndexOffset = 1;\n    static constexpr int zeroValue = 0;\n    static constexpr int slotsForNormalValue = 1;\n    static constexpr int slotsForDuplicatedZero = 2;\n};"
