      "code": "class Solution {\npublic:\n    vector<string> removeSubfolders(vector<string>& folder) {\n        sort(folder.begin(), folder.end());\n\n        vector<string> roots;\n        roots.reserve(folder.size());\n\n        for (const string& path : folder) {\n            if (roots.empty() || !isSubfolderOf(path, roots.back())) {\n                roots.push_back(path);\n            }\n        }\n\n        return roots;\n    }\n\nprivate:\n    bool isSubfolderOf(const string& path, const string& root) const {\n        if (path.size() <= root.size()) {\n            return false;\n        }\n        if (path.compare(firstIndex, root.size(), root) != sameText) {\n            return false;\n        }\n\n        return path[root.size()] == pathSeparator;\n    }\n\n    static constexpr size_t firstIndex = 0;\n    static constexpr int sameText = 0;\n    static constexpr char pathSeparator = '/';\n};"
