      "code": "class Solution {\npublic:\n    vector<string> removeSubfolders(vector<string>& folder) {\n        TrieNode root;\n        for (const string& path : folder) {\n            insert(root, path);\n        }\n\n        vector<string> answer;\n        collectRoots(root, answer);\n        return answer;\n    }\n\nprivate:\n    struct TrieNode {\n        unordered_map<string, unique_ptr<TrieNode>> children;\n        string folderPath;\n    };\n\n    void insert(TrieNode& root, const string& path) const {\n        TrieNode* node = &root;\n        vector<string> parts = splitPath(path);\n\n        for (const string& part : parts) {\n            auto& child = node->children[part];\n            if (child == nullptr) {\n                child = make_unique<TrieNode>();\n            }\n            node = child.get();\n        }\n\n        node->folderPath = path;\n    }\n\n    vector<string> splitPath(const string& path) const {\n        vector<string> parts;\n        string current;\n\n        for (int index = firstNameIndex;\n             index < static_cast<int>(path.size());\n             ++index) {\n            if (path[index] == pathSeparator) {\n                parts.push_back(current);\n                current.clear();\n                continue;\n            }\n            current.push_back(path[index]);\n        }\n\n        parts.push_back(current);\n        return parts;\n    }\n\n    void collectRoots(\n        const TrieNode& node,\n        vector<string>& answer\n    ) const {\n        if (!node.folderPath.empty()) {\n            // A complete kept folder removes all descendants below it.\n            answer.push_back(node.folderPath);\n            return;\n        }\n\n        for (const auto& entry : node.children) {\n            collectRoots(*entry.second, answer);\n        }\n    }\n\n    static constexpr int firstNameIndex = 1;\n    static constexpr char pathSeparator = '/';\n};"
