      "code": "class Solution {\npublic:\n    int threeSumMulti(vector<int>& arr, int target) {\n        unordered_map<int, long long> valueCount;\n        unordered_map<int, long long> pairSumCount;\n        long long answer = 0;\n\n        for (int currentValue : arr) {\n            int neededPairSum = target - currentValue;\n            auto pairIt = pairSumCount.find(neededPairSum);\n            if (pairIt != pairSumCount.end()) {\n                answer = (answer + pairIt->second) % modulo;\n            }\n\n            // Query first: currentValue is the third index of the triplet.\n            for (const auto& [previousValue, count] : valueCount) {\n                int newPairSum = previousValue + currentValue;\n                pairSumCount[newPairSum] = (\n                    pairSumCount[newPairSum] + count\n                ) % modulo;\n            }\n\n            ++valueCount[currentValue];\n        }\n\n        return static_cast<int>(answer);\n    }\n\nprivate:\n    static constexpr long long modulo = 1000000007LL;\n};"
