      "code": "class Solution {\npublic:\n    int findCircleNum(vector<vector<int>>& isConnected) {\n        int cityCount = static_cast<int>(isConnected.size());\n        parent.resize(cityCount);\n        componentSize.assign(cityCount, singletonSize);\n        iota(parent.begin(), parent.end(), firstCity);\n        provinceCount = cityCount;\n\n        for (int city = 0; city < cityCount; ++city) {\n            for (int nextCity = city + 1; nextCity < cityCount; ++nextCity) {\n                if (isConnected[city][nextCity] == connected) {\n                    unite(city, nextCity);\n                }\n            }\n        }\n\n        return provinceCount;\n    }\n\nprivate:\n    static constexpr int firstCity = 0;\n    static constexpr int connected = 1;\n    static constexpr int singletonSize = 1;\n\n    vector<int> parent;\n    vector<int> componentSize;\n    int provinceCount = 0;\n\n    int find(int city) {\n        if (parent[city] != city) {\n            // Path compression makes future searches jump straight to the root.\n            parent[city] = find(parent[city]);\n        }\n\n        return parent[city];\n    }\n\n    void unite(int firstCity, int secondCity) {\n        int firstRoot = find(firstCity);\n        int secondRoot = find(secondCity);\n        if (firstRoot == secondRoot) {\n            return;\n        }\n\n        if (componentSize[firstRoot] < componentSize[secondRoot]) {\n            swap(firstRoot, secondRoot);\n        }\n\n        parent[secondRoot] = firstRoot;\n        componentSize[firstRoot] += componentSize[secondRoot];\n        --provinceCount;\n    }\n};"
