      "code": "class Solution {\npublic:\n    bool isScramble(string s1, string s2) {\n        int n = static_cast<int>(s1.size());\n        if (n != static_cast<int>(s2.size())) {\n            return false;\n        }\n        if (n == 0) {\n            return true;\n        }\n\n        first = s1;\n        second = s2;\n        memo.assign(\n            n,\n            vector<vector<int>>(n, vector<int>(n + 1, unknown))\n        );\n\n        return canScramble(0, 0, n);\n    }\n\nprivate:\n    static constexpr int alphabetSize = 26;\n    static constexpr char firstLowercaseLetter = 'a';\n    static constexpr int unknown = -1;\n    static constexpr int falseValue = 0;\n    static constexpr int trueValue = 1;\n\n    string first;\n    string second;\n    vector<vector<vector<int>>> memo;\n\n    bool canScramble(int left1, int left2, int length) {\n        int& state = memo[left1][left2][length];\n        if (state != unknown) {\n            return state == trueValue;\n        }\n\n        if (first.compare(left1, length, second, left2, length) == 0) {\n            state = trueValue;\n            return true;\n        }\n\n        if (!hasSameLetters(left1, left2, length)) {\n            state = falseValue;\n            return false;\n        }\n\n        for (int cut = 1; cut < length; ++cut) {\n            bool noSwap =\n                canScramble(left1, left2, cut) &&\n                canScramble(left1 + cut, left2 + cut, length - cut);\n            if (noSwap) {\n                state = trueValue;\n                return true;\n            }\n\n            bool swapped =\n                canScramble(left1, left2 + length - cut, cut) &&\n                canScramble(left1 + cut, left2, length - cut);\n            if (swapped) {\n                state = trueValue;\n                return true;\n            }\n        }\n\n        state = falseValue;\n        return false;\n    }\n\n    bool hasSameLetters(int left1, int left2, int length) const {\n        vector<int> balance(alphabetSize, 0);\n\n        for (int offset = 0; offset < length; ++offset) {\n            ++balance[first[left1 + offset] - firstLowercaseLetter];\n            --balance[second[left2 + offset] - firstLowercaseLetter];\n        }\n\n        for (int count : balance) {\n            if (count != 0) {\n                return false;\n            }\n        }\n        return true;\n    }\n};"
