      "code": "class Solution {\npublic:\n    int maxArea(\n        int n,\n        int m,\n        vector<int>& hBars,\n        vector<int>& vBars\n    ) {\n        (void)n;\n        (void)m;\n\n        int maxHeight = longestConsecutiveRun(hBars) + extraCell;\n        int maxWidth = longestConsecutiveRun(vBars) + extraCell;\n        int side = min(maxHeight, maxWidth);\n\n        // hBars and vBars have at most 100 items, so side * side fits in int.\n        return side * side;\n    }\n\nprivate:\n    int longestConsecutiveRun(vector<int> bars) const {\n        if (bars.empty()) {\n            return noRemovedBars;\n        }\n\n        sort(bars.begin(), bars.end());\n        int best = singleBarRun;\n        int current = singleBarRun;\n\n        for (int i = firstComparableIndex;\n             i < static_cast<int>(bars.size());\n             ++i) {\n            if (bars[i] == bars[i - previousIndexStep]) {\n                continue;\n            }\n            if (bars[i] == bars[i - previousIndexStep] + consecutiveStep) {\n                current += runLengthStep;\n            } else {\n                current = singleBarRun;\n            }\n            best = max(best, current);\n        }\n\n        return best;\n    }\n\n    static constexpr int noRemovedBars = 0;\n    static constexpr int singleBarRun = 1;\n    static constexpr int extraCell = 1;\n    static constexpr int firstComparableIndex = 1;\n    static constexpr int previousIndexStep = 1;\n    static constexpr int consecutiveStep = 1;\n    static constexpr int runLengthStep = 1;\n};"
