      "code": "class Solution {\npublic:\n    int maxEvents(vector<vector<int>>& events) {\n        sort(events.begin(), events.end());\n\n        priority_queue<int, vector<int>, greater<int>> minEndDays;\n        int attended = 0;\n        int day = 0;\n        int index = 0;\n        int n = static_cast<int>(events.size());\n\n        while (index < n || !minEndDays.empty()) {\n            if (minEndDays.empty() && index < n && day < events[index][0]) {\n                day = events[index][0];\n            }\n\n            while (index < n && events[index][0] <= day) {\n                minEndDays.push(events[index][1]);\n                ++index;\n            }\n\n            while (!minEndDays.empty() && minEndDays.top() < day) {\n                minEndDays.pop();\n            }\n\n            if (!minEndDays.empty()) {\n                // Attend the event that expires first; it has the least slack.\n                minEndDays.pop();\n                ++attended;\n                ++day;\n            }\n        }\n\n        return attended;\n    }\n};"
