      "code": "class Solution {\npublic:\n    int maxEvents(vector<vector<int>>& events) {\n        sort(events.begin(), events.end());\n\n        priority_queue<int, vector<int>, greater<int>> activeEnds;\n        int attended = 0;\n        int index = 0;\n        int n = static_cast<int>(events.size());\n\n        for (int day = 1; index < n || !activeEnds.empty(); ++day) {\n            if (activeEnds.empty() && index < n && day < events[index][0]) {\n                day = events[index][0];\n            }\n\n            addStartedEvents(events, index, day, activeEnds);\n            removeExpiredEvents(day, activeEnds);\n\n            if (activeEnds.empty()) {\n                continue;\n            }\n\n            // Taking the earliest ending event keeps longer events available.\n            activeEnds.pop();\n            ++attended;\n        }\n\n        return attended;\n    }\n\nprivate:\n    void addStartedEvents(\n        const vector<vector<int>>& events,\n        int& index,\n        int day,\n        priority_queue<int, vector<int>, greater<int>>& activeEnds\n    ) {\n        int n = static_cast<int>(events.size());\n        while (index < n && events[index][0] <= day) {\n            activeEnds.push(events[index][1]);\n            ++index;\n        }\n    }\n\n    void removeExpiredEvents(\n        int day,\n        priority_queue<int, vector<int>, greater<int>>& activeEnds\n    ) {\n        while (!activeEnds.empty() && activeEnds.top() < day) {\n            activeEnds.pop();\n        }\n    }\n};"
