      "code": "class Solution {\npublic:\n    int videoStitching(vector<vector<int>>& clips, int time) {\n        if (time == 0) {\n            return 0;\n        }\n\n        sort(clips.begin(), clips.end());\n\n        int clipsUsed = 0;\n        int currentEnd = 0;\n        int nextEnd = 0;\n        int index = 0;\n        int n = static_cast<int>(clips.size());\n\n        while (currentEnd < time) {\n            // Every clip starting at or before currentEnd can be attached.\n            while (index < n && clips[index][0] <= currentEnd) {\n                nextEnd = max(nextEnd, clips[index][1]);\n                ++index;\n            }\n\n            // No attachable clip extends the covered range, so a gap exists.\n            if (nextEnd == currentEnd) {\n                return -1;\n            }\n\n            ++clipsUsed;\n            currentEnd = nextEnd;\n        }\n\n        return clipsUsed;\n    }\n};"
