      "code": "class Solution {\npublic:\n    bool leafSimilar(TreeNode* root1, TreeNode* root2) {\n        vector<TreeNode*> stack1;\n        vector<TreeNode*> stack2;\n        pushIfPresent(stack1, root1);\n        pushIfPresent(stack2, root2);\n\n        while (true) {\n            int leaf1 = 0;\n            int leaf2 = 0;\n            bool hasLeaf1 = nextLeaf(stack1, leaf1);\n            bool hasLeaf2 = nextLeaf(stack2, leaf2);\n\n            if (!hasLeaf1 || !hasLeaf2) {\n                return hasLeaf1 == hasLeaf2;\n            }\n            if (leaf1 != leaf2) {\n                return false;\n            }\n        }\n    }\n\nprivate:\n    void pushIfPresent(vector<TreeNode*>& nodes, TreeNode* node) {\n        if (node != nullptr) {\n            nodes.push_back(node);\n        }\n    }\n\n    bool nextLeaf(vector<TreeNode*>& nodes, int& value) {\n        while (!nodes.empty()) {\n            TreeNode* node = nodes.back();\n            nodes.pop_back();\n\n            if (node->left == nullptr && node->right == nullptr) {\n                value = node->val;\n                return true;\n            }\n\n            // Push right first so left is processed first by the stack.\n            pushIfPresent(nodes, node->right);\n            pushIfPresent(nodes, node->left);\n        }\n\n        return false;\n    }\n};"
