      "code": "class Solution {\npublic:\n    int longestMountain(vector<int>& arr) {\n        int n = static_cast<int>(arr.size());\n        if (n < minimumMountainLength) {\n            return 0;\n        }\n\n        vector<int> up(n, 0);\n        vector<int> down(n, 0);\n\n        // up[i] counts strictly increasing edges ending at index i.\n        for (int i = 1; i < n; ++i) {\n            if (arr[i - 1] < arr[i]) {\n                up[i] = up[i - 1] + 1;\n            }\n        }\n\n        // down[i] counts strictly decreasing edges starting at index i.\n        for (int i = n - 2; i >= 0; --i) {\n            if (arr[i] > arr[i + 1]) {\n                down[i] = down[i + 1] + 1;\n            }\n        }\n\n        int best = 0;\n        for (int peak = 1; peak + 1 < n; ++peak) {\n            if (up[peak] == 0 || down[peak] == 0) {\n                continue;\n            }\n\n            best = max(best, up[peak] + down[peak] + 1);\n        }\n\n        return best;\n    }\n\nprivate:\n    static constexpr int minimumMountainLength = 3;\n};"
