      "code": "class Solution {\npublic:\n    int longestMountain(vector<int>& arr) {\n        int n = static_cast<int>(arr.size());\n        int best = 0;\n        int start = 0;\n\n        while (start < n) {\n            int end = start;\n\n            // A mountain must begin with at least one strict uphill edge.\n            if (end + 1 < n && arr[end] < arr[end + 1]) {\n                while (end + 1 < n && arr[end] < arr[end + 1]) {\n                    ++end;\n                }\n\n                // After the peak, it must have at least one strict downhill edge.\n                if (end + 1 < n && arr[end] > arr[end + 1]) {\n                    while (end + 1 < n && arr[end] > arr[end + 1]) {\n                        ++end;\n                    }\n\n                    best = max(best, end - start + 1);\n                }\n            }\n\n            // Move forward even when start could not begin a mountain.\n            start = max(end, start + 1);\n        }\n\n        return best;\n    }\n};"
