      "code": "class Solution {\npublic:\n    int numBusesToDestination(\n        vector<vector<int>>& routes,\n        int source,\n        int target\n    ) {\n        if (source == target) {\n            return 0;\n        }\n\n        unordered_map<int, vector<int>> stationToRoutes;\n        for (int route = 0; route < static_cast<int>(routes.size()); ++route) {\n            for (int station : routes[route]) {\n                stationToRoutes[station].push_back(route);\n            }\n        }\n\n        queue<int> stations;\n        unordered_set<int> visitedStations;\n        vector<char> visitedRoutes(routes.size(), false);\n\n        stations.push(source);\n        visitedStations.insert(source);\n\n        int buses = 0;\n        while (!stations.empty()) {\n            ++buses;\n            int levelSize = static_cast<int>(stations.size());\n\n            for (int i = 0; i < levelSize; ++i) {\n                int station = stations.front();\n                stations.pop();\n\n                auto stationIt = stationToRoutes.find(station);\n                if (stationIt == stationToRoutes.end()) {\n                    continue;\n                }\n\n                for (int route : stationIt->second) {\n                    if (visitedRoutes[route]) {\n                        continue;\n                    }\n                    visitedRoutes[route] = true;\n\n                    // One bus route can take us to every station on it.\n                    for (int nextStation : routes[route]) {\n                        if (nextStation == target) {\n                            return buses;\n                        }\n\n                        if (visitedStations.insert(nextStation).second) {\n                            stations.push(nextStation);\n                        }\n                    }\n                }\n            }\n        }\n\n        return -1;\n    }\n};"
