      "code": "class Solution {\npublic:\n    int maximumSwap(int num) {\n        string digits = to_string(num);\n        vector<int> lastPosition(decimalBase, missingPosition);\n\n        for (int i = 0; i < static_cast<int>(digits.size()); ++i) {\n            lastPosition[digits[i] - '0'] = i;\n        }\n\n        for (int i = 0; i < static_cast<int>(digits.size()); ++i) {\n            int currentDigit = digits[i] - '0';\n\n            // Put the largest possible digit at the earliest possible place.\n            for (int digit = largestDigit; digit > currentDigit; --digit) {\n                if (lastPosition[digit] > i) {\n                    // The recorded position is the rightmost occurrence.\n                    // It keeps the smaller current digit as far right as possible.\n                    swap(digits[i], digits[lastPosition[digit]]);\n                    return stoi(digits);\n                }\n            }\n        }\n\n        return num;\n    }\n\nprivate:\n    static constexpr int decimalBase = 10;\n    static constexpr int largestDigit = 9;\n    static constexpr int missingPosition = -1;\n};"
