      "code": "class Solution {\npublic:\n    int maximumSwap(int num) {\n        string digits = to_string(num);\n        int n = digits.size();\n        vector<int> bestPosition(n);\n        bestPosition[n - 1] = n - 1;\n\n        for (int i = n - 2; i >= 0; --i) {\n            int rightBest = bestPosition[i + 1];\n\n            if (digits[i] > digits[rightBest]) {\n                bestPosition[i] = i;\n            } else {\n                // If the digits are equal, keep the farther-right index.\n                bestPosition[i] = rightBest;\n            }\n        }\n\n        for (int i = 0; i < n; ++i) {\n            int swapIndex = bestPosition[i];\n            if (digits[swapIndex] > digits[i]) {\n                swap(digits[i], digits[swapIndex]);\n                return stoi(digits);\n            }\n        }\n\n        return num;\n    }\n};"
