      "code": "class Solution {\npublic:\n    TreeNode* trimBST(TreeNode* root, int low, int high) {\n        if (root == nullptr) {\n            return nullptr;\n        }\n\n        if (root->val < low) {\n            // The current node and its whole left subtree are too small.\n            // Only the right subtree can still contain valid values.\n            return trimBST(root->right, low, high);\n        }\n\n        if (root->val > high) {\n            // The current node and its whole right subtree are too large.\n            // Only the left subtree can still contain valid values.\n            return trimBST(root->left, low, high);\n        }\n\n        // The current node is valid. Reconnect it to the trimmed children.\n        root->left = trimBST(root->left, low, high);\n        root->right = trimBST(root->right, low, high);\n        return root;\n    }\n};"
