      "code": "class Solution {\npublic:\n    TreeNode* trimBST(TreeNode* root, int low, int high) {\n        root = moveRootIntoRange(root, low, high);\n        if (root == nullptr) {\n            return nullptr;\n        }\n\n        trimTooSmallLeftChildren(root, low);\n        trimTooLargeRightChildren(root, high);\n        return root;\n    }\n\nprivate:\n    TreeNode* moveRootIntoRange(TreeNode* root, int low, int high) {\n        while (root != nullptr && (root->val < low || root->val > high)) {\n            if (root->val < low) {\n                root = root->right;\n            } else {\n                root = root->left;\n            }\n        }\n        return root;\n    }\n\n    void trimTooSmallLeftChildren(TreeNode* root, int low) {\n        TreeNode* node = root;\n        while (node != nullptr && node->left != nullptr) {\n            if (node->left->val < low) {\n                // The left child and its left subtree are too small.\n                // Its right subtree may still fit under the current node.\n                node->left = node->left->right;\n            } else {\n                node = node->left;\n            }\n        }\n    }\n\n    void trimTooLargeRightChildren(TreeNode* root, int high) {\n        TreeNode* node = root;\n        while (node != nullptr && node->right != nullptr) {\n            if (node->right->val > high) {\n                // The right child and its right subtree are too large.\n                // Its left subtree may still fit under the current node.\n                node->right = node->right->left;\n            } else {\n                node = node->right;\n            }\n        }\n    }\n};"
