      "code": "class Solution {\nprivate:\n    struct Event {\n        int x;\n        int height;\n    };\n\npublic:\n    vector<vector<int>> getSkyline(vector<vector<int>>& buildings) {\n        vector<Event> events;\n        for (const vector<int>& building : buildings) {\n            int left = building[0];\n            int right = building[1];\n            int height = building[2];\n\n            // Negative height means a building starts at this x.\n            events.push_back({left, -height});\n            // Positive height means a building ends at this x.\n            events.push_back({right, height});\n        }\n\n        sort(events.begin(), events.end(), [](const Event& a,\n                                              const Event& b) {\n            if (a.x != b.x) {\n                return a.x < b.x;\n            }\n            return a.height < b.height;\n        });\n\n        multiset<int> activeHeights;\n        activeHeights.insert(0);\n\n        vector<vector<int>> skyline;\n        int previousHeight = 0;\n        int index = 0;\n\n        while (index < static_cast<int>(events.size())) {\n            int x = events[index].x;\n\n            // Process every start/end event at this same x before output.\n            while (index < static_cast<int>(events.size()) &&\n                   events[index].x == x) {\n                int height = events[index].height;\n                if (height < 0) {\n                    activeHeights.insert(-height);\n                } else {\n                    auto it = activeHeights.find(height);\n                    if (it != activeHeights.end()) {\n                        activeHeights.erase(it);\n                    }\n                }\n                ++index;\n            }\n\n            int currentHeight = *activeHeights.rbegin();\n            if (currentHeight != previousHeight) {\n                skyline.push_back({x, currentHeight});\n                previousHeight = currentHeight;\n            }\n        }\n\n        return skyline;\n    }\n};"
