      "code": "class Solution {\nprivate:\n    using Prefix = vector<vector<long long>>;\n\npublic:\n    int maxSideLength(vector<vector<int>>& mat, int threshold) {\n        int rows = static_cast<int>(mat.size());\n        int cols = static_cast<int>(mat[0].size());\n        Prefix prefix = buildPrefix(mat);\n\n        int best = 0;\n        for (int bottom = 1; bottom <= rows; ++bottom) {\n            for (int right = 1; right <= cols; ++right) {\n                while (best < min(bottom, right)) {\n                    int side = best + 1;\n                    int top = bottom - side;\n                    int left = right - side;\n\n                    // Only try to grow by one. Larger valid squares imply\n                    // this smaller square is valid because all values are non-negative.\n                    if (squareSum(prefix, top, left, bottom, right)\n                        > threshold) {\n                        break;\n                    }\n                    best = side;\n                }\n            }\n        }\n\n        return best;\n    }\n\nprivate:\n    Prefix buildPrefix(const vector<vector<int>>& mat) {\n        int rows = static_cast<int>(mat.size());\n        int cols = static_cast<int>(mat[0].size());\n        Prefix prefix(rows + 1, vector<long long>(cols + 1, 0));\n\n        for (int row = 1; row <= rows; ++row) {\n            for (int col = 1; col <= cols; ++col) {\n                prefix[row][col] = mat[row - 1][col - 1]\n                    + prefix[row - 1][col]\n                    + prefix[row][col - 1]\n                    - prefix[row - 1][col - 1];\n            }\n        }\n\n        return prefix;\n    }\n\n    long long squareSum(\n        const Prefix& prefix,\n        int top,\n        int left,\n        int bottom,\n        int right\n    ) {\n        // top and left are inclusive; bottom and right are exclusive.\n        return prefix[bottom][right]\n            - prefix[top][right]\n            - prefix[bottom][left]\n            + prefix[top][left];\n    }\n};"
