      "code": "class Solution {\npublic:\n    bool canWinNim(int n) {\n        const int maxTake = 3;\n        const int cycleLength = maxTake + 1;\n        vector<bool> canWin(cycleLength + 1, false);\n\n        for (int stones = 1; stones <= cycleLength; ++stones) {\n            for (int take = 1;\n                 take <= maxTake && take <= stones;\n                 ++take) {\n                if (!canWin[stones - take]) {\n                    canWin[stones] = true;\n                    break;\n                }\n            }\n        }\n\n        // The small DP shows states 1, 2, 3 win and state 4 loses.\n        // After that, each pair of turns can remove exactly 4 stones.\n        return n % cycleLength != 0;\n    }\n};"
