      "code": "class Solution {\npublic:\n    bool find132pattern(vector<int>& nums) {\n        int n = static_cast<int>(nums.size());\n        if (n < patternLength) {\n            return false;\n        }\n\n        vector<int> decreasingStack;\n        int third = numeric_limits<int>::min();\n\n        for (int index = n - 1; index >= 0; --index) {\n            int current = nums[index];\n\n            // third is a confirmed nums[k] value from the right side.\n            // If current is smaller, current can be nums[i].\n            if (current < third) {\n                return true;\n            }\n\n            // current can become nums[j]. Every smaller value popped from\n            // the right side can then become nums[k].\n            while (!decreasingStack.empty() &&\n                   current > decreasingStack.back()) {\n                third = decreasingStack.back();\n                decreasingStack.pop_back();\n            }\n\n            decreasingStack.push_back(current);\n        }\n\n        return false;\n    }\n\nprivate:\n    static constexpr int patternLength = 3;\n};"
