      "code": "class Solution {\npublic:\n    bool find132pattern(vector<int>& nums) {\n        int n = static_cast<int>(nums.size());\n        if (n < patternLength) {\n            return false;\n        }\n\n        multiset<int> rightValues(nums.begin() + 2, nums.end());\n        int leftMin = nums[0];\n\n        for (int middle = 1; middle + 1 < n; ++middle) {\n            int middleValue = nums[middle];\n\n            // We need leftMin < nums[k] < middleValue.\n            if (leftMin < middleValue) {\n                auto candidate = rightValues.upper_bound(leftMin);\n                if (candidate != rightValues.end() &&\n                    *candidate < middleValue) {\n                    return true;\n                }\n            }\n\n            leftMin = min(leftMin, middleValue);\n\n            // For the next middle index, nums[middle + 1] is no longer\n            // on the right side, so remove one copy from the multiset.\n            auto toRemove = rightValues.find(nums[middle + 1]);\n            if (toRemove != rightValues.end()) {\n                rightValues.erase(toRemove);\n            }\n        }\n\n        return false;\n    }\n\nprivate:\n    static constexpr int patternLength = 3;\n};"
