      "language": "C++",
      "status": "Reference",
      "provenance": "generated-reference",
      "approachTitle": "DFS Depth Accumulation",
      "complexity": "Time $O(n)$ / Space $O(h)$ recursion plus $O(d)$ arrays",
      "submittedAt": null,
