      "code": "class Solution {\npublic:\n    int minEatingSpeed(vector<int>& piles, int h) {\n        int left = 1;\n        int right = *max_element(piles.begin(), piles.end()) + 1;\n\n        // Search in [left, right). right is one past the largest candidate.\n        while (left < right) {\n            int speed = left + (right - left) / 2;\n\n            if (canFinish(piles, h, speed)) {\n                // speed works, so the first working speed may be smaller.\n                right = speed;\n            } else {\n                // speed is too slow, so all smaller speeds are impossible.\n                left = speed + 1;\n            }\n        }\n\n        return left;\n    }\n\nprivate:\n    bool canFinish(const vector<int>& piles, int h, int speed) {\n        long long hours = 0;\n\n        for (int pile : piles) {\n            long long needed = (\n                static_cast<long long>(pile) + speed - 1\n            ) / speed;\n            hours += needed;\n\n            if (hours > h) {\n                return false;\n            }\n        }\n\n        return true;\n    }\n};"
