      "code": "class Solution {\npublic:\n    int minEatingSpeed(vector<int>& piles, int h) {\n        int left = 1;\n        int right = *max_element(piles.begin(), piles.end());\n        int answer = right;\n\n        while (left <= right) {\n            int speed = left + (right - left) / 2;\n            long long hours = countHours(piles, speed, h);\n\n            if (hours <= h) {\n                answer = speed;\n                right = speed - 1;\n            } else {\n                left = speed + 1;\n            }\n        }\n\n        return answer;\n    }\n\nprivate:\n    long long countHours(\n        const vector<int>& piles,\n        int speed,\n        int limit\n    ) {\n        long long hours = 0;\n\n        for (int pile : piles) {\n            // For positive pile, (pile - 1) / speed + 1 is ceil(pile / speed).\n            hours += (pile - 1) / speed + 1;\n            if (hours > limit) {\n                return hours;\n            }\n        }\n\n        return hours;\n    }\n};"
