      "code": "class Solution {\npublic:\n    int countNegatives(vector<vector<int>>& grid) {\n        int rows = static_cast<int>(grid.size());\n        int cols = static_cast<int>(grid[0].size());\n        int total = 0;\n\n        for (int row = 0; row < rows; ++row) {\n            int firstNegative = firstNegativeIndex(grid[row]);\n            total += cols - firstNegative;\n        }\n\n        return total;\n    }\n\nprivate:\n    int firstNegativeIndex(const vector<int>& row) {\n        int left = 0;\n        int right = static_cast<int>(row.size());\n\n        while (left < right) {\n            int mid = left + (right - left) / 2;\n\n            if (row[mid] < 0) {\n                // The first negative number may be mid or further left.\n                right = mid;\n            } else {\n                // mid is non-negative, so all valid answers are to the right.\n                left = mid + 1;\n            }\n        }\n\n        return left;\n    }\n};"
