      "code": "class Solution {\npublic:\n    bool isIsomorphic(string s, string t) {\n        if (s.size() != t.size()) {\n            return false;\n        }\n\n        const int charKinds = 256;\n        vector<int> toT(charKinds, -1);\n        vector<int> toS(charKinds, -1);\n        int n = static_cast<int>(s.size());\n\n        for (int i = 0; i < n; ++i) {\n            unsigned char left = static_cast<unsigned char>(s[i]);\n            unsigned char right = static_cast<unsigned char>(t[i]);\n\n            // The same source character must always choose the same target.\n            if (toT[left] != -1 && toT[left] != right) {\n                return false;\n            }\n\n            // A target character cannot already belong to another source.\n            if (toS[right] != -1 && toS[right] != left) {\n                return false;\n            }\n\n            toT[left] = right;\n            toS[right] = left;\n        }\n\n        return true;\n    }\n};"
