      "code": "class Solution {\npublic:\n    int maxEnvelopes(vector<vector<int>>& envelopes) {\n        sort(envelopes.begin(), envelopes.end(), compareEnvelopes);\n\n        vector<int> tails;\n        for (const vector<int>& envelope : envelopes) {\n            int height = envelope[heightIndex];\n            auto place = lower_bound(tails.begin(), tails.end(), height);\n\n            if (place == tails.end()) {\n                tails.push_back(height);\n            } else {\n                // Keep the smallest possible ending height for this length.\n                *place = height;\n            }\n        }\n\n        return static_cast<int>(tails.size());\n    }\n\nprivate:\n    static constexpr int widthIndex = 0;\n    static constexpr int heightIndex = 1;\n\n    static bool compareEnvelopes(\n        const vector<int>& left,\n        const vector<int>& right\n    ) {\n        if (left[widthIndex] != right[widthIndex]) {\n            return left[widthIndex] < right[widthIndex];\n        }\n\n        // Equal widths cannot nest, so put larger heights first.\n        return left[heightIndex] > right[heightIndex];\n    }\n};"
