      "sourceTitle": "面试题 02.05. 链表求和 recursive carry reference",
      "sourceUrl": "https://leetcode.cn/problems/sum-lists-lcci/description/",
      "code": "class Solution {\npublic:\n    ListNode* addTwoNumbers(ListNode* l1, ListNode* l2) {\n        return addFromCurrentDigit(l1, l2, 0);\n    }\n\nprivate:\n    static constexpr int digitBase = 10;\n\n    ListNode* addFromCurrentDigit(\n        ListNode* first,\n        ListNode* second,\n        int carry\n    ) {\n        if (first == nullptr && second == nullptr && carry == 0) {\n            return nullptr;\n        }\n\n        int sum = carry;\n        ListNode* nextFirst = nullptr;\n        ListNode* nextSecond = nullptr;\n\n        if (first != nullptr) {\n            sum += first->val;\n            nextFirst = first->next;\n        }\n        if (second != nullptr) {\n            sum += second->val;\n            nextSecond = second->next;\n        }\n\n        // The current recursive call owns exactly one digit of the answer.\n        ListNode* node = new ListNode(sum % digitBase);\n        node->next = addFromCurrentDigit(\n            nextFirst,\n            nextSecond,\n            sum / digitBase\n        );\n        return node;\n    }\n};"
