      "code": "class Solution {\npublic:\n    int maxProfit(vector<int>& prices, int fee) {\n        if (prices.empty()) {\n            return 0;\n        }\n\n        int cash = 0;\n        int hold = -prices[0];\n\n        for (int day = 1; day < prices.size(); ++day) {\n            int price = prices[day];\n            int previousCash = cash;\n            int previousHold = hold;\n\n            // End today without stock: keep cash, or sell one share today.\n            cash = max(previousCash, previousHold + price - fee);\n\n            // End today with stock: keep holding, or buy one share today.\n            hold = max(previousHold, previousCash - price);\n        }\n\n        return cash;\n    }\n};"
