      "code": "class Solution {\npublic:\n    int maxProfit(vector<int>& prices, int fee) {\n        if (prices.empty()) {\n            return 0;\n        }\n\n        int profit = 0;\n        int effectiveBuyPrice = prices[0] + fee;\n\n        for (int day = 1; day < prices.size(); ++day) {\n            int price = prices[day];\n\n            if (price + fee < effectiveBuyPrice) {\n                // A cheaper buy point replaces the old one.\n                effectiveBuyPrice = price + fee;\n            } else if (price > effectiveBuyPrice) {\n                // Sell enough to lock this profit segment.\n                profit += price - effectiveBuyPrice;\n\n                // Treat the current price as the new cost so a continued rise\n                // can add more profit without paying another fee immediately.\n                effectiveBuyPrice = price;\n            }\n        }\n\n        return profit;\n    }\n};"
