      "code": "class Solution {\npublic:\n    int maxSumSubmatrix(vector<vector<int>>& matrix, int k) {\n        int rows = static_cast<int>(matrix.size());\n        int cols = static_cast<int>(matrix[0].size());\n        long long best = numeric_limits<long long>::min();\n\n        for (int top = 0; top < rows; ++top) {\n            vector<int> colSums(cols, 0);\n\n            for (int bottom = top; bottom < rows; ++bottom) {\n                for (int col = 0; col < cols; ++col) {\n                    colSums[col] += matrix[bottom][col];\n                }\n\n                best = max(best, bestSubarrayNoLargerThanK(colSums, k));\n                if (best == k) {\n                    return k;\n                }\n            }\n        }\n\n        return static_cast<int>(best);\n    }\n\nprivate:\n    long long bestSubarrayNoLargerThanK(\n        const vector<int>& nums,\n        int k\n    ) {\n        set<long long> prefixes;\n        prefixes.insert(0);\n\n        long long prefix = 0;\n        long long best = numeric_limits<long long>::min();\n\n        for (int value : nums) {\n            prefix += value;\n\n            // Need prefix - previous <= k, so previous >= prefix - k.\n            auto previous = prefixes.lower_bound(prefix - k);\n            if (previous != prefixes.end()) {\n                best = max(best, prefix - *previous);\n            }\n\n            prefixes.insert(prefix);\n        }\n\n        return best;\n    }\n};"
