      "code": "class Solution {\npublic:\n    bool checkSubarraySum(vector<int>& nums, int k) {\n        const int minimumLength = 2;\n        const int emptyPrefixIndex = -1;\n\n        unordered_map<int, int> firstIndexByRemainder;\n        firstIndexByRemainder[0] = emptyPrefixIndex;\n\n        long long prefixSum = 0;\n        int n = static_cast<int>(nums.size());\n\n        for (int i = 0; i < n; ++i) {\n            prefixSum += nums[i];\n            int remainder = static_cast<int>(prefixSum % k);\n\n            auto first = firstIndexByRemainder.find(remainder);\n            if (first != firstIndexByRemainder.end()) {\n                // Same remainder means the sum between the two prefixes\n                // is divisible by k. The distance is the subarray length.\n                if (i - first->second >= minimumLength) {\n                    return true;\n                }\n                continue;\n            }\n\n            // Keep only the earliest index for this remainder. An earlier\n            // prefix creates a longer candidate subarray later.\n            firstIndexByRemainder[remainder] = i;\n        }\n\n        return false;\n    }\n};"
