      "code": "class Solution {\npublic:\n    int smallestDistancePair(vector<int>& nums, int k) {\n        sort(nums.begin(), nums.end());\n\n        int low = 0;\n        int high = nums.back() - nums.front();\n\n        while (low < high) {\n            int mid = low + (high - low) / 2;\n\n            if (countPairsAtMost(nums, mid) >= k) {\n                high = mid;\n            } else {\n                low = mid + 1;\n            }\n        }\n\n        return low;\n    }\n\nprivate:\n    long long countPairsAtMost(const vector<int>& nums, int distance) {\n        long long count = 0;\n        int n = static_cast<int>(nums.size());\n\n        for (int right = 0; right < n; ++right) {\n            int smallestAllowedValue = nums[right] - distance;\n            auto first = lower_bound(\n                nums.begin(),\n                nums.begin() + right,\n                smallestAllowedValue\n            );\n\n            // Values from first up to right - 1 are close enough to nums[right].\n            count += nums.begin() + right - first;\n        }\n\n        return count;\n    }\n};"
