      "code": "class Solution {\npublic:\n    int minPairSum(vector<int>& nums) {\n        int maxValue = *max_element(nums.begin(), nums.end());\n        vector<int> frequency(maxValue + 1, 0);\n\n        for (int value : nums) {\n            ++frequency[value];\n        }\n\n        int low = 0;\n        int high = maxValue;\n        int answer = 0;\n\n        while (low <= high) {\n            while (low <= high && frequency[low] == 0) {\n                ++low;\n            }\n            while (low <= high && frequency[high] == 0) {\n                --high;\n            }\n            if (low > high) {\n                break;\n            }\n\n            // This is the same greedy pair as sorted two pointers, but the\n            // sorted order is represented by counts instead of an array.\n            answer = max(answer, low + high);\n            --frequency[low];\n            --frequency[high];\n        }\n\n        return answer;\n    }\n};"
