      "sourceTitle": "8. 字符串转换整数 (atoi) DFA state machine reference",
      "sourceUrl": "https://leetcode.cn/problems/string-to-integer-atoi/description/",
      "code": "class Solution {\npublic:\n    int myAtoi(string s) {\n        const int intMax = numeric_limits<int>::max();\n        const int intMin = numeric_limits<int>::min();\n        const int base = 10;\n\n        State state = State::Start;\n        int sign = positiveSign;\n        int result = 0;\n\n        for (char ch : s) {\n            CharType type = typeOf(ch);\n            state = nextState(state, type);\n\n            if (state == State::End) {\n                break;\n            }\n            if (state == State::Signed) {\n                sign = ch == minusChar ? negativeSign : positiveSign;\n                continue;\n            }\n            if (state != State::InNumber) {\n                continue;\n            }\n\n            int digit = ch - zeroChar;\n            if (sign == positiveSign && result > (intMax - digit) / base) {\n                return intMax;\n            }\n            if (sign == negativeSign && result < (intMin + digit) / base) {\n                return intMin;\n            }\n\n            if (sign == positiveSign) {\n                result = result * base + digit;\n            } else {\n                result = result * base - digit;\n            }\n        }\n\n        return result;\n    }\n\nprivate:\n    enum class State {\n        Start,\n        Signed,\n        InNumber,\n        End\n    };\n\n    enum class CharType {\n        Space,\n        Sign,\n        Digit,\n        Other\n    };\n\n    static constexpr int positiveSign = 1;\n    static constexpr int negativeSign = -1;\n    static constexpr char spaceChar = ' ';\n    static constexpr char plusChar = '+';\n    static constexpr char minusChar = '-';\n    static constexpr char zeroChar = '0';\n    static constexpr char nineChar = '9';\n\n    CharType typeOf(char ch) {\n        if (ch == spaceChar) {\n            return CharType::Space;\n        }\n        if (ch == plusChar || ch == minusChar) {\n            return CharType::Sign;\n        }\n        if (ch >= zeroChar && ch <= nineChar) {\n            return CharType::Digit;\n        }\n        return CharType::Other;\n    }\n\n    State nextState(State state, CharType type) {\n        switch (state) {\n            case State::Start:\n                return nextFromStart(type);\n            case State::Signed:\n                return type == CharType::Digit ? State::InNumber : State::End;\n            case State::InNumber:\n                return type == CharType::Digit ? State::InNumber : State::End;\n            case State::End:\n                return State::End;\n        }\n        return State::End;\n    }\n\n    State nextFromStart(CharType type) {\n        if (type == CharType::Space) {\n            return State::Start;\n        }\n        if (type == CharType::Sign) {\n            return State::Signed;\n        }\n        if (type == CharType::Digit) {\n            return State::InNumber;\n        }\n        return State::End;\n    }\n};"
