      "sourceUrl": "https://leetcode.cn/problems/trapping-rain-water-ii/description/",
      "code": "class Solution {\npublic:\n    int trapRainWater(vector<vector<int>>& heightMap) {\n        int rows = heightMap.size();\n        int cols = heightMap[0].size();\n        if (rows < minSideLength || cols < minSideLength) {\n            return 0;\n        }\n\n        const int unknownLevel = numeric_limits<int>::max();\n        vector<vector<int>> escapeLevel(\n            rows,\n            vector<int>(cols, unknownLevel)\n        );\n        priority_queue<State, vector<State>, HigherState> heap;\n\n        for (int row = 0; row < rows; ++row) {\n            addSource(row, 0, heightMap, escapeLevel, heap);\n            addSource(row, cols - 1, heightMap, escapeLevel, heap);\n        }\n        for (int col = 1; col + 1 < cols; ++col) {\n            addSource(0, col, heightMap, escapeLevel, heap);\n            addSource(rows - 1, col, heightMap, escapeLevel, heap);\n        }\n\n        const vector<pair<int, int>> directions = {\n            {1, 0},\n            {-1, 0},\n            {0, 1},\n            {0, -1},\n        };\n\n        while (!heap.empty()) {\n            State current = heap.top();\n            heap.pop();\n            if (current.level != escapeLevel[current.row][current.col]) {\n                continue;\n            }\n\n            for (const auto& [dr, dc] : directions) {\n                int nextRow = current.row + dr;\n                int nextCol = current.col + dc;\n                if (nextRow < 0 || nextRow >= rows ||\n                    nextCol < 0 || nextCol >= cols) {\n                    continue;\n                }\n\n                int nextLevel = max(\n                    current.level,\n                    heightMap[nextRow][nextCol]\n                );\n                if (nextLevel >= escapeLevel[nextRow][nextCol]) {\n                    continue;\n                }\n\n                escapeLevel[nextRow][nextCol] = nextLevel;\n                heap.push({nextLevel, nextRow, nextCol});\n            }\n        }\n\n        int water = 0;\n        for (int row = 1; row + 1 < rows; ++row) {\n            for (int col = 1; col + 1 < cols; ++col) {\n                water += escapeLevel[row][col] - heightMap[row][col];\n            }\n        }\n\n        return water;\n    }\n\nprivate:\n    static constexpr int minSideLength = 3;\n\n    struct State {\n        int level;\n        int row;\n        int col;\n    };\n\n    struct HigherState {\n        bool operator()(const State& a, const State& b) const {\n            return a.level > b.level;\n        }\n    };\n\n    void addSource(\n        int row,\n        int col,\n        const vector<vector<int>>& heightMap,\n        vector<vector<int>>& escapeLevel,\n        priority_queue<State, vector<State>, HigherState>& heap\n    ) {\n        if (escapeLevel[row][col] != numeric_limits<int>::max()) {\n            return;\n        }\n\n        int level = heightMap[row][col];\n        escapeLevel[row][col] = level;\n        heap.push({level, row, col});\n    }\n};"
