      "code": "class Solution {\npublic:\n    void nextPermutation(vector<int>& nums) {\n        int n = nums.size();\n        int pivot = n - 2;\n\n        while (pivot >= 0 && nums[pivot] >= nums[pivot + 1]) {\n            --pivot;\n        }\n\n        if (pivot < 0) {\n            reverse(nums.begin(), nums.end());\n            return;\n        }\n\n        int successor = n - 1;\n        while (nums[successor] <= nums[pivot]) {\n            --successor;\n        }\n\n        swap(nums[pivot], nums[successor]);\n        reverse(nums.begin() + pivot + 1, nums.end());\n    }\n};"
