      "code": "class MagicDictionary {\n    static constexpr int alphabetSize = 26;\n    static constexpr int firstIndex = 0;\n    static constexpr int nextPositionStep = 1;\n    static constexpr bool notChanged = false;\n    static constexpr char firstLetter = 'a';\n\n    struct Node {\n        array<unique_ptr<Node>, alphabetSize> children;\n        bool isWord = false;\n    };\n\npublic:\n    MagicDictionary() : root(make_unique<Node>()) {\n    }\n\n    void buildDict(vector<string> dictionary) {\n        root = make_unique<Node>();\n        for (const string& word : dictionary) {\n            insert(word);\n        }\n    }\n\n    bool search(string searchWord) {\n        return dfs(searchWord, firstIndex, root.get(), notChanged);\n    }\n\nprivate:\n    void insert(const string& word) {\n        Node* node = root.get();\n        for (char letter : word) {\n            int childIndex = toIndex(letter);\n            if (node->children[childIndex] == nullptr) {\n                node->children[childIndex] = make_unique<Node>();\n            }\n            node = node->children[childIndex].get();\n        }\n        node->isWord = true;\n    }\n\n    bool dfs(\n        const string& word,\n        int position,\n        const Node* node,\n        bool changed\n    ) const {\n        if (position == static_cast<int>(word.size())) {\n            return node->isWord && changed;\n        }\n\n        int originalIndex = toIndex(word[position]);\n        for (int childIndex = firstIndex; childIndex < alphabetSize; ++childIndex) {\n            const unique_ptr<Node>& child = node->children[childIndex];\n            if (child == nullptr) {\n                continue;\n            }\n\n            bool isDifferentLetter = childIndex != originalIndex;\n            if (changed && isDifferentLetter) {\n                continue;\n            }\n\n            bool nextChanged = changed || isDifferentLetter;\n            if (dfs(word, position + nextPositionStep, child.get(), nextChanged)) {\n                return true;\n            }\n        }\n        return false;\n    }\n\n    int toIndex(char letter) const {\n        return letter - firstLetter;\n    }\n\n    unique_ptr<Node> root;\n};"
