      "code": "class Solution {\n    static constexpr int firstCol = 0;\n\n    struct Candidate {\n        long long sum;\n        int row;\n        int col;\n    };\n\n    struct GreaterSum {\n        bool operator()(const Candidate& left, const Candidate& right) const {\n            if (left.sum != right.sum) {\n                return left.sum > right.sum;\n            }\n            if (left.row != right.row) {\n                return left.row > right.row;\n            }\n            return left.col > right.col;\n        }\n    };\n\n    long long pairSum(\n        const vector<int>& nums1,\n        const vector<int>& nums2,\n        int row,\n        int col\n    ) {\n        return static_cast<long long>(nums1[row]) + nums2[col];\n    }\n\npublic:\n    vector<vector<int>> kSmallestPairs(\n        vector<int>& nums1,\n        vector<int>& nums2,\n        int k\n    ) {\n        vector<vector<int>> answer;\n        if (nums1.empty() || nums2.empty() || k <= 0) {\n            return answer;\n        }\n\n        int rows = nums1.size();\n        int cols = nums2.size();\n        int initialRows = min(rows, k);\n        priority_queue<Candidate, vector<Candidate>, GreaterSum> minHeap;\n\n        for (int row = 0; row < initialRows; ++row) {\n            minHeap.push({\n                pairSum(nums1, nums2, row, firstCol),\n                row,\n                firstCol\n            });\n        }\n\n        while (!minHeap.empty() && answer.size() < static_cast<size_t>(k)) {\n            Candidate current = minHeap.top();\n            minHeap.pop();\n            answer.push_back({nums1[current.row], nums2[current.col]});\n\n            int nextCol = current.col + 1;\n            if (nextCol < cols) {\n                minHeap.push({\n                    pairSum(nums1, nums2, current.row, nextCol),\n                    current.row,\n                    nextCol\n                });\n            }\n        }\n\n        return answer;\n    }\n};"
