      "code": "class Solution {\npublic:\n    bool carPooling(vector<vector<int>>& trips, int capacity) {\n        vector<pair<int, int>> events;\n        events.reserve(trips.size() * eventsPerTrip);\n\n        for (const vector<int>& trip : trips) {\n            int passengers = trip[passengerIndex];\n            int from = trip[fromIndex];\n            int to = trip[toIndex];\n\n            events.push_back({from, passengers});\n            events.push_back({to, -passengers});\n        }\n\n        sort(events.begin(), events.end(), compareEvent);\n\n        int currentPassengers = 0;\n        for (const auto& [position, change] : events) {\n            currentPassengers += change;\n            if (currentPassengers > capacity) {\n                return false;\n            }\n        }\n\n        return true;\n    }\n\nprivate:\n    static constexpr int passengerIndex = 0;\n    static constexpr int fromIndex = 1;\n    static constexpr int toIndex = 2;\n    static constexpr int eventsPerTrip = 2;\n\n    static bool compareEvent(\n        const pair<int, int>& left,\n        const pair<int, int>& right\n    ) {\n        if (left.first != right.first) {\n            return left.first < right.first;\n        }\n\n        // Dropoff events are negative, so they run before pickups.\n        return left.second < right.second;\n    }\n};"
