      "code": "class SnapshotArray {\npublic:\n    SnapshotArray(int length)\n        : histories(length),\n          currentSnap(firstSnapId) {\n        for (auto& history : histories) {\n            history.push_back({firstSnapId, defaultValue});\n        }\n    }\n\n    void set(int index, int val) {\n        vector<pair<int, int>>& history = histories[index];\n        if (history.back().first == currentSnap) {\n            history.back().second = val;\n            return;\n        }\n\n        history.push_back({currentSnap, val});\n    }\n\n    int snap() {\n        int snapId = currentSnap;\n        currentSnap += nextSnapStep;\n        return snapId;\n    }\n\n    int get(int index, int snap_id) {\n        const vector<pair<int, int>>& history = histories[index];\n        int left = firstPosition;\n        int right = static_cast<int>(history.size());\n\n        while (left < right) {\n            int middle = left + (right - left) / binaryParts;\n            if (history[middle].first <= snap_id) {\n                left = middle + nextPositionStep;\n            } else {\n                right = middle;\n            }\n        }\n\n        // The initial (0, 0) record makes left - 1 a valid position.\n        return history[left - previousPositionStep].second;\n    }\n\nprivate:\n    vector<vector<pair<int, int>>> histories;\n    int currentSnap;\n\n    static constexpr int firstSnapId = 0;\n    static constexpr int defaultValue = 0;\n    static constexpr int firstPosition = 0;\n    static constexpr int binaryParts = 2;\n    static constexpr int nextSnapStep = 1;\n    static constexpr int nextPositionStep = 1;\n    static constexpr int previousPositionStep = 1;\n};"
