      "code": "class Solution {\npublic:\n    int kSimilarity(string s1, string s2) {\n        if (s1 == s2) {\n            return noSwapNeeded;\n        }\n\n        queue<string> states;\n        unordered_set<string> visited;\n        states.push(s1);\n        visited.insert(s1);\n\n        int swaps = noSwapNeeded;\n        while (!states.empty()) {\n            int layerSize = static_cast<int>(states.size());\n            for (int count = 0; count < layerSize; ++count) {\n                string current = states.front();\n                states.pop();\n\n                if (current == s2) {\n                    return swaps;\n                }\n\n                for (const string& next : nextStates(current, s2)) {\n                    if (!visited.insert(next).second) {\n                        continue;\n                    }\n                    if (next == s2) {\n                        return swaps + oneSwap;\n                    }\n                    states.push(next);\n                }\n            }\n            ++swaps;\n        }\n\n        return noSwapNeeded;\n    }\n\nprivate:\n    vector<string> nextStates(const string& current, const string& target) const {\n        int n = static_cast<int>(current.size());\n        int firstMismatch = firstIndex;\n        while (\n            firstMismatch < n\n            && current[firstMismatch] == target[firstMismatch]\n        ) {\n            ++firstMismatch;\n        }\n\n        vector<string> result;\n        if (firstMismatch == n) {\n            return result;\n        }\n\n        for (int j = firstMismatch + nextIndexStep; j < n; ++j) {\n            if (current[j] != target[firstMismatch]) {\n                continue;\n            }\n            if (current[j] == target[j]) {\n                continue;\n            }\n\n            string next = current;\n            swap(next[firstMismatch], next[j]);\n            result.push_back(next);\n        }\n        return result;\n    }\n\n    static constexpr int noSwapNeeded = 0;\n    static constexpr int oneSwap = 1;\n    static constexpr int firstIndex = 0;\n    static constexpr int nextIndexStep = 1;\n};"
