      "code": "/**\n * Definition for a binary tree node.\n * struct TreeNode {\n *     int val;\n *     TreeNode *left;\n *     TreeNode *right;\n *     TreeNode() : val(0), left(nullptr), right(nullptr) {}\n *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n *     TreeNode(int x, TreeNode *left, TreeNode *right)\n *         : val(x), left(left), right(right) {}\n * };\n */\nclass Solution {\npublic:\n    TreeNode* buildTree(vector<int>& inorder, vector<int>& postorder) {\n        int n = static_cast<int>(inorder.size());\n        for (int index = firstIndex; index < n; ++index) {\n            inorderIndex[inorder[index]] = index;\n        }\n\n        return build(\n            inorder,\n            postorder,\n            firstIndex,\n            n - emptyOffset,\n            firstIndex,\n            n - emptyOffset\n        );\n    }\n\nprivate:\n    unordered_map<int, int> inorderIndex;\n\n    TreeNode* build(\n        const vector<int>& inorder,\n        const vector<int>& postorder,\n        int inLeft,\n        int inRight,\n        int postLeft,\n        int postRight\n    ) {\n        if (inLeft > inRight || postLeft > postRight) {\n            return nullptr;\n        }\n\n        int rootValue = postorder[postRight];\n        int rootIndex = inorderIndex[rootValue];\n        int leftSize = rootIndex - inLeft;\n\n        TreeNode* root = new TreeNode(rootValue);\n        root->left = build(\n            inorder,\n            postorder,\n            inLeft,\n            rootIndex - oneStep,\n            postLeft,\n            postLeft + leftSize - oneStep\n        );\n        root->right = build(\n            inorder,\n            postorder,\n            rootIndex + oneStep,\n            inRight,\n            postLeft + leftSize,\n            postRight - oneStep\n        );\n        return root;\n    }\n\n    static constexpr int firstIndex = 0;\n    static constexpr int emptyOffset = 1;\n    static constexpr int oneStep = 1;\n};"
