      "code": "class Solution {\npublic:\n    int countTrapezoids(vector<vector<int>>& points) {\n        unordered_map<string, unordered_map<long long, long long>> bySlope;\n        int n = static_cast<int>(points.size());\n\n        for (int left = 0; left < n; ++left) {\n            for (int right = left + one; right < n; ++right) {\n                int x1 = points[left][xIndex];\n                int y1 = points[left][yIndex];\n                int x2 = points[right][xIndex];\n                int y2 = points[right][yIndex];\n                pair<int, int> slope = normalizedSlope(y2 - y1, x2 - x1);\n                long long line = lineKey(slope, x1, y1);\n\n                ++bySlope[slopeKey(slope)][line];\n            }\n        }\n\n        long long answer = 0;\n        for (const auto& slopeEntry : bySlope) {\n            long long previousSegments = 0;\n            for (const auto& lineEntry : slopeEntry.second) {\n                long long currentLineSegments = lineEntry.second;\n                answer += previousSegments * currentLineSegments;\n                previousSegments += currentLineSegments;\n            }\n        }\n\n        answer -= countParallelograms(points);\n        return static_cast<int>(answer);\n    }\n\nprivate:\n    static constexpr int xIndex = 0;\n    static constexpr int yIndex = 1;\n    static constexpr int one = 1;\n    static constexpr int zero = 0;\n\n    pair<int, int> normalizedSlope(int dy, int dx) const {\n        if (dx == zero) {\n            return {one, zero};\n        }\n        if (dy == zero) {\n            return {zero, one};\n        }\n\n        int divisor = gcd(abs(dy), abs(dx));\n        dy /= divisor;\n        dx /= divisor;\n        if (dx < zero) {\n            dy = -dy;\n            dx = -dx;\n        }\n        return {dy, dx};\n    }\n\n    string slopeKey(const pair<int, int>& slope) const {\n        return to_string(slope.first) + \",\" + to_string(slope.second);\n    }\n\n    string midpointKey(int xSum, int ySum) const {\n        return to_string(xSum) + \",\" + to_string(ySum);\n    }\n\n    long long lineKey(const pair<int, int>& slope, int x, int y) const {\n        long long dy = slope.first;\n        long long dx = slope.second;\n        return dy * x - dx * y;\n    }\n\n    long long countParallelograms(vector<vector<int>>& points) const {\n        unordered_map<string, unordered_map<string, long long>> byMidpoint;\n        int n = static_cast<int>(points.size());\n\n        for (int left = 0; left < n; ++left) {\n            for (int right = left + one; right < n; ++right) {\n                int x1 = points[left][xIndex];\n                int y1 = points[left][yIndex];\n                int x2 = points[right][xIndex];\n                int y2 = points[right][yIndex];\n                pair<int, int> slope = normalizedSlope(y2 - y1, x2 - x1);\n\n                ++byMidpoint[midpointKey(x1 + x2, y1 + y2)][slopeKey(slope)];\n            }\n        }\n\n        long long parallelograms = 0;\n        for (const auto& midpointEntry : byMidpoint) {\n            long long previousDiagonals = 0;\n            for (const auto& slopeEntry : midpointEntry.second) {\n                long long currentDiagonals = slopeEntry.second;\n                parallelograms += previousDiagonals * currentDiagonals;\n                previousDiagonals += currentDiagonals;\n            }\n        }\n        return parallelograms;\n    }\n};"
