      "code": "class Solution {\npublic:\n    int countTrapezoids(vector<vector<int>>& points) {\n        vector<Segment> segments = buildSegments(points);\n        long long allParallelPairs = countParallelPairs(segments);\n        long long parallelograms = countParallelograms(segments);\n\n        return static_cast<int>(allParallelPairs - parallelograms);\n    }\n\nprivate:\n    static constexpr int xIndex = 0;\n    static constexpr int yIndex = 1;\n    static constexpr int one = 1;\n    static constexpr int zero = 0;\n\n    struct Segment {\n        int dy;\n        int dx;\n        long long line;\n        int midX;\n        int midY;\n    };\n\n    vector<Segment> buildSegments(const vector<vector<int>>& points) const {\n        int n = static_cast<int>(points.size());\n        vector<Segment> segments;\n        segments.reserve(n * (n - one) / 2);\n\n        for (int left = 0; left < n; ++left) {\n            for (int right = left + one; right < n; ++right) {\n                int x1 = points[left][xIndex];\n                int y1 = points[left][yIndex];\n                int x2 = points[right][xIndex];\n                int y2 = points[right][yIndex];\n                pair<int, int> slope = normalizedSlope(y2 - y1, x2 - x1);\n\n                segments.push_back({slope.first,\n                                    slope.second,\n                                    lineKey(slope, x1, y1),\n                                    x1 + x2,\n                                    y1 + y2});\n            }\n        }\n        return segments;\n    }\n\n    pair<int, int> normalizedSlope(int dy, int dx) const {\n        if (dx == zero) {\n            return {one, zero};\n        }\n        if (dy == zero) {\n            return {zero, one};\n        }\n\n        int divisor = gcd(abs(dy), abs(dx));\n        dy /= divisor;\n        dx /= divisor;\n        if (dx < zero) {\n            dy = -dy;\n            dx = -dx;\n        }\n        return {dy, dx};\n    }\n\n    long long lineKey(const pair<int, int>& slope, int x, int y) const {\n        long long dy = slope.first;\n        long long dx = slope.second;\n        return dy * x - dx * y;\n    }\n\n    long long countParallelPairs(vector<Segment> segments) const {\n        sort(segments.begin(), segments.end(), [](const Segment& a,\n                                                  const Segment& b) {\n            return tie(a.dy, a.dx, a.line) < tie(b.dy, b.dx, b.line);\n        });\n\n        long long answer = 0;\n        int index = 0;\n        while (index < static_cast<int>(segments.size())) {\n            int slopeEnd = index;\n            while (slopeEnd < static_cast<int>(segments.size()) &&\n                   sameSlope(segments[index], segments[slopeEnd])) {\n                ++slopeEnd;\n            }\n\n            long long previousSegments = 0;\n            int lineStart = index;\n            while (lineStart < slopeEnd) {\n                int lineEnd = lineStart;\n                while (lineEnd < slopeEnd &&\n                       segments[lineEnd].line == segments[lineStart].line) {\n                    ++lineEnd;\n                }\n\n                long long currentLineSegments = lineEnd - lineStart;\n                answer += previousSegments * currentLineSegments;\n                previousSegments += currentLineSegments;\n                lineStart = lineEnd;\n            }\n            index = slopeEnd;\n        }\n        return answer;\n    }\n\n    long long countParallelograms(vector<Segment> segments) const {\n        sort(segments.begin(), segments.end(), [](const Segment& a,\n                                                  const Segment& b) {\n            return tie(a.midX, a.midY, a.dy, a.dx) <\n                   tie(b.midX, b.midY, b.dy, b.dx);\n        });\n\n        long long answer = 0;\n        int index = 0;\n        while (index < static_cast<int>(segments.size())) {\n            int midpointEnd = index;\n            while (midpointEnd < static_cast<int>(segments.size()) &&\n                   sameMidpoint(segments[index], segments[midpointEnd])) {\n                ++midpointEnd;\n            }\n\n            long long previousDiagonals = 0;\n            int slopeStart = index;\n            while (slopeStart < midpointEnd) {\n                int slopeEnd = slopeStart;\n                while (slopeEnd < midpointEnd &&\n                       sameSlope(segments[slopeStart], segments[slopeEnd])) {\n                    ++slopeEnd;\n                }\n\n                long long currentDiagonals = slopeEnd - slopeStart;\n                answer += previousDiagonals * currentDiagonals;\n                previousDiagonals += currentDiagonals;\n                slopeStart = slopeEnd;\n            }\n            index = midpointEnd;\n        }\n        return answer;\n    }\n\n    bool sameSlope(const Segment& a, const Segment& b) const {\n        return a.dy == b.dy && a.dx == b.dx;\n    }\n\n    bool sameMidpoint(const Segment& a, const Segment& b) const {\n        return a.midX == b.midX && a.midY == b.midY;\n    }\n};"
