      "code": "class Solution {\npublic:\n    long long minimumCost(\n        string source,\n        string target,\n        vector<string>& original,\n        vector<string>& changed,\n        vector<int>& cost\n    ) {\n        int ruleCount = static_cast<int>(original.size());\n        vector<vector<long long>> dist(maxPatternCount,\n                                      vector<long long>(maxPatternCount, inf));\n        vector<TrieNode> trie(1);\n        unordered_map<string, int> idByPattern;\n\n        for (int rule = 0; rule < ruleCount; ++rule) {\n            int from = getPatternId(original[rule], idByPattern, dist, trie);\n            int to = getPatternId(changed[rule], idByPattern, dist, trie);\n            dist[from][to] = min(dist[from][to],\n                                 static_cast<long long>(cost[rule]));\n        }\n\n        int patternCount = static_cast<int>(idByPattern.size());\n        for (int id = firstIndex; id < patternCount; ++id) {\n            dist[id][id] = noCost;\n        }\n\n        for (int mid = firstIndex; mid < patternCount; ++mid) {\n            for (int from = firstIndex; from < patternCount; ++from) {\n                if (dist[from][mid] == inf) {\n                    continue;\n                }\n                for (int to = firstIndex; to < patternCount; ++to) {\n                    if (dist[mid][to] == inf) {\n                        continue;\n                    }\n                    dist[from][to] = min(dist[from][to],\n                                         dist[from][mid] + dist[mid][to]);\n                }\n            }\n        }\n\n        int n = static_cast<int>(source.size());\n        vector<long long> dp(n + suffixSentinel, inf);\n        dp[n] = noCost;\n\n        for (int start = n - oneChar; start >= firstIndex; --start) {\n            if (source[start] == target[start]) {\n                dp[start] = dp[start + oneChar];\n            }\n\n            int sourceNode = rootNode;\n            int targetNode = rootNode;\n            for (int end = start; end < n; ++end) {\n                sourceNode = nextNode(trie, sourceNode, source[end]);\n                targetNode = nextNode(trie, targetNode, target[end]);\n                if (sourceNode == missingNode || targetNode == missingNode) {\n                    break;\n                }\n\n                int sourceId = trie[sourceNode].patternId;\n                int targetId = trie[targetNode].patternId;\n                if (sourceId == missingPattern || targetId == missingPattern) {\n                    continue;\n                }\n                if (dist[sourceId][targetId] == inf || dp[end + oneChar] == inf) {\n                    continue;\n                }\n\n                dp[start] = min(dp[start],\n                                dist[sourceId][targetId] + dp[end + oneChar]);\n            }\n        }\n\n        return dp[firstIndex] == inf ? impossible : dp[firstIndex];\n    }\n\nprivate:\n    static constexpr int firstIndex = 0;\n    static constexpr int oneChar = 1;\n    static constexpr int suffixSentinel = 1;\n    static constexpr int rootNode = 0;\n    static constexpr int missingNode = -1;\n    static constexpr int missingPattern = -1;\n    static constexpr int alphabetSize = 26;\n    static constexpr int maxPatternCount = 205;\n    static constexpr char firstLetter = 'a';\n    static constexpr long long noCost = 0;\n    static constexpr long long impossible = -1;\n    static constexpr long long inf = 4'000'000'000'000'000'000LL;\n\n    struct TrieNode {\n        array<int, alphabetSize> child;\n        int patternId = missingPattern;\n\n        TrieNode() {\n            child.fill(missingNode);\n        }\n    };\n\n    int getPatternId(\n        const string& pattern,\n        unordered_map<string, int>& idByPattern,\n        vector<vector<long long>>& dist,\n        vector<TrieNode>& trie\n    ) const {\n        auto it = idByPattern.find(pattern);\n        if (it != idByPattern.end()) {\n            return it->second;\n        }\n\n        int id = static_cast<int>(idByPattern.size());\n        idByPattern[pattern] = id;\n        dist[id][id] = noCost;\n\n        int node = rootNode;\n        for (char ch : pattern) {\n            int index = ch - firstLetter;\n            if (trie[node].child[index] == missingNode) {\n                trie[node].child[index] = static_cast<int>(trie.size());\n                trie.emplace_back();\n            }\n            node = trie[node].child[index];\n        }\n        trie[node].patternId = id;\n        return id;\n    }\n\n    int nextNode(const vector<TrieNode>& trie, int node, char ch) const {\n        if (node == missingNode) {\n            return missingNode;\n        }\n        return trie[node].child[ch - firstLetter];\n    }\n};"
