      "code": "class Solution {\npublic:\n    vector<vector<int>> insert(\n        vector<vector<int>>& intervals,\n        vector<int>& newInterval\n    ) {\n        vector<vector<int>> allIntervals = intervals;\n        allIntervals.push_back(newInterval);\n        sort(allIntervals.begin(), allIntervals.end());\n\n        vector<vector<int>> merged;\n        for (const vector<int>& interval : allIntervals) {\n            if (merged.empty()\n                || merged.back()[endIndex] < interval[startIndex]) {\n                // There is a real gap. Boundary-touching closed intervals,\n                // such as [1, 3] and [3, 5], should be merged instead.\n                merged.push_back(interval);\n                continue;\n            }\n\n            merged.back()[endIndex] = max(\n                merged.back()[endIndex],\n                interval[endIndex]\n            );\n        }\n\n        return merged;\n    }\n\nprivate:\n    static constexpr int startIndex = 0;\n    static constexpr int endIndex = 1;\n};"
