      "code": "class Solution {\npublic:\n    int minPushBox(vector<vector<char>>& grid) {\n        rows = static_cast<int>(grid.size());\n        cols = static_cast<int>(grid[0].size());\n        this->grid = &grid;\n\n        Position box;\n        Position player;\n        Position target;\n        parseGrid(box, player, target);\n\n        queue<State> states;\n        vector<vector<vector<vector<bool>>>> visited(\n            rows,\n            vector<vector<vector<bool>>>(\n                cols,\n                vector<vector<bool>>(\n                    rows,\n                    vector<bool>(cols, false))));\n\n        states.push({box, player, 0});\n        visited[box.row][box.col][player.row][player.col] = true;\n\n        while (!states.empty()) {\n            State current = states.front();\n            states.pop();\n\n            if (current.box == target) {\n                return current.pushes;\n            }\n\n            for (const Direction& direction : directions) {\n                Position nextBox = move(current.box, direction);\n                Position stand = move(current.box, opposite(direction));\n\n                if (!isOpen(nextBox) || !isOpen(stand)) {\n                    continue;\n                }\n                if (!canReach(current.player, stand, current.box)) {\n                    continue;\n                }\n                if (visited[nextBox.row][nextBox.col]\n                    [current.box.row][current.box.col]) {\n                    continue;\n                }\n\n                visited[nextBox.row][nextBox.col]\n                    [current.box.row][current.box.col] = true;\n                states.push({nextBox, current.box, current.pushes + onePush});\n            }\n        }\n\n        return impossible;\n    }\n\nprivate:\n    struct Position {\n        int row;\n        int col;\n\n        bool operator==(const Position& other) const {\n            return row == other.row && col == other.col;\n        }\n    };\n\n    struct Direction {\n        int rowDelta;\n        int colDelta;\n    };\n\n    struct State {\n        Position box;\n        Position player;\n        int pushes;\n    };\n\n    static constexpr char wall = '#';\n    static constexpr char boxCell = 'B';\n    static constexpr char playerCell = 'S';\n    static constexpr char targetCell = 'T';\n    static constexpr int impossible = -1;\n    static constexpr int onePush = 1;\n\n    const vector<Direction> directions = {\n        {-1, 0}, {1, 0}, {0, -1}, {0, 1}\n    };\n\n    int rows = 0;\n    int cols = 0;\n    vector<vector<char>>* grid = nullptr;\n\n    void parseGrid(\n        Position& box,\n        Position& player,\n        Position& target\n    ) const {\n        for (int row = 0; row < rows; ++row) {\n            for (int col = 0; col < cols; ++col) {\n                char cell = (*grid)[row][col];\n                if (cell == boxCell) {\n                    box = {row, col};\n                } else if (cell == playerCell) {\n                    player = {row, col};\n                } else if (cell == targetCell) {\n                    target = {row, col};\n                }\n            }\n        }\n    }\n\n    Direction opposite(const Direction& direction) const {\n        return {-direction.rowDelta, -direction.colDelta};\n    }\n\n    Position move(Position position, const Direction& direction) const {\n        return {\n            position.row + direction.rowDelta,\n            position.col + direction.colDelta,\n        };\n    }\n\n    bool isInside(Position position) const {\n        return position.row >= 0 && position.row < rows &&\n            position.col >= 0 && position.col < cols;\n    }\n\n    bool isOpen(Position position) const {\n        return isInside(position) &&\n            (*grid)[position.row][position.col] != wall;\n    }\n\n    bool canReach(\n        Position start,\n        Position target,\n        Position blockedBox\n    ) const {\n        queue<Position> cells;\n        vector<vector<bool>> seen(rows, vector<bool>(cols, false));\n\n        cells.push(start);\n        seen[start.row][start.col] = true;\n\n        while (!cells.empty()) {\n            Position current = cells.front();\n            cells.pop();\n\n            if (current == target) {\n                return true;\n            }\n\n            for (const Direction& direction : directions) {\n                Position next = move(current, direction);\n                if (!isOpen(next) || next == blockedBox ||\n                    seen[next.row][next.col]) {\n                    continue;\n                }\n\n                seen[next.row][next.col] = true;\n                cells.push(next);\n            }\n        }\n\n        return false;\n    }\n};"
