      "code": "class Solution {\npublic:\n    int minPushBox(vector<vector<char>>& grid) {\n        rows = static_cast<int>(grid.size());\n        cols = static_cast<int>(grid[0].size());\n        this->grid = &grid;\n\n        Position box;\n        Position player;\n        Position target;\n        parseGrid(box, player, target);\n\n        int cellCount = rows * cols;\n        int stateCount = cellCount * cellCount;\n        vector<int> dist(stateCount, infinity);\n        deque<State> states;\n\n        int startId = encode(box, player);\n        dist[startId] = noPushes;\n        states.push_front({box, player});\n\n        while (!states.empty()) {\n            State current = states.front();\n            states.pop_front();\n\n            int currentId = encode(current.box, current.player);\n            int pushes = dist[currentId];\n            if (current.box == target) {\n                return pushes;\n            }\n\n            for (const Direction& direction : directions) {\n                Position nextPlayer = move(current.player, direction);\n                if (!isOpen(nextPlayer)) {\n                    continue;\n                }\n\n                Position nextBox = current.box;\n                int cost = noPushes;\n                if (nextPlayer == current.box) {\n                    nextBox = move(current.box, direction);\n                    if (!isOpen(nextBox)) {\n                        continue;\n                    }\n                    cost = onePush;\n                }\n\n                int nextId = encode(nextBox, nextPlayer);\n                if (pushes + cost >= dist[nextId]) {\n                    continue;\n                }\n\n                dist[nextId] = pushes + cost;\n                State nextState = {nextBox, nextPlayer};\n                if (cost == noPushes) {\n                    states.push_front(nextState);\n                } else {\n                    states.push_back(nextState);\n                }\n            }\n        }\n\n        return impossible;\n    }\n\nprivate:\n    struct Position {\n        int row;\n        int col;\n\n        bool operator==(const Position& other) const {\n            return row == other.row && col == other.col;\n        }\n    };\n\n    struct Direction {\n        int rowDelta;\n        int colDelta;\n    };\n\n    struct State {\n        Position box;\n        Position player;\n    };\n\n    static constexpr char wall = '#';\n    static constexpr char boxCell = 'B';\n    static constexpr char playerCell = 'S';\n    static constexpr char targetCell = 'T';\n    static constexpr int impossible = -1;\n    static constexpr int noPushes = 0;\n    static constexpr int onePush = 1;\n    static constexpr int infinity = 1'000'000'000;\n\n    const vector<Direction> directions = {\n        {-1, 0}, {1, 0}, {0, -1}, {0, 1}\n    };\n\n    int rows = 0;\n    int cols = 0;\n    vector<vector<char>>* grid = nullptr;\n\n    void parseGrid(\n        Position& box,\n        Position& player,\n        Position& target\n    ) const {\n        for (int row = 0; row < rows; ++row) {\n            for (int col = 0; col < cols; ++col) {\n                char cell = (*grid)[row][col];\n                if (cell == boxCell) {\n                    box = {row, col};\n                } else if (cell == playerCell) {\n                    player = {row, col};\n                } else if (cell == targetCell) {\n                    target = {row, col};\n                }\n            }\n        }\n    }\n\n    Position move(Position position, const Direction& direction) const {\n        return {\n            position.row + direction.rowDelta,\n            position.col + direction.colDelta,\n        };\n    }\n\n    bool isInside(Position position) const {\n        return position.row >= 0 && position.row < rows &&\n            position.col >= 0 && position.col < cols;\n    }\n\n    bool isOpen(Position position) const {\n        return isInside(position) &&\n            (*grid)[position.row][position.col] != wall;\n    }\n\n    int cellId(Position position) const {\n        return position.row * cols + position.col;\n    }\n\n    int encode(Position box, Position player) const {\n        return cellId(box) * rows * cols + cellId(player);\n    }\n};"
