      "code": "class Solution {\npublic:\n    int maxNumberOfFamilies(\n        int n,\n        vector<vector<int>>& reservedSeats\n    ) {\n        unordered_map<int, int> reservedMaskByRow;\n\n        for (const vector<int>& seat : reservedSeats) {\n            int row = seat[rowIndex];\n            int column = seat[columnIndex];\n            if (column <= firstIgnoredSeat || column >= lastIgnoredSeat) {\n                continue;\n            }\n\n            int bit = column - firstTrackedSeat;\n            reservedMaskByRow[row] |= oneBit << bit;\n        }\n\n        int answer = (n - static_cast<int>(reservedMaskByRow.size())) *\n            familiesInEmptyRow;\n\n        for (const auto& entry : reservedMaskByRow) {\n            int rowMask = entry.second;\n            bool canUseLeft = (rowMask & leftBlockMask) == emptyMask;\n            bool canUseMiddle = (rowMask & middleBlockMask) == emptyMask;\n            bool canUseRight = (rowMask & rightBlockMask) == emptyMask;\n\n            if (canUseLeft && canUseRight) {\n                answer += familiesInEmptyRow;\n            } else if (canUseLeft || canUseMiddle || canUseRight) {\n                answer += oneFamily;\n            }\n        }\n\n        return answer;\n    }\n\nprivate:\n    static constexpr int rowIndex = 0;\n    static constexpr int columnIndex = 1;\n    static constexpr int firstIgnoredSeat = 1;\n    static constexpr int lastIgnoredSeat = 10;\n    static constexpr int firstTrackedSeat = 2;\n    static constexpr int oneBit = 1;\n    static constexpr int emptyMask = 0;\n    static constexpr int oneFamily = 1;\n    static constexpr int familiesInEmptyRow = 2;\n    static constexpr int familySize = 4;\n    static constexpr int leftBlockStart = 2;\n    static constexpr int middleBlockStart = 4;\n    static constexpr int rightBlockStart = 6;\n    static constexpr int familyMask = (oneBit << familySize) - oneBit;\n    static constexpr int leftBlockMask = familyMask <<\n        (leftBlockStart - firstTrackedSeat);\n    static constexpr int middleBlockMask = familyMask <<\n        (middleBlockStart - firstTrackedSeat);\n    static constexpr int rightBlockMask = familyMask <<\n        (rightBlockStart - firstTrackedSeat);\n};"
