      "code": "class Solution {\npublic:\n    int matrixMedian(vector<vector<int>>& grid) {\n        int rows = static_cast<int>(grid.size());\n        int cols = static_cast<int>(grid[0].size());\n        int targetRank = rows * cols / twoParts + oneBasedStep;\n\n        int low = grid[firstRow][firstCol];\n        int high = grid[firstRow][cols - lastColOffset];\n        for (const vector<int>& row : grid) {\n            low = min(low, row[firstCol]);\n            high = max(high, row[cols - lastColOffset]);\n        }\n\n        while (low < high) {\n            long long distance = static_cast<long long>(high) - low;\n            int mid = low + static_cast<int>(distance / twoParts);\n            int countLessOrEqual = countValuesLessOrEqual(grid, mid);\n\n            // If fewer than targetRank values are <= mid, the median must be\n            // larger than mid. Otherwise, mid may already be large enough.\n            if (countLessOrEqual < targetRank) {\n                low = mid + nextValueStep;\n            } else {\n                high = mid;\n            }\n        }\n\n        return low;\n    }\n\nprivate:\n    int countValuesLessOrEqual(\n        const vector<vector<int>>& grid,\n        int value\n    ) const {\n        int total = noValues;\n        for (const vector<int>& row : grid) {\n            auto firstGreater = upper_bound(row.begin(), row.end(), value);\n            total += static_cast<int>(firstGreater - row.begin());\n        }\n        return total;\n    }\n\n    static constexpr int firstRow = 0;\n    static constexpr int firstCol = 0;\n    static constexpr int lastColOffset = 1;\n    static constexpr int twoParts = 2;\n    static constexpr int oneBasedStep = 1;\n    static constexpr int nextValueStep = 1;\n    static constexpr int noValues = 0;\n};"
