      "code": "class Solution {\npublic:\n    int matrixMedian(vector<vector<int>>& grid) {\n        int rows = static_cast<int>(grid.size());\n        int cols = static_cast<int>(grid[0].size());\n        int targetRank = rows * cols / twoParts + oneBasedStep;\n\n        priority_queue<Cell, vector<Cell>, CompareCell> minHeap;\n        for (int row = firstRow; row < rows; ++row) {\n            minHeap.push({grid[row][firstCol], row, firstCol});\n        }\n\n        int answer = noAnswerYet;\n        for (int rank = firstRank; rank <= targetRank; ++rank) {\n            Cell current = minHeap.top();\n            minHeap.pop();\n            answer = current.value;\n\n            int nextCol = current.col + nextColStep;\n            if (nextCol < cols) {\n                minHeap.push({grid[current.row][nextCol], current.row, nextCol});\n            }\n        }\n\n        return answer;\n    }\n\nprivate:\n    struct Cell {\n        int value;\n        int row;\n        int col;\n    };\n\n    struct CompareCell {\n        bool operator()(const Cell& left, const Cell& right) const {\n            // priority_queue puts the \"largest\" item first by default.\n            // Returning true when left is larger makes it a min heap by value.\n            return left.value > right.value;\n        }\n    };\n\n    static constexpr int firstRow = 0;\n    static constexpr int firstCol = 0;\n    static constexpr int twoParts = 2;\n    static constexpr int oneBasedStep = 1;\n    static constexpr int firstRank = 1;\n    static constexpr int nextColStep = 1;\n    static constexpr int noAnswerYet = 0;\n};"
