      "code": "class Solution {\npublic:\n    vector<vector<int>> combinationSum2(vector<int>& candidates, int target) {\n        sort(candidates.begin(), candidates.end());\n        values = &candidates;\n        answers.clear();\n        path.clear();\n\n        dfs(firstIndex, target);\n        return answers;\n    }\n\nprivate:\n    void dfs(int start, int remaining) {\n        if (remaining == exactSum) {\n            answers.push_back(path);\n            return;\n        }\n\n        for (int index = start;\n             index < static_cast<int>(values->size());\n             ++index) {\n            if (index > start\n                && (*values)[index] == (*values)[index - previousIndexStep]) {\n                // The same value was already used as this layer's next\n                // choice. Trying it again would build duplicate combinations.\n                continue;\n            }\n            if ((*values)[index] > remaining) {\n                // The array is sorted, so later values are even larger.\n                break;\n            }\n\n            path.push_back((*values)[index]);\n            dfs(index + nextIndexStep, remaining - (*values)[index]);\n            path.pop_back();\n        }\n    }\n\n    const vector<int>* values = nullptr;\n    vector<int> path;\n    vector<vector<int>> answers;\n\n    static constexpr int firstIndex = 0;\n    static constexpr int exactSum = 0;\n    static constexpr int previousIndexStep = 1;\n    static constexpr int nextIndexStep = 1;\n};"
