      "code": "class Solution {\npublic:\n    vector<vector<int>> combinationSum2(vector<int>& candidates, int target) {\n        sort(candidates.begin(), candidates.end());\n        groups.clear();\n        answers.clear();\n        path.clear();\n\n        for (int value : candidates) {\n            if (groups.empty() || groups.back().first != value) {\n                groups.push_back({value, firstOccurrence});\n            } else {\n                ++groups.back().second;\n            }\n        }\n\n        dfs(firstGroup, target);\n        return answers;\n    }\n\nprivate:\n    void dfs(int groupIndex, int remaining) {\n        if (remaining == exactSum) {\n            answers.push_back(path);\n            return;\n        }\n        if (groupIndex == static_cast<int>(groups.size())) {\n            return;\n        }\n\n        int value = groups[groupIndex].first;\n        int count = groups[groupIndex].second;\n        int maxTake = min(count, remaining / value);\n\n        // Choose how many copies of this value to use: 0, 1, ..., maxTake.\n        // Each copy comes from a different original index, so this respects\n        // the rule that every input position can be used at most once.\n        for (int take = noCopy; take <= maxTake; ++take) {\n            for (int copy = noCopy; copy < take; ++copy) {\n                path.push_back(value);\n            }\n\n            dfs(\n                groupIndex + nextGroupStep,\n                remaining - take * value\n            );\n\n            for (int copy = noCopy; copy < take; ++copy) {\n                path.pop_back();\n            }\n        }\n    }\n\n    vector<pair<int, int>> groups;\n    vector<int> path;\n    vector<vector<int>> answers;\n\n    static constexpr int firstGroup = 0;\n    static constexpr int exactSum = 0;\n    static constexpr int firstOccurrence = 1;\n    static constexpr int noCopy = 0;\n    static constexpr int nextGroupStep = 1;\n};"
