      "code": "class Solution {\npublic:\n    int maxProfit(\n        int n,\n        vector<int>& present,\n        vector<int>& future,\n        vector<vector<int>>& hierarchy,\n        int budget\n    ) {\n        presentPrice = &present;\n        futurePrice = &future;\n        maxBudget = budget;\n        children.assign(n, vector<int>{});\n\n        for (const vector<int>& edge : hierarchy) {\n            int boss = edge[bossIndex] - employeeIdOffset;\n            int worker = edge[workerIndex] - employeeIdOffset;\n            children[boss].push_back(worker);\n        }\n\n        array<vector<int>, stateCount> rootDp = dfs(ceoIndex);\n        return rootDp[parentNotBought][budget];\n    }\n\nprivate:\n    array<vector<int>, stateCount> dfs(int employee) const {\n        vector<array<vector<int>, stateCount>> childStates;\n        childStates.reserve(children[employee].size());\n        for (int child : children[employee]) {\n            childStates.push_back(dfs(child));\n        }\n\n        array<vector<int>, stateCount> result;\n        for (int parentState = parentNotBought;\n             parentState < stateCount;\n             ++parentState) {\n            vector<int> skip(maxBudget + includeZeroBudget, noProfit);\n            int cost = stockCost(employee, parentState);\n            int profit = (*futurePrice)[employee] - cost;\n            vector<int> take(\n                maxBudget + includeZeroBudget,\n                impossibleProfit\n            );\n\n            for (int money = cost; money <= maxBudget; ++money) {\n                take[money] = profit;\n            }\n\n            for (const auto& childDp : childStates) {\n                // If employee is skipped, direct children receive no discount.\n                skip = mergeKnapsack(skip, childDp[parentNotBought]);\n                // If employee is bought, direct children receive the discount.\n                take = mergeKnapsack(take, childDp[parentBought]);\n            }\n\n            result[parentState].assign(\n                maxBudget + includeZeroBudget,\n                noProfit\n            );\n            for (int money = noBudget; money <= maxBudget; ++money) {\n                result[parentState][money] = max(skip[money], take[money]);\n            }\n        }\n\n        return result;\n    }\n\n    vector<int> mergeKnapsack(\n        const vector<int>& base,\n        const vector<int>& child\n    ) const {\n        vector<int> merged(maxBudget + includeZeroBudget, impossibleProfit);\n\n        for (int total = noBudget; total <= maxBudget; ++total) {\n            for (int childBudget = noBudget;\n                 childBudget <= total;\n                 ++childBudget) {\n                int baseBudget = total - childBudget;\n                if (base[baseBudget] == impossibleProfit\n                    || child[childBudget] == impossibleProfit) {\n                    continue;\n                }\n                merged[total] = max(\n                    merged[total],\n                    base[baseBudget] + child[childBudget]\n                );\n            }\n        }\n\n        return merged;\n    }\n\n    int stockCost(int employee, int parentState) const {\n        int fullCost = (*presentPrice)[employee];\n        if (parentState == parentBought) {\n            return fullCost / discountDivisor;\n        }\n        return fullCost;\n    }\n\n    const vector<int>* presentPrice = nullptr;\n    const vector<int>* futurePrice = nullptr;\n    vector<vector<int>> children;\n    int maxBudget = noBudget;\n\n    static constexpr int stateCount = 2;\n    static constexpr int parentNotBought = 0;\n    static constexpr int parentBought = 1;\n    static constexpr int bossIndex = 0;\n    static constexpr int workerIndex = 1;\n    static constexpr int employeeIdOffset = 1;\n    static constexpr int ceoIndex = 0;\n    static constexpr int noBudget = 0;\n    static constexpr int includeZeroBudget = 1;\n    static constexpr int noProfit = 0;\n    static constexpr int discountDivisor = 2;\n    static constexpr int impossibleProfit = -1000000000;\n};"
