      "code": "class Solution {\npublic:\n    int maxProfit(\n        int n,\n        vector<int>& present,\n        vector<int>& future,\n        vector<vector<int>>& hierarchy,\n        int budget\n    ) {\n        maxBudget = budget;\n        current = &present;\n        tomorrow = &future;\n        tree.assign(n, vector<int>{});\n\n        for (const vector<int>& relation : hierarchy) {\n            int manager = relation[managerIndex] - employeeIdBase;\n            int employee = relation[employeeIndex] - employeeIdBase;\n            tree[manager].push_back(employee);\n        }\n\n        array<vector<int>, stateCount> root = build(ceoNode);\n        return root[withoutParentDiscount][budget];\n    }\n\nprivate:\n    array<vector<int>, stateCount> build(int node) const {\n        vector<array<vector<int>, stateCount>> childrenDp;\n        for (int child : tree[node]) {\n            childrenDp.push_back(build(child));\n        }\n\n        array<vector<int>, stateCount> answer;\n        answer[withoutParentDiscount] = solveChoice(\n            node,\n            fullPrice,\n            childrenDp\n        );\n        answer[withParentDiscount] = solveChoice(\n            node,\n            halfPrice,\n            childrenDp\n        );\n        return answer;\n    }\n\n    vector<int> solveChoice(\n        int node,\n        int priceMode,\n        const vector<array<vector<int>, stateCount>>& childrenDp\n    ) const {\n        vector<int> doNotBuy(maxBudget + zeroCapacitySlot, zeroProfit);\n        int cost = buyCost(node, priceMode);\n        int ownProfit = (*tomorrow)[node] - cost;\n        vector<int> buy(maxBudget + zeroCapacitySlot, negativeInfinity);\n\n        for (int capacity = cost; capacity <= maxBudget; ++capacity) {\n            buy[capacity] = ownProfit;\n        }\n\n        for (const auto& child : childrenDp) {\n            doNotBuy = combine(doNotBuy, child[withoutParentDiscount]);\n            buy = combine(buy, child[withParentDiscount]);\n        }\n\n        vector<int> best(maxBudget + zeroCapacitySlot, zeroProfit);\n        for (int capacity = emptyBudget; capacity <= maxBudget; ++capacity) {\n            best[capacity] = max(doNotBuy[capacity], buy[capacity]);\n        }\n        return best;\n    }\n\n    vector<int> combine(const vector<int>& left, const vector<int>& right) const {\n        vector<int> next(maxBudget + zeroCapacitySlot, negativeInfinity);\n\n        for (int capacity = emptyBudget; capacity <= maxBudget; ++capacity) {\n            for (int rightBudget = emptyBudget;\n                 rightBudget <= capacity;\n                 ++rightBudget) {\n                int leftBudget = capacity - rightBudget;\n                if (left[leftBudget] == negativeInfinity\n                    || right[rightBudget] == negativeInfinity) {\n                    continue;\n                }\n                next[capacity] = max(\n                    next[capacity],\n                    left[leftBudget] + right[rightBudget]\n                );\n            }\n        }\n\n        return next;\n    }\n\n    int buyCost(int node, int priceMode) const {\n        int price = (*current)[node];\n        if (priceMode == halfPrice) {\n            return price / discountFactor;\n        }\n        return price;\n    }\n\n    const vector<int>* current = nullptr;\n    const vector<int>* tomorrow = nullptr;\n    vector<vector<int>> tree;\n    int maxBudget = emptyBudget;\n\n    static constexpr int stateCount = 2;\n    static constexpr int withoutParentDiscount = 0;\n    static constexpr int withParentDiscount = 1;\n    static constexpr int fullPrice = 0;\n    static constexpr int halfPrice = 1;\n    static constexpr int managerIndex = 0;\n    static constexpr int employeeIndex = 1;\n    static constexpr int employeeIdBase = 1;\n    static constexpr int ceoNode = 0;\n    static constexpr int emptyBudget = 0;\n    static constexpr int zeroCapacitySlot = 1;\n    static constexpr int zeroProfit = 0;\n    static constexpr int discountFactor = 2;\n    static constexpr int negativeInfinity = -1000000000;\n};"
