      "code": "class Solution {\npublic:\n    vector<int> exclusiveTime(int n, vector<string>& logs) {\n        vector<int> exclusive(n, noTime);\n        stack<int> activeFunctions;\n        int previousTime = noTime;\n\n        for (const string& log : logs) {\n            LogEntry entry = parseLog(log);\n\n            if (entry.isStart) {\n                if (!activeFunctions.empty()) {\n                    int runningFunction = activeFunctions.top();\n                    exclusive[runningFunction] += entry.time - previousTime;\n                }\n\n                activeFunctions.push(entry.functionId);\n                previousTime = entry.time;\n                continue;\n            }\n\n            int runningFunction = activeFunctions.top();\n            exclusive[runningFunction] +=\n                entry.time - previousTime + inclusiveEnd;\n            activeFunctions.pop();\n            previousTime = entry.time + nextTimeUnit;\n        }\n\n        return exclusive;\n    }\n\nprivate:\n    struct LogEntry {\n        int functionId;\n        bool isStart;\n        int time;\n    };\n\n    LogEntry parseLog(const string& log) const {\n        size_t firstColon = log.find(fieldDelimiter);\n        size_t secondColon = log.find(fieldDelimiter, firstColon + nextField);\n\n        int functionId = stoi(log.substr(firstField, firstColon));\n        string event = log.substr(firstColon + nextField,\n                                  secondColon - firstColon - nextField);\n        int time = stoi(log.substr(secondColon + nextField));\n\n        return LogEntry{functionId, event == startEvent, time};\n    }\n\n    static constexpr int noTime = 0;\n    static constexpr int firstField = 0;\n    static constexpr int nextField = 1;\n    static constexpr int inclusiveEnd = 1;\n    static constexpr int nextTimeUnit = 1;\n    static constexpr char fieldDelimiter = ':';\n    inline static const string startEvent = \"start\";\n};"
