      "code": "class Solution {\npublic:\n    vector<int> asteroidCollision(vector<int>& asteroids) {\n        vector<int> survived;\n\n        for (int current : asteroids) {\n            bool alive = true;\n\n            while (alive && current < stationaryValue &&\n                   !survived.empty() && survived.back() > stationaryValue) {\n                int currentMass = abs(current);\n                int previousMass = survived.back();\n\n                if (previousMass < currentMass) {\n                    // The right-moving asteroid is smaller, so it explodes.\n                    survived.pop_back();\n                    continue;\n                }\n\n                if (previousMass == currentMass) {\n                    // Equal masses destroy both asteroids.\n                    survived.pop_back();\n                }\n\n                // In both the equal and previous-larger cases, current is gone.\n                alive = false;\n            }\n\n            if (alive) {\n                survived.push_back(current);\n            }\n        }\n\n        return survived;\n    }\n\nprivate:\n    static constexpr int stationaryValue = 0;\n};"
