      "code": "/**\n * Definition for a binary tree node.\n * struct TreeNode {\n *     int val;\n *     TreeNode *left;\n *     TreeNode *right;\n *     TreeNode() : val(0), left(nullptr), right(nullptr) {}\n *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n *     TreeNode(int x, TreeNode *left, TreeNode *right)\n *         : val(x), left(left), right(right) {}\n * };\n */\nclass Solution {\npublic:\n    TreeNode* constructMaximumBinaryTree(vector<int>& nums) {\n        return build(nums, firstIndex, static_cast<int>(nums.size()));\n    }\n\nprivate:\n    TreeNode* build(vector<int>& nums, int left, int right) {\n        if (left == right) {\n            return nullptr;\n        }\n\n        int maxIndex = left;\n        for (int i = left + nextIndexStep; i < right; ++i) {\n            if (nums[i] > nums[maxIndex]) {\n                maxIndex = i;\n            }\n        }\n\n        TreeNode* root = new TreeNode(nums[maxIndex]);\n        root->left = build(nums, left, maxIndex);\n        root->right = build(nums, maxIndex + nextIndexStep, right);\n        return root;\n    }\n\n    static constexpr int firstIndex = 0;\n    static constexpr int nextIndexStep = 1;\n};"
