      "code": "/**\n * Definition for a binary tree node.\n * struct TreeNode {\n *     int val;\n *     TreeNode *left;\n *     TreeNode *right;\n *     TreeNode() : val(0), left(nullptr), right(nullptr) {}\n *     TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}\n *     TreeNode(int x, TreeNode *left, TreeNode *right)\n *         : val(x), left(left), right(right) {}\n * };\n */\nclass Solution {\npublic:\n    vector<int> largestValues(TreeNode* root) {\n        vector<int> answer;\n        collectByDepth(root, rootDepth, answer);\n        return answer;\n    }\n\nprivate:\n    static constexpr int rootDepth = 0;\n\n    void collectByDepth(\n        TreeNode* node,\n        int depth,\n        vector<int>& answer\n    ) {\n        if (node == nullptr) {\n            return;\n        }\n\n        if (depth == static_cast<int>(answer.size())) {\n            // First node seen at this depth starts this row's maximum.\n            answer.push_back(node->val);\n        } else {\n            answer[depth] = max(answer[depth], node->val);\n        }\n\n        collectByDepth(node->left, depth + 1, answer);\n        collectByDepth(node->right, depth + 1, answer);\n    }\n};"
