      "code": "class Solution {\npublic:\n    long long maximumProfit(vector<int>& prices, int k) {\n        int n = static_cast<int>(prices.size());\n        vector<vector<array<long long, stateCount>>> dp(\n            n,\n            vector<array<long long, stateCount>>(k + transactionPadding)\n        );\n\n        for (int day = 0; day < n; ++day) {\n            for (int used = 0; used <= k; ++used) {\n                dp[day][used].fill(unreachableProfit);\n            }\n        }\n\n        dp[0][noTransaction][emptyState] = noProfit;\n        if (k >= firstTransaction) {\n            long long firstPrice = prices[0];\n            dp[0][firstTransaction][longState] = -firstPrice;\n            dp[0][firstTransaction][shortState] = firstPrice;\n        }\n\n        for (int day = 1; day < n; ++day) {\n            long long price = prices[day];\n\n            for (int used = 0; used <= k; ++used) {\n                const auto& previous = dp[day - previousDay][used];\n\n                dp[day][used][emptyState] = max({\n                    previous[emptyState],\n                    previous[longState] + price,\n                    previous[shortState] - price,\n                });\n\n                dp[day][used][longState] = previous[longState];\n                dp[day][used][shortState] = previous[shortState];\n\n                if (used == noTransaction) {\n                    continue;\n                }\n\n                long long previousEmpty =\n                    dp[day - previousDay][used - openedTransaction][emptyState];\n                if (previousEmpty == unreachableProfit) {\n                    continue;\n                }\n\n                // Opening a long position consumes one transaction.\n                dp[day][used][longState] = max(\n                    dp[day][used][longState],\n                    previousEmpty - price\n                );\n\n                // Opening a short position also consumes one transaction.\n                dp[day][used][shortState] = max(\n                    dp[day][used][shortState],\n                    previousEmpty + price\n                );\n            }\n        }\n\n        long long answer = noProfit;\n        for (int used = 0; used <= k; ++used) {\n            answer = max(answer, dp[n - lastDayOffset][used][emptyState]);\n        }\n        return answer;\n    }\n\nprivate:\n    static constexpr int emptyState = 0;\n    static constexpr int longState = 1;\n    static constexpr int shortState = 2;\n    static constexpr int stateCount = 3;\n    static constexpr int noTransaction = 0;\n    static constexpr int firstTransaction = 1;\n    static constexpr int openedTransaction = 1;\n    static constexpr int transactionPadding = 1;\n    static constexpr int previousDay = 1;\n    static constexpr int lastDayOffset = 1;\n    static constexpr long long noProfit = 0;\n    static constexpr long long unreachableProfit = LLONG_MIN / 4;\n};"
