      "code": "class Solution {\npublic:\n    long long maximumProfit(vector<int>& prices, int k) {\n        vector<array<long long, stateCount>> previous(k + transactionPadding);\n        vector<array<long long, stateCount>> current(k + transactionPadding);\n\n        resetStates(previous);\n        previous[noTransaction][emptyState] = noProfit;\n        if (k >= firstTransaction) {\n            long long firstPrice = prices[0];\n            previous[firstTransaction][longState] = -firstPrice;\n            previous[firstTransaction][shortState] = firstPrice;\n        }\n\n        int n = static_cast<int>(prices.size());\n        for (int day = 1; day < n; ++day) {\n            long long price = prices[day];\n            resetStates(current);\n\n            for (int used = 0; used <= k; ++used) {\n                current[used][emptyState] = max({\n                    previous[used][emptyState],\n                    previous[used][longState] + price,\n                    previous[used][shortState] - price,\n                });\n\n                current[used][longState] = previous[used][longState];\n                current[used][shortState] = previous[used][shortState];\n\n                if (used == noTransaction) {\n                    continue;\n                }\n\n                long long previousEmpty =\n                    previous[used - openedTransaction][emptyState];\n                if (previousEmpty == unreachableProfit) {\n                    continue;\n                }\n\n                // Read only from previous, never from current. This keeps\n                // same-day close-then-open paths out of the DP.\n                current[used][longState] = max(\n                    current[used][longState],\n                    previousEmpty - price\n                );\n                current[used][shortState] = max(\n                    current[used][shortState],\n                    previousEmpty + price\n                );\n            }\n\n            previous.swap(current);\n        }\n\n        long long answer = noProfit;\n        for (int used = 0; used <= k; ++used) {\n            answer = max(answer, previous[used][emptyState]);\n        }\n        return answer;\n    }\n\nprivate:\n    static constexpr int emptyState = 0;\n    static constexpr int longState = 1;\n    static constexpr int shortState = 2;\n    static constexpr int stateCount = 3;\n    static constexpr int noTransaction = 0;\n    static constexpr int firstTransaction = 1;\n    static constexpr int openedTransaction = 1;\n    static constexpr int transactionPadding = 1;\n    static constexpr long long noProfit = 0;\n    static constexpr long long unreachableProfit = LLONG_MIN / 4;\n\n    void resetStates(vector<array<long long, stateCount>>& states) const {\n        for (auto& state : states) {\n            state.fill(unreachableProfit);\n        }\n    }\n};"
