      "code": "class Solution {\npublic:\n    vector<vector<int>> findSubsequences(vector<int>& nums) {\n        uniqueSequences.clear();\n        path.clear();\n        dfs(nums, 0);\n\n        vector<vector<int>> answer;\n        answer.reserve(uniqueSequences.size());\n        for (const vector<int>& sequence : uniqueSequences) {\n            answer.push_back(sequence);\n        }\n        return answer;\n    }\n\nprivate:\n    static constexpr size_t minLength = 2;\n\n    set<vector<int>> uniqueSequences;\n    vector<int> path;\n\n    void dfs(const vector<int>& nums, int index) {\n        if (index == static_cast<int>(nums.size())) {\n            if (path.size() >= minLength) {\n                uniqueSequences.insert(path);\n            }\n            return;\n        }\n\n        int value = nums[index];\n        if (path.empty() || value >= path.back()) {\n            path.push_back(value);\n            dfs(nums, index + 1);\n            path.pop_back();\n        }\n\n        // Skipping keeps the original order because later choices use index + 1.\n        dfs(nums, index + 1);\n    }\n};"
