      "code": "class Solution {\npublic:\n    vector<int> diffWaysToCompute(string expression) {\n        memo.clear();\n        return solve(expression, 0, expression.size() - 1);\n    }\n\nprivate:\n    static constexpr char plusOp = '+';\n    static constexpr char minusOp = '-';\n    static constexpr char multiplyOp = '*';\n\n    map<pair<int, int>, vector<int>> memo;\n\n    vector<int> solve(\n        const string& expression,\n        int left,\n        int right\n    ) {\n        pair<int, int> interval = {left, right};\n        auto cached = memo.find(interval);\n        if (cached != memo.end()) {\n            return cached->second;\n        }\n\n        vector<int> results;\n        for (int split = left; split <= right; ++split) {\n            char op = expression[split];\n            if (!isOperator(op)) {\n                continue;\n            }\n\n            vector<int> leftResults = solve(expression, left, split - 1);\n            vector<int> rightResults = solve(expression, split + 1, right);\n\n            // Treat this operator as the last operation of the interval.\n            for (int leftValue : leftResults) {\n                for (int rightValue : rightResults) {\n                    results.push_back(\n                        applyOperator(leftValue, op, rightValue)\n                    );\n                }\n            }\n        }\n\n        if (results.empty()) {\n            results.push_back(parseNumber(expression, left, right));\n        }\n\n        memo[interval] = results;\n        return results;\n    }\n\n    bool isOperator(char ch) const {\n        return ch == plusOp || ch == minusOp || ch == multiplyOp;\n    }\n\n    int parseNumber(\n        const string& expression,\n        int left,\n        int right\n    ) const {\n        int value = 0;\n        for (int i = left; i <= right; ++i) {\n            value = value * 10 + expression[i] - '0';\n        }\n        return value;\n    }\n\n    int applyOperator(int leftValue, char op, int rightValue) const {\n        if (op == plusOp) {\n            return leftValue + rightValue;\n        }\n        if (op == minusOp) {\n            return leftValue - rightValue;\n        }\n        return leftValue * rightValue;\n    }\n};"
