      "code": "class NumMatrix {\npublic:\n    NumMatrix(vector<vector<int>>& matrix) {\n        int rows = matrix.size();\n        if (rows == 0) {\n            prefix.assign(1, vector<int>(1, 0));\n            return;\n        }\n\n        int cols = matrix[0].size();\n        prefix.assign(rows + 1, vector<int>(cols + 1, 0));\n\n        for (int row = 0; row < rows; ++row) {\n            for (int col = 0; col < cols; ++col) {\n                // prefix[row + 1][col + 1] stores sum of [0..row] x [0..col].\n                prefix[row + 1][col + 1] = prefix[row][col + 1]\n                    + prefix[row + 1][col]\n                    - prefix[row][col]\n                    + matrix[row][col];\n            }\n        }\n    }\n\n    int sumRegion(int row1, int col1, int row2, int col2) {\n        if (prefix.size() == emptyPrefixSize) {\n            return 0;\n        }\n\n        int afterRow2 = row2 + 1;\n        int afterCol2 = col2 + 1;\n\n        // Big rectangle - top strip - left strip + overlapped top-left part.\n        return prefix[afterRow2][afterCol2]\n            - prefix[row1][afterCol2]\n            - prefix[afterRow2][col1]\n            + prefix[row1][col1];\n    }\n\nprivate:\n    static const int emptyPrefixSize = 1;\n\n    vector<vector<int>> prefix;\n};\n\n/**\n * Your NumMatrix object will be instantiated and called as such:\n * NumMatrix* obj = new NumMatrix(matrix);\n * int param_1 = obj->sumRegion(row1, col1, row2, col2);\n */"
