      "code": "class Solution {\npublic:\n    bool canMeasureWater(\n        int jug1Capacity,\n        int jug2Capacity,\n        int targetCapacity\n    ) {\n        if (targetCapacity == 0) {\n            return true;\n        }\n\n        int totalCapacity = jug1Capacity + jug2Capacity;\n        if (targetCapacity > totalCapacity) {\n            return false;\n        }\n\n        int divisor = greatestCommonDivisor(jug1Capacity, jug2Capacity);\n        return targetCapacity % divisor == 0;\n    }\n\nprivate:\n    int greatestCommonDivisor(int a, int b) const {\n        while (b != 0) {\n            int remainder = a % b;\n            a = b;\n            b = remainder;\n        }\n\n        return a;\n    }\n};"
