      "code": "class Solution {\npublic:\n    int findRadius(vector<int>& houses, vector<int>& heaters) {\n        sort(heaters.begin(), heaters.end());\n\n        long long answer = 0;\n        for (int house : houses) {\n            long long nearestDistance = distanceToNearestHeater(\n                house,\n                heaters\n            );\n\n            // One shared radius must satisfy the hardest house.\n            answer = max(answer, nearestDistance);\n        }\n\n        return static_cast<int>(answer);\n    }\n\nprivate:\n    long long distanceToNearestHeater(\n        int house,\n        const vector<int>& heaters\n    ) const {\n        auto right = lower_bound(heaters.begin(), heaters.end(), house);\n        long long nearestDistance = numeric_limits<long long>::max();\n\n        if (right != heaters.end()) {\n            nearestDistance = min(\n                nearestDistance,\n                absoluteDistance(house, *right)\n            );\n        }\n\n        if (right != heaters.begin()) {\n            auto left = prev(right);\n            nearestDistance = min(\n                nearestDistance,\n                absoluteDistance(house, *left)\n            );\n        }\n\n        return nearestDistance;\n    }\n\n    long long absoluteDistance(int first, int second) const {\n        long long distance = static_cast<long long>(first) - second;\n        if (distance < 0) {\n            return -distance;\n        }\n        return distance;\n    }\n};"
