      "code": "class Solution {\npublic:\n    vector<vector<int>> matrixBlockSum(vector<vector<int>>& mat, int k) {\n        int rows = mat.size();\n        int cols = mat[0].size();\n\n        vector<vector<int>> prefix(rows + 1, vector<int>(cols + 1, 0));\n        for (int row = 0; row < rows; ++row) {\n            for (int col = 0; col < cols; ++col) {\n                // prefix[row + 1][col + 1] stores sum of [0..row] x [0..col].\n                prefix[row + 1][col + 1] = prefix[row][col + 1]\n                    + prefix[row + 1][col]\n                    - prefix[row][col]\n                    + mat[row][col];\n            }\n        }\n\n        vector<vector<int>> answer(rows, vector<int>(cols, 0));\n        for (int row = 0; row < rows; ++row) {\n            for (int col = 0; col < cols; ++col) {\n                int top = max(0, row - k);\n                int bottom = min(rows - 1, row + k);\n                int left = max(0, col - k);\n                int right = min(cols - 1, col + k);\n\n                answer[row][col] = prefix[bottom + 1][right + 1]\n                    - prefix[top][right + 1]\n                    - prefix[bottom + 1][left]\n                    + prefix[top][left];\n            }\n        }\n\n        return answer;\n    }\n};"
