      "code": "class Solution {\npublic:\n    int countTrapezoids(vector<vector<int>>& points) {\n        const long long modulo = 1000000007LL;\n        unordered_map<int, long long> countByY;\n\n        for (const vector<int>& point : points) {\n            ++countByY[point[1]];\n        }\n\n        long long answer = 0;\n        long long previousPairs = 0;\n\n        for (const auto& entry : countByY) {\n            long long count = entry.second;\n            // Any two points on the same y-level form one horizontal edge.\n            long long currentPairs = count * (count - 1) / 2 % modulo;\n\n            // Pair every current horizontal edge with one from an earlier y-level.\n            answer = (answer + previousPairs * currentPairs) % modulo;\n            previousPairs = (previousPairs + currentPairs) % modulo;\n        }\n\n        return static_cast<int>(answer);\n    }\n};"
