      "code": "class Solution {\npublic:\n    vector<int> findDuplicates(vector<int>& nums) {\n        vector<int> duplicates;\n        int n = nums.size();\n        int i = 0;\n\n        while (i < n) {\n            int value = nums[i];\n            int targetIndex = value - 1;\n\n            if (targetIndex == i) {\n                ++i;\n                continue;\n            }\n\n            if (nums[targetIndex] == value) {\n                duplicates.push_back(value);\n                ++i;\n                continue;\n            }\n\n            swap(nums[i], nums[targetIndex]);\n        }\n\n        return duplicates;\n    }\n};"
