      "code": "class Solution {\npublic:\n    vector<string> findRepeatedDnaSequences(string s) {\n        const int windowLength = 10;\n        const int bitsPerChar = 2;\n        const int alphabetSize = 26;\n        const char firstUppercaseLetter = 'A';\n        const int mask = (1 << (windowLength * bitsPerChar)) - 1;\n\n        int n = s.size();\n        if (n < windowLength) {\n            return {};\n        }\n\n        vector<int> codeByChar(alphabetSize);\n        codeByChar['A' - firstUppercaseLetter] = 0;\n        codeByChar['C' - firstUppercaseLetter] = 1;\n        codeByChar['G' - firstUppercaseLetter] = 2;\n        codeByChar['T' - firstUppercaseLetter] = 3;\n\n        unordered_set<int> seen;\n        unordered_set<int> repeated;\n        vector<string> answer;\n        int code = 0;\n\n        for (int right = 0; right < n; ++right) {\n            code <<= bitsPerChar;\n            code |= codeByChar[s[right] - firstUppercaseLetter];\n            code &= mask;\n\n            if (right + 1 < windowLength) {\n                continue;\n            }\n\n            if (seen.insert(code).second) {\n                continue;\n            }\n\n            if (repeated.insert(code).second) {\n                int start = right - windowLength + 1;\n                answer.push_back(s.substr(start, windowLength));\n            }\n        }\n\n        return answer;\n    }\n};"
