      "code": "class Solution {\npublic:\n    int minMeetingRooms(vector<vector<int>>& intervals) {\n        if (intervals.empty()) {\n            return 0;\n        }\n\n        sort(intervals.begin(), intervals.end());\n\n        priority_queue<int, vector<int>, greater<int>> endTimes;\n        int answer = 0;\n\n        for (const vector<int>& interval : intervals) {\n            int start = interval[0];\n            int end = interval[1];\n\n            // Ended meetings have released their rooms under [start, end).\n            while (!endTimes.empty() && endTimes.top() <= start) {\n                endTimes.pop();\n            }\n\n            endTimes.push(end);\n            answer = max(answer, static_cast<int>(endTimes.size()));\n        }\n\n        return answer;\n    }\n};"
