      "code": "class Solution {\npublic:\n    int largestOverlap(vector<vector<int>>& img1,\n                       vector<vector<int>>& img2) {\n        int n = img1.size();\n        vector<pair<int, int>> ones1 = collectOnes(img1);\n        vector<pair<int, int>> ones2 = collectOnes(img2);\n        unordered_map<int, int> shiftCounts;\n        int best = 0;\n\n        const int offset = n - 1;\n        const int width = 2 * n - 1;\n\n        for (const auto& [row1, col1] : ones1) {\n            for (const auto& [row2, col2] : ones2) {\n                int rowShift = row2 - row1;\n                int colShift = col2 - col1;\n                int key = encodeShift(rowShift, colShift, offset, width);\n                best = max(best, ++shiftCounts[key]);\n            }\n        }\n\n        return best;\n    }\n\nprivate:\n    vector<pair<int, int>> collectOnes(vector<vector<int>>& image) {\n        vector<pair<int, int>> ones;\n        int n = image.size();\n\n        for (int row = 0; row < n; ++row) {\n            for (int col = 0; col < n; ++col) {\n                if (image[row][col] == 1) {\n                    ones.push_back({row, col});\n                }\n            }\n        }\n\n        return ones;\n    }\n\n    int encodeShift(int rowShift, int colShift, int offset, int width) {\n        return (rowShift + offset) * width + colShift + offset;\n    }\n};"
