      "code": "class Solution {\npublic:\n    int largestOverlap(vector<vector<int>>& img1,\n                       vector<vector<int>>& img2) {\n        int n = img1.size();\n        int best = 0;\n\n        for (int rowShift = 1 - n; rowShift < n; ++rowShift) {\n            for (int colShift = 1 - n; colShift < n; ++colShift) {\n                best = max(best, countOverlap(img1, img2,\n                                              rowShift, colShift));\n            }\n        }\n\n        return best;\n    }\n\nprivate:\n    int countOverlap(vector<vector<int>>& img1,\n                     vector<vector<int>>& img2,\n                     int rowShift,\n                     int colShift) {\n        int n = img1.size();\n        int overlap = 0;\n\n        for (int row1 = 0; row1 < n; ++row1) {\n            for (int col1 = 0; col1 < n; ++col1) {\n                int row2 = row1 + rowShift;\n                int col2 = col1 + colShift;\n                if (isInside(row2, col2, n) &&\n                    img1[row1][col1] == 1 &&\n                    img2[row2][col2] == 1) {\n                    ++overlap;\n                }\n            }\n        }\n\n        return overlap;\n    }\n\n    bool isInside(int row, int col, int n) {\n        return row >= 0 && row < n && col >= 0 && col < n;\n    }\n};"
