      "code": "class Solution {\npublic:\n    string numberToWords(int num) {\n        if (num == 0) {\n            return zeroWord;\n        }\n\n        vector<pair<int, string>> groups = {\n            {billionValue, billionWord},\n            {millionValue, millionWord},\n            {thousandValue, thousandWord},\n            {oneValue, emptyWord},\n        };\n        vector<string> words;\n\n        for (const auto& [value, scaleName] : groups) {\n            int groupValue = num / value;\n            if (groupValue == 0) {\n                continue;\n            }\n\n            appendThreeDigitWords(groupValue, words);\n            if (!scaleName.empty()) {\n                words.push_back(scaleName);\n            }\n            num %= value;\n        }\n\n        return joinWords(words);\n    }\n\nprivate:\n    static constexpr int oneValue = 1;\n    static constexpr int tenValue = 10;\n    static constexpr int twentyValue = 20;\n    static constexpr int hundredValue = 100;\n    static constexpr int thousandValue = 1000;\n    static constexpr int millionValue = 1000000;\n    static constexpr int billionValue = 1000000000;\n    static constexpr const char* emptyWord = \"\";\n    static constexpr const char* zeroWord = \"Zero\";\n    static constexpr const char* hundredWord = \"Hundred\";\n    static constexpr const char* thousandWord = \"Thousand\";\n    static constexpr const char* millionWord = \"Million\";\n    static constexpr const char* billionWord = \"Billion\";\n\n    const vector<string>& smallWords() {\n        static const vector<string> words = {\n            \"\", \"One\", \"Two\", \"Three\", \"Four\", \"Five\", \"Six\",\n            \"Seven\", \"Eight\", \"Nine\", \"Ten\", \"Eleven\", \"Twelve\",\n            \"Thirteen\", \"Fourteen\", \"Fifteen\", \"Sixteen\",\n            \"Seventeen\", \"Eighteen\", \"Nineteen\",\n        };\n        return words;\n    }\n\n    const vector<string>& tensWords() {\n        static const vector<string> words = {\n            \"\", \"\", \"Twenty\", \"Thirty\", \"Forty\", \"Fifty\",\n            \"Sixty\", \"Seventy\", \"Eighty\", \"Ninety\",\n        };\n        return words;\n    }\n\n    void appendThreeDigitWords(int num, vector<string>& words) {\n        if (num >= hundredValue) {\n            words.push_back(smallWords()[num / hundredValue]);\n            words.push_back(hundredWord);\n            num %= hundredValue;\n        }\n\n        if (num >= twentyValue) {\n            words.push_back(tensWords()[num / tenValue]);\n            num %= tenValue;\n        }\n\n        if (num > 0) {\n            words.push_back(smallWords()[num]);\n        }\n    }\n\n    string joinWords(const vector<string>& words) {\n        string result;\n        for (const string& word : words) {\n            if (!result.empty()) {\n                result += ' ';\n            }\n            result += word;\n        }\n        return result;\n    }\n};"
