      "code": "class Solution {\npublic:\n    int kthSmallest(TreeNode* root, int k) {\n        targetRank = k;\n        visited = 0;\n        answer = 0;\n        found = false;\n\n        inorder(root);\n        return answer;\n    }\n\nprivate:\n    int targetRank = 0;\n    int visited = 0;\n    int answer = 0;\n    bool found = false;\n\n    void inorder(TreeNode* node) {\n        if (node == nullptr || found) {\n            return;\n        }\n\n        inorder(node->left);\n        if (found) {\n            return;\n        }\n\n        // Visiting nodes in inorder gives values from small to large.\n        ++visited;\n        if (visited == targetRank) {\n            answer = node->val;\n            found = true;\n            return;\n        }\n\n        inorder(node->right);\n    }\n};"
