      "code": "class Solution {\npublic:\n    vector<int> findDiagonalOrder(vector<vector<int>>& mat) {\n        int rowCount = mat.size();\n        if (rowCount == 0) {\n            return {};\n        }\n\n        int colCount = mat[0].size();\n        if (colCount == 0) {\n            return {};\n        }\n\n        int lastRow = rowCount - 1;\n        int lastCol = colCount - 1;\n        int totalCount = rowCount * colCount;\n        vector<int> answer;\n        answer.reserve(totalCount);\n\n        int row = 0;\n        int col = 0;\n        bool movingUp = true;\n\n        while (answer.size() < static_cast<size_t>(totalCount)) {\n            answer.push_back(mat[row][col]);\n\n            if (movingUp) {\n                // At the right edge, move down before flipping direction.\n                if (col == lastCol) {\n                    ++row;\n                    movingUp = false;\n                } else if (row == 0) {\n                    ++col;\n                    movingUp = false;\n                } else {\n                    --row;\n                    ++col;\n                }\n            } else {\n                // At the bottom edge, move right before flipping direction.\n                if (row == lastRow) {\n                    ++col;\n                    movingUp = true;\n                } else if (col == 0) {\n                    ++row;\n                    movingUp = true;\n                } else {\n                    ++row;\n                    --col;\n                }\n            }\n        }\n\n        return answer;\n    }\n};"
