      "code": "class Solution {\npublic:\n    vector<int> findDiagonalOrder(vector<vector<int>>& mat) {\n        int rowCount = mat.size();\n        if (rowCount == 0) {\n            return {};\n        }\n\n        int colCount = mat[0].size();\n        if (colCount == 0) {\n            return {};\n        }\n\n        int diagonalCount = rowCount + colCount - 1;\n        vector<int> answer;\n        answer.reserve(rowCount * colCount);\n\n        for (int diagonal = 0; diagonal < diagonalCount; ++diagonal) {\n            vector<int> current;\n            int firstRow = max(0, diagonal - colCount + 1);\n            int lastRow = min(rowCount - 1, diagonal);\n\n            for (int row = firstRow; row <= lastRow; ++row) {\n                int col = diagonal - row;\n                current.push_back(mat[row][col]);\n            }\n\n            bool shouldReverse = diagonal % 2 == 0;\n            if (shouldReverse) {\n                reverse(current.begin(), current.end());\n            }\n\n            answer.insert(answer.end(), current.begin(), current.end());\n        }\n\n        return answer;\n    }\n};"
