      "code": "class Solution {\npublic:\n    int maxStability(int n, vector<vector<int>>& edges, int k) {\n        if (!canConnectWithAllEdges(n, edges)) {\n            return impossibleAnswer;\n        }\n\n        long long high = 0;\n        bool hasMustEdge = false;\n        int mustUpperBound = numeric_limits<int>::max();\n        for (const auto& edge : edges) {\n            int strength = edge[strengthIndex];\n            if (isMustEdge(edge)) {\n                hasMustEdge = true;\n                mustUpperBound = min(mustUpperBound, strength);\n                high = max(high, static_cast<long long>(strength));\n            } else {\n                high = max(high, static_cast<long long>(strength) * upgradeFactor);\n            }\n        }\n        if (hasMustEdge) {\n            high = min(high, static_cast<long long>(mustUpperBound));\n        }\n\n        int left = 0;\n        int right = static_cast<int>(high);\n        int answer = impossibleAnswer;\n        while (left <= right) {\n            int middle = left + (right - left) / 2;\n            if (canBuildWithLimit(n, edges, k, middle)) {\n                answer = middle;\n                left = middle + 1;\n            } else {\n                right = middle - 1;\n            }\n        }\n\n        return answer;\n    }\n\nprivate:\n    static constexpr int fromIndex = 0;\n    static constexpr int toIndex = 1;\n    static constexpr int strengthIndex = 2;\n    static constexpr int mustIndex = 3;\n    static constexpr int mustFlag = 1;\n    static constexpr int upgradeFactor = 2;\n    static constexpr int impossibleAnswer = -1;\n\n    class DisjointSet {\n    public:\n        explicit DisjointSet(int n) : parent(n), size(n, 1), groups(n) {\n            iota(parent.begin(), parent.end(), 0);\n        }\n\n        int find(int node) {\n            if (parent[node] != node) {\n                parent[node] = find(parent[node]);\n            }\n            return parent[node];\n        }\n\n        bool unite(int first, int second) {\n            int rootFirst = find(first);\n            int rootSecond = find(second);\n            if (rootFirst == rootSecond) {\n                return false;\n            }\n            if (size[rootFirst] < size[rootSecond]) {\n                swap(rootFirst, rootSecond);\n            }\n            parent[rootSecond] = rootFirst;\n            size[rootFirst] += size[rootSecond];\n            --groups;\n            return true;\n        }\n\n        int count() const {\n            return groups;\n        }\n\n    private:\n        vector<int> parent;\n        vector<int> size;\n        int groups;\n    };\n\n    static bool isMustEdge(const vector<int>& edge) {\n        return edge[mustIndex] == mustFlag;\n    }\n\n    bool canConnectWithAllEdges(int n, const vector<vector<int>>& edges) {\n        DisjointSet dsu(n);\n        for (const auto& edge : edges) {\n            dsu.unite(edge[fromIndex], edge[toIndex]);\n        }\n        return dsu.count() == 1;\n    }\n\n    bool canBuildWithLimit(\n        int n,\n        const vector<vector<int>>& edges,\n        int k,\n        int limit\n    ) {\n        DisjointSet dsu(n);\n        for (const auto& edge : edges) {\n            if (!isMustEdge(edge)) {\n                continue;\n            }\n            if (edge[strengthIndex] < limit) {\n                return false;\n            }\n            if (!dsu.unite(edge[fromIndex], edge[toIndex])) {\n                return false;\n            }\n        }\n\n        for (const auto& edge : edges) {\n            if (isMustEdge(edge) || edge[strengthIndex] < limit) {\n                continue;\n            }\n            dsu.unite(edge[fromIndex], edge[toIndex]);\n        }\n\n        int usedUpgrades = 0;\n        for (const auto& edge : edges) {\n            if (isMustEdge(edge) || edge[strengthIndex] >= limit) {\n                continue;\n            }\n            long long upgradedStrength =\n                static_cast<long long>(edge[strengthIndex]) * upgradeFactor;\n            if (upgradedStrength < limit) {\n                continue;\n            }\n            if (!dsu.unite(edge[fromIndex], edge[toIndex])) {\n                continue;\n            }\n            ++usedUpgrades;\n            if (usedUpgrades > k) {\n                return false;\n            }\n        }\n\n        return dsu.count() == 1;\n    }\n};"
