      "sourceUrl": "https://leetcode.cn/problems/can-place-flowers/description/",
      "code": "class Solution {\npublic:\n    bool canPlaceFlowers(vector<int>& flowerbed, int n) {\n        if (n == 0) {\n            return true;\n        }\n\n        int size = flowerbed.size();\n        int emptyCount = 0;\n        int planted = 0;\n        bool leftHasFlower = false;\n\n        for (int i = 0; i <= size; ++i) {\n            bool reachesEnd = i == size;\n            bool meetsFlower = !reachesEnd && flowerbed[i] == 1;\n            if (!reachesEnd && !meetsFlower) {\n                ++emptyCount;\n                continue;\n            }\n\n            if (emptyCount > 0) {\n                bool rightHasFlower = !reachesEnd;\n                int usableEmpty = emptyCount;\n                if (leftHasFlower) {\n                    --usableEmpty;\n                }\n                if (rightHasFlower) {\n                    --usableEmpty;\n                }\n                if (usableEmpty > 0) {\n                    planted += (usableEmpty + 1) / 2;\n                }\n                if (planted >= n) {\n                    return true;\n                }\n            }\n\n            emptyCount = 0;\n            leftHasFlower = !reachesEnd;\n        }\n\n        return false;\n    }\n};"
