      "code": "class Solution {\npublic:\n    vector<string> fullJustify(vector<string>& words, int maxWidth) {\n        vector<string> result;\n        int n = words.size();\n        int start = 0;\n\n        while (start < n) {\n            int end = start;\n            int letters = 0;\n\n            while (end < n) {\n                int nextLetters = letters + words[end].size();\n                int minSpaces = end - start;\n                if (nextLetters + minSpaces > maxWidth) {\n                    break;\n                }\n                letters = nextLetters;\n                ++end;\n            }\n\n            int wordCount = end - start;\n            bool isLastLine = end == n;\n            string line;\n\n            if (isLastLine || wordCount == 1) {\n                for (int i = start; i < end; ++i) {\n                    if (i > start) {\n                        line.push_back(' ');\n                    }\n                    line += words[i];\n                }\n                line.append(maxWidth - line.size(), ' ');\n            } else {\n                int spaces = maxWidth - letters;\n                int gaps = wordCount - 1;\n                int baseSpaces = spaces / gaps;\n                int extraSpaces = spaces % gaps;\n\n                for (int i = start; i < end; ++i) {\n                    line += words[i];\n                    if (i + 1 == end) {\n                        continue;\n                    }\n\n                    int extra = (i - start < extraSpaces) ? 1 : 0;\n                    line.append(baseSpaces + extra, ' ');\n                }\n            }\n\n            result.push_back(line);\n            start = end;\n        }\n\n        return result;\n    }\n};"
