      "code": "class Solution {\npublic:\n    int peakIndexInMountainArray(vector<int>& arr) {\n        int left = 0;\n        int right = arr.size() - 1;\n\n        while (left < right) {\n            int mid = left + (right - left) / 2;\n\n            if (arr[mid] < arr[mid + 1]) {\n                // The slope is still rising, so the peak is on the right.\n                left = mid + 1;\n            } else {\n                // Mid may already be the peak, so keep it in the range.\n                right = mid;\n            }\n        }\n\n        return left;\n    }\n};"
