      "code": "class Solution {\npublic:\n    int peakIndexInMountainArray(vector<int>& arr) {\n        int n = arr.size();\n\n        for (int i = 0; i + 1 < n; ++i) {\n            if (arr[i] > arr[i + 1]) {\n                // The first drop starts immediately after the peak.\n                return i;\n            }\n        }\n\n        return -1;\n    }\n};"
