      "code": "class Solution {\npublic:\n    bool isEvenOddTree(TreeNode* root) {\n        if (root == nullptr) {\n            return true;\n        }\n\n        queue<TreeNode*> nodes;\n        nodes.push(root);\n        int level = firstLevel;\n\n        while (!nodes.empty()) {\n            int levelSize = static_cast<int>(nodes.size());\n            bool isEvenLevel = level % parityDivisor == evenLevelRemainder;\n            int previous = isEvenLevel ? lowerSentinel : upperSentinel;\n\n            for (int i = firstIndex; i < levelSize; ++i) {\n                TreeNode* node = nodes.front();\n                nodes.pop();\n\n                int value = node->val;\n                if (!hasValidParity(value, isEvenLevel) ||\n                    !hasValidOrder(value, previous, isEvenLevel)) {\n                    return false;\n                }\n                previous = value;\n\n                // Null children are absent nodes, so they do not enter a level.\n                if (node->left != nullptr) {\n                    nodes.push(node->left);\n                }\n                if (node->right != nullptr) {\n                    nodes.push(node->right);\n                }\n            }\n\n            level += nextLevelStep;\n        }\n\n        return true;\n    }\n\nprivate:\n    bool hasValidParity(int value, bool isEvenLevel) const {\n        bool isOddValue = value % parityDivisor == oddValueRemainder;\n        return isEvenLevel ? isOddValue : !isOddValue;\n    }\n\n    bool hasValidOrder(\n        int value,\n        int previous,\n        bool isEvenLevel\n    ) const {\n        return isEvenLevel ? value > previous : value < previous;\n    }\n\n    static constexpr int firstLevel = 0;\n    static constexpr int firstIndex = 0;\n    static constexpr int nextLevelStep = 1;\n    static constexpr int parityDivisor = 2;\n    static constexpr int evenLevelRemainder = 0;\n    static constexpr int oddValueRemainder = 1;\n    static constexpr int lowerSentinel = 0;\n    static constexpr int upperSentinel = 1000001;\n};"
