      "code": "class Solution {\npublic:\n    vector<double> calcEquation(\n        vector<vector<string>>& equations,\n        vector<double>& values,\n        vector<vector<string>>& queries\n    ) {\n        for (int i = 0; i < static_cast<int>(equations.size()); ++i) {\n            unite(equations[i][fromIndex], equations[i][toIndex], values[i]);\n        }\n\n        vector<double> answers;\n        answers.reserve(queries.size());\n\n        for (const vector<string>& query : queries) {\n            answers.push_back(getRatio(query[fromIndex], query[toIndex]));\n        }\n\n        return answers;\n    }\n\nprivate:\n    unordered_map<string, string> parent;\n    unordered_map<string, double> weightToParent;\n\n    static constexpr int fromIndex = 0;\n    static constexpr int toIndex = 1;\n    static constexpr double impossible = -1.0;\n    static constexpr double identity = 1.0;\n\n    void addIfAbsent(const string& variable) {\n        if (parent.count(variable) != 0) {\n            return;\n        }\n\n        parent[variable] = variable;\n        weightToParent[variable] = identity;\n    }\n\n    string findRoot(const string& variable) {\n        if (parent[variable] == variable) {\n            return variable;\n        }\n\n        string oldParent = parent[variable];\n        string root = findRoot(oldParent);\n\n        // If variable / oldParent = a and oldParent / root = b, then\n        // variable / root = a * b after path compression.\n        weightToParent[variable] *= weightToParent[oldParent];\n        parent[variable] = root;\n        return root;\n    }\n\n    void unite(const string& numerator, const string& denominator, double ratio) {\n        addIfAbsent(numerator);\n        addIfAbsent(denominator);\n\n        string numeratorRoot = findRoot(numerator);\n        string denominatorRoot = findRoot(denominator);\n        if (numeratorRoot == denominatorRoot) {\n            return;\n        }\n\n        // We store weightToParent[x] as x / parent[x].\n        // Need numerator / denominator = ratio.\n        // After linking numeratorRoot under denominatorRoot:\n        // numerator / denominator =\n        // (numerator / numeratorRoot) *\n        // (numeratorRoot / denominatorRoot) /\n        // (denominator / denominatorRoot).\n        parent[numeratorRoot] = denominatorRoot;\n        weightToParent[numeratorRoot] =\n            ratio * weightToParent[denominator] / weightToParent[numerator];\n    }\n\n    double getRatio(const string& numerator, const string& denominator) {\n        if (parent.count(numerator) == 0 || parent.count(denominator) == 0) {\n            return impossible;\n        }\n\n        string numeratorRoot = findRoot(numerator);\n        string denominatorRoot = findRoot(denominator);\n        if (numeratorRoot != denominatorRoot) {\n            return impossible;\n        }\n\n        return weightToParent[numerator] / weightToParent[denominator];\n    }\n};"
