      "code": "class Solution {\npublic:\n    int evalRPN(vector<string>& tokens) {\n        vector<int> values;\n\n        for (const string& token : tokens) {\n            if (!isOperator(token)) {\n                values.push_back(stoi(token));\n                continue;\n            }\n\n            int right = values.back();\n            values.pop_back();\n            int left = values.back();\n            values.pop_back();\n\n            values.push_back(applyOperator(left, right, token[0]));\n        }\n\n        return values.back();\n    }\n\nprivate:\n    static constexpr size_t operatorTokenLength = 1;\n    static constexpr char plusOperator = '+';\n    static constexpr char minusOperator = '-';\n    static constexpr char multiplyOperator = '*';\n    static constexpr char divideOperator = '/';\n\n    bool isOperator(const string& token) const {\n        if (token.size() != operatorTokenLength) {\n            return false;\n        }\n\n        char op = token[0];\n        return op == plusOperator || op == minusOperator ||\n               op == multiplyOperator || op == divideOperator;\n    }\n\n    int applyOperator(int left, int right, char op) const {\n        if (op == plusOperator) {\n            return left + right;\n        }\n        if (op == minusOperator) {\n            return left - right;\n        }\n        if (op == multiplyOperator) {\n            return left * right;\n        }\n        return left / right;\n    }\n};"
