      "code": "class Solution {\npublic:\n    int minSwapsCouples(vector<int>& row) {\n        const int seatCount = static_cast<int>(row.size());\n        const int coupleCount = seatCount / seatsPerSofa;\n        UnionFind unionFind(coupleCount);\n\n        for (int seat = 0; seat < seatCount; seat += seatsPerSofa) {\n            const int firstCouple = row[seat] / seatsPerSofa;\n            const int secondCouple = row[seat + 1] / seatsPerSofa;\n            unionFind.unite(firstCouple, secondCouple);\n        }\n\n        return coupleCount - unionFind.componentCount();\n    }\n\nprivate:\n    static constexpr int seatsPerSofa = 2;\n\n    class UnionFind {\n    public:\n        explicit UnionFind(int size) : parent(size), rank(size, 0), count(size) {\n            iota(parent.begin(), parent.end(), 0);\n        }\n\n        int find(int node) {\n            if (parent[node] != node) {\n                parent[node] = find(parent[node]);\n            }\n            return parent[node];\n        }\n\n        void unite(int first, int second) {\n            int firstRoot = find(first);\n            int secondRoot = find(second);\n            if (firstRoot == secondRoot) {\n                return;\n            }\n\n            if (rank[firstRoot] < rank[secondRoot]) {\n                swap(firstRoot, secondRoot);\n            }\n            parent[secondRoot] = firstRoot;\n            if (rank[firstRoot] == rank[secondRoot]) {\n                ++rank[firstRoot];\n            }\n            --count;\n        }\n\n        int componentCount() const {\n            return count;\n        }\n\n    private:\n        vector<int> parent;\n        vector<int> rank;\n        int count;\n    };\n};"
