      "code": "class Solution {\npublic:\n    vector<double> medianSlidingWindow(vector<int>& nums, int k) {\n        windowSize = k;\n        vector<double> medians;\n\n        for (int right = 0; right < nums.size(); ++right) {\n            addNum(nums[right]);\n            if (right >= k) {\n                removeNum(nums[right - k]);\n            }\n            if (right + 1 >= k) {\n                medians.push_back(currentMedian());\n            }\n        }\n\n        return medians;\n    }\n\nprivate:\n    static constexpr int balanceLimit = 1;\n    static constexpr int splitFactor = 2;\n    static constexpr int oddRemainder = 1;\n\n    priority_queue<int> small;\n    priority_queue<int, vector<int>, greater<int>> large;\n    unordered_map<int, int> delayed;\n    int smallSize = 0;\n    int largeSize = 0;\n    int windowSize = 0;\n\n    void addNum(int num) {\n        if (small.empty() || num <= small.top()) {\n            small.push(num);\n            ++smallSize;\n        } else {\n            large.push(num);\n            ++largeSize;\n        }\n        rebalance();\n    }\n\n    void removeNum(int num) {\n        prune(small);\n        prune(large);\n        ++delayed[num];\n\n        if (!small.empty() && num <= small.top()) {\n            --smallSize;\n            if (num == small.top()) {\n                prune(small);\n            }\n        } else {\n            --largeSize;\n            if (!large.empty() && num == large.top()) {\n                prune(large);\n            }\n        }\n        rebalance();\n    }\n\n    double currentMedian() {\n        prune(small);\n        prune(large);\n        if (windowSize % splitFactor == oddRemainder) {\n            return static_cast<double>(small.top());\n        }\n        double left = static_cast<double>(small.top());\n        double right = static_cast<double>(large.top());\n        return (left + right) / splitFactor;\n    }\n\n    void rebalance() {\n        prune(small);\n        prune(large);\n\n        if (smallSize > largeSize + balanceLimit) {\n            large.push(small.top());\n            small.pop();\n            --smallSize;\n            ++largeSize;\n            prune(small);\n        } else if (smallSize < largeSize) {\n            small.push(large.top());\n            large.pop();\n            ++smallSize;\n            --largeSize;\n            prune(large);\n        }\n    }\n\n    template <typename Heap>\n    void prune(Heap& heap) {\n        while (!heap.empty()) {\n            int value = heap.top();\n            auto it = delayed.find(value);\n            if (it == delayed.end()) {\n                break;\n            }\n\n            heap.pop();\n            --it->second;\n            if (it->second == 0) {\n                delayed.erase(it);\n            }\n        }\n    }\n};"
