      "code": "class Solution {\npublic:\n    vector<double> medianSlidingWindow(vector<int>& nums, int k) {\n        windowSize = k;\n        vector<double> medians;\n\n        for (int right = 0; right < nums.size(); ++right) {\n            addNum(nums[right]);\n            if (right >= k) {\n                removeNum(nums[right - k]);\n            }\n            if (right + 1 >= k) {\n                medians.push_back(currentMedian());\n            }\n        }\n\n        return medians;\n    }\n\nprivate:\n    static constexpr int balanceLimit = 1;\n    static constexpr int splitFactor = 2;\n    static constexpr int oddRemainder = 1;\n\n    multiset<int> low;\n    multiset<int> high;\n    int windowSize = 0;\n\n    void addNum(int num) {\n        if (low.empty() || num <= *low.rbegin()) {\n            low.insert(num);\n        } else {\n            high.insert(num);\n        }\n        rebalance();\n    }\n\n    void removeNum(int num) {\n        auto lowIt = low.find(num);\n        if (lowIt != low.end()) {\n            low.erase(lowIt);\n        } else {\n            auto highIt = high.find(num);\n            if (highIt != high.end()) {\n                high.erase(highIt);\n            }\n        }\n        rebalance();\n    }\n\n    double currentMedian() const {\n        if (windowSize % splitFactor == oddRemainder) {\n            return static_cast<double>(*low.rbegin());\n        }\n        double left = static_cast<double>(*low.rbegin());\n        double right = static_cast<double>(*high.begin());\n        return (left + right) / splitFactor;\n    }\n\n    void rebalance() {\n        while (low.size() > high.size() + balanceLimit) {\n            auto it = prev(low.end());\n            high.insert(*it);\n            low.erase(it);\n        }\n        while (low.size() < high.size()) {\n            auto it = high.begin();\n            low.insert(*it);\n            high.erase(it);\n        }\n    }\n};"
