      "code": "class Solution {\npublic:\n    long long maxRunTime(int n, vector<int>& batteries) {\n        long long totalPower = 0;\n        for (int capacity : batteries) {\n            totalPower += capacity;\n        }\n\n        long long low = initialMinutes;\n        long long high = totalPower / n;\n        while (low < high) {\n            long long mid = low + (high - low + oneMinute) / splitFactor;\n            if (canRunFor(n, batteries, mid)) {\n                low = mid;\n            } else {\n                high = mid - oneMinute;\n            }\n        }\n\n        return low;\n    }\n\nprivate:\n    static constexpr long long initialMinutes = 0;\n    static constexpr long long oneMinute = 1;\n    static constexpr long long splitFactor = 2;\n\n    bool canRunFor(\n        int computers,\n        const vector<int>& batteries,\n        long long minutes\n    ) const {\n        long long requiredPower = minutes * computers;\n        long long availablePower = 0;\n\n        for (int capacity : batteries) {\n            availablePower += min(static_cast<long long>(capacity), minutes);\n            if (availablePower >= requiredPower) {\n                return true;\n            }\n        }\n\n        return false;\n    }\n};"
