      "code": "class Solution {\npublic:\n    int wiggleMaxLength(vector<int>& nums) {\n        if (nums.empty()) {\n            return 0;\n        }\n\n        int length = 1;\n        int previousDirection = flatDirection;\n\n        for (int i = 1; i < nums.size(); ++i) {\n            int currentDirection = directionOf(nums[i - 1], nums[i]);\n            if (currentDirection == flatDirection) {\n                continue;\n            }\n\n            if (previousDirection == flatDirection ||\n                currentDirection != previousDirection) {\n                ++length;\n                previousDirection = currentDirection;\n            }\n        }\n\n        return length;\n    }\n\nprivate:\n    static constexpr int flatDirection = 0;\n    static constexpr int risingDirection = 1;\n    static constexpr int fallingDirection = -1;\n\n    int directionOf(int previous, int current) {\n        if (current > previous) {\n            return risingDirection;\n        }\n        if (current < previous) {\n            return fallingDirection;\n        }\n        return flatDirection;\n    }\n};"
