      "code": "class Solution {\npublic:\n    int atMostNGivenDigitSet(vector<string>& digits, int n) {\n        string target = to_string(n);\n        int length = target.size();\n        int digitsCount = digits.size();\n        int answer = 0;\n\n        int currentPower = 1;\n        for (int len = 1; len < length; ++len) {\n            currentPower *= digitsCount;\n            answer += currentPower;\n        }\n\n        int suffixChoices = currentPower;\n        for (int pos = 0; pos < length; ++pos) {\n            int smaller = 0;\n            bool equal = false;\n\n            for (const string& digit : digits) {\n                if (digit[0] < target[pos]) {\n                    ++smaller;\n                } else if (digit[0] == target[pos]) {\n                    equal = true;\n                }\n            }\n\n            answer += smaller * suffixChoices;\n            if (!equal) {\n                return answer;\n            }\n            suffixChoices /= digitsCount;\n        }\n\n        return answer + 1;\n    }\n};"
