      "code": "class Solution {\npublic:\n    int numSubarrayProductLessThanK(vector<int>& nums, int k) {\n        if (k <= 1) {\n            return 0;\n        }\n\n        int n = nums.size();\n        vector<long double> prefix(n + 1, 0.0L);\n        for (int i = 0; i < n; ++i) {\n            prefix[i + 1] =\n                prefix[i] + log(static_cast<long double>(nums[i]));\n        }\n\n        const long double epsilon = 1e-12L;\n        long double logLimit = log(static_cast<long double>(k));\n        int answer = 0;\n\n        for (int left = 0; left < n; ++left) {\n            long double target = prefix[left] + logLimit - epsilon;\n            auto firstTooLarge = lower_bound(\n                prefix.begin() + left + 1,\n                prefix.end(),\n                target\n            );\n            answer += static_cast<int>(\n                firstTooLarge - (prefix.begin() + left + 1)\n            );\n        }\n\n        return answer;\n    }\n};"
