      "code": "class Solution {\npublic:\n    vector<int> productExceptSelf(vector<int>& nums) {\n        int n = nums.size();\n        vector<int> answer(n, 1);\n\n        int leftProduct = 1;\n        for (int i = 0; i < n; ++i) {\n            answer[i] = leftProduct;\n            leftProduct *= nums[i];\n        }\n\n        int rightProduct = 1;\n        for (int i = n - 1; i >= 0; --i) {\n            answer[i] *= rightProduct;\n            rightProduct *= nums[i];\n        }\n\n        return answer;\n    }\n};"
