      "code": "class Solution {\npublic:\n    bool hasPathSum(TreeNode* root, int targetSum) {\n        if (root == nullptr) {\n            return false;\n        }\n\n        vector<pair<TreeNode*, int>> pending;\n        pending.push_back({root, root->val});\n\n        while (!pending.empty()) {\n            auto [node, currentSum] = pending.back();\n            pending.pop_back();\n\n            if (isLeaf(node) && currentSum == targetSum) {\n                return true;\n            }\n            if (node->right != nullptr) {\n                pending.push_back({\n                    node->right,\n                    currentSum + node->right->val\n                });\n            }\n            if (node->left != nullptr) {\n                pending.push_back({\n                    node->left,\n                    currentSum + node->left->val\n                });\n            }\n        }\n\n        return false;\n    }\n\nprivate:\n    bool isLeaf(const TreeNode* node) {\n        return node->left == nullptr && node->right == nullptr;\n    }\n};"
