      "code": "class Solution {\npublic:\n    bool judgePoint24(vector<int>& cards) {\n        vector<Node> nodes;\n        nodes.reserve(cards.size());\n        for (int card : cards) {\n            nodes.push_back({static_cast<double>(card), to_string(card)});\n        }\n\n        answerExpression.clear();\n        return search(nodes);\n    }\n\nprivate:\n    struct Node {\n        double value;\n        string expression;\n    };\n\n    static constexpr int singleValueCount = 1;\n    static constexpr int expressionExtraChars = 5;\n    static constexpr double targetValue = 24.0;\n    static constexpr double zeroValue = 0.0;\n    static constexpr double eps = 1e-6;\n    static constexpr char leftParen = '(';\n    static constexpr char rightParen = ')';\n    static constexpr char spaceChar = ' ';\n    static constexpr char plusOperator = '+';\n    static constexpr char minusOperator = '-';\n    static constexpr char multiplyOperator = '*';\n    static constexpr char divideOperator = '/';\n\n    string answerExpression;\n\n    bool search(vector<Node>& nodes) {\n        int count = static_cast<int>(nodes.size());\n        if (count == singleValueCount) {\n            if (!closeTo(nodes[0].value, targetValue)) {\n                return false;\n            }\n            answerExpression = nodes[0].expression;\n            return true;\n        }\n\n        for (int first = 0; first < count; ++first) {\n            for (int second = first + 1; second < count; ++second) {\n                vector<Node> rest;\n                rest.reserve(count - 1);\n\n                for (int index = 0; index < count; ++index) {\n                    if (index != first && index != second) {\n                        rest.push_back(nodes[index]);\n                    }\n                }\n\n                const Node& left = nodes[first];\n                const Node& right = nodes[second];\n                if (tryNode(rest, left.value + right.value,\n                            buildExpression(left.expression, plusOperator,\n                                            right.expression)) ||\n                    tryNode(rest, left.value * right.value,\n                            buildExpression(left.expression, multiplyOperator,\n                                            right.expression)) ||\n                    tryNode(rest, left.value - right.value,\n                            buildExpression(left.expression, minusOperator,\n                                            right.expression)) ||\n                    tryNode(rest, right.value - left.value,\n                            buildExpression(right.expression, minusOperator,\n                                            left.expression))) {\n                    return true;\n                }\n                if (!closeTo(right.value, zeroValue) &&\n                    tryNode(rest, left.value / right.value,\n                            buildExpression(left.expression, divideOperator,\n                                            right.expression))) {\n                    return true;\n                }\n                if (!closeTo(left.value, zeroValue) &&\n                    tryNode(rest, right.value / left.value,\n                            buildExpression(right.expression, divideOperator,\n                                            left.expression))) {\n                    return true;\n                }\n            }\n        }\n\n        return false;\n    }\n\n    bool tryNode(\n        vector<Node>& rest,\n        double value,\n        string expression\n    ) {\n        rest.push_back({value, move(expression)});\n        bool found = search(rest);\n        rest.pop_back();\n        return found;\n    }\n\n    string buildExpression(\n        const string& left,\n        char operation,\n        const string& right\n    ) {\n        string expression;\n        expression.reserve(left.size() + right.size() + expressionExtraChars);\n        expression.push_back(leftParen);\n        expression += left;\n        expression.push_back(spaceChar);\n        expression.push_back(operation);\n        expression.push_back(spaceChar);\n        expression += right;\n        expression.push_back(rightParen);\n        return expression;\n    }\n\n    bool closeTo(double left, double right) {\n        return fabs(left - right) < eps;\n    }\n};"
