      "code": "class Solution {\npublic:\n    vector<string> binaryTreePaths(TreeNode* root) {\n        if (root == nullptr) {\n            return {};\n        }\n\n        vector<string> answer;\n        stack<pair<TreeNode*, string>> pending;\n        pending.push({root, to_string(root->val)});\n\n        while (!pending.empty()) {\n            auto [node, path] = pending.top();\n            pending.pop();\n\n            if (isLeaf(node)) {\n                answer.push_back(path);\n                continue;\n            }\n\n            if (node->right != nullptr) {\n                pending.push({\n                    node->right,\n                    extendPath(path, node->right->val)\n                });\n            }\n            if (node->left != nullptr) {\n                pending.push({\n                    node->left,\n                    extendPath(path, node->left->val)\n                });\n            }\n        }\n\n        return answer;\n    }\n\nprivate:\n    static constexpr char separatorLeft = '-';\n    static constexpr char separatorRight = '>';\n\n    bool isLeaf(const TreeNode* node) {\n        return node->left == nullptr && node->right == nullptr;\n    }\n\n    string extendPath(const string& path, int value) {\n        string nextPath = path;\n        nextPath.push_back(separatorLeft);\n        nextPath.push_back(separatorRight);\n        nextPath += to_string(value);\n        return nextPath;\n    }\n};"
