      "code": "class Solution {\npublic:\n    int reversePairs(vector<int>& record) {\n        int n = static_cast<int>(record.size());\n        if (n < minPairLength) {\n            return 0;\n        }\n\n        vector<int> sortedValues = record;\n        sort(sortedValues.begin(), sortedValues.end());\n        sortedValues.erase(\n            unique(sortedValues.begin(), sortedValues.end()),\n            sortedValues.end()\n        );\n\n        FenwickTree tree(static_cast<int>(sortedValues.size()));\n        long long pairCount = 0;\n        for (int index = n - 1; index >= 0; --index) {\n            int rank = rankOf(sortedValues, record[index]);\n            pairCount += tree.query(rank - 1);\n            tree.add(rank, singleOccurrence);\n        }\n\n        return static_cast<int>(pairCount);\n    }\n\nprivate:\n    static constexpr int minPairLength = 2;\n    static constexpr int firstRank = 1;\n    static constexpr int singleOccurrence = 1;\n\n    class FenwickTree {\n    public:\n        explicit FenwickTree(int size) : counts(size + 1, 0) {}\n\n        void add(int index, int delta) {\n            int treeSize = static_cast<int>(counts.size());\n            for (int i = index; i < treeSize; i += lowbit(i)) {\n                counts[i] += delta;\n            }\n        }\n\n        int query(int index) const {\n            int total = 0;\n            for (int i = index; i > 0; i -= lowbit(i)) {\n                total += counts[i];\n            }\n            return total;\n        }\n\n    private:\n        vector<int> counts;\n\n        static int lowbit(int value) {\n            return value & -value;\n        }\n    };\n\n    int rankOf(const vector<int>& sortedValues, int value) {\n        auto it = lower_bound(\n            sortedValues.begin(),\n            sortedValues.end(),\n            value\n        );\n        return static_cast<int>(it - sortedValues.begin()) + firstRank;\n    }\n};"
