      "code": "class Solution {\npublic:\n    vector<string> restoreIpAddresses(string s) {\n        int n = static_cast<int>(s.size());\n        vector<string> answer;\n        if (n < minTotalLength || n > maxTotalLength) {\n            return answer;\n        }\n\n        vector<string> path;\n        dfs(s, 0, path, answer);\n        return answer;\n    }\n\nprivate:\n    static constexpr int segmentCount = 4;\n    static constexpr int minSegmentLength = 1;\n    static constexpr int maxSegmentLength = 3;\n    static constexpr int maxSegmentValue = 255;\n    static constexpr int digitBase = 10;\n    static constexpr int minTotalLength = segmentCount * minSegmentLength;\n    static constexpr int maxTotalLength = segmentCount * maxSegmentLength;\n    static constexpr char zeroDigit = '0';\n    static constexpr char minDigit = '0';\n    static constexpr char maxDigit = '9';\n    static constexpr char segmentSeparator = '.';\n\n    void dfs(\n        const string& s,\n        int index,\n        vector<string>& path,\n        vector<string>& answer\n    ) {\n        int n = static_cast<int>(s.size());\n        int usedSegments = static_cast<int>(path.size());\n        int remainingSegments = segmentCount - usedSegments;\n        int remainingChars = n - index;\n\n        if (remainingChars < remainingSegments * minSegmentLength ||\n            remainingChars > remainingSegments * maxSegmentLength) {\n            return;\n        }\n\n        if (usedSegments == segmentCount) {\n            answer.push_back(buildAddress(path));\n            return;\n        }\n\n        int value = 0;\n        for (int length = minSegmentLength;\n             length <= maxSegmentLength && index + length <= n;\n             ++length) {\n            char current = s[index + length - 1];\n            if (current < minDigit || current > maxDigit) {\n                break;\n            }\n            if (length > minSegmentLength && s[index] == zeroDigit) {\n                break;\n            }\n\n            value = value * digitBase + (current - minDigit);\n            if (value > maxSegmentValue) {\n                break;\n            }\n\n            path.push_back(s.substr(index, length));\n            dfs(s, index + length, path, answer);\n            path.pop_back();\n        }\n    }\n\n    string buildAddress(const vector<string>& path) {\n        string address;\n        for (int i = 0; i < static_cast<int>(path.size()); ++i) {\n            if (i > 0) {\n                address += segmentSeparator;\n            }\n            address += path[i];\n        }\n        return address;\n    }\n};"
