      "code": "class Solution {\npublic:\n    bool canMakeArithmeticProgression(vector<int>& arr) {\n        int n = static_cast<int>(arr.size());\n        if (n <= minRequiredLength) {\n            return true;\n        }\n\n        auto minMax = minmax_element(arr.begin(), arr.end());\n        long long minValue = *minMax.first;\n        long long maxValue = *minMax.second;\n        long long totalRange = maxValue - minValue;\n        int gapCount = n - 1;\n\n        if (totalRange == 0) {\n            return true;\n        }\n        if (totalRange % gapCount != 0) {\n            return false;\n        }\n\n        long long step = totalRange / gapCount;\n        vector<bool> used(n, false);\n        for (int value : arr) {\n            long long offset = static_cast<long long>(value) - minValue;\n            if (offset % step != 0) {\n                return false;\n            }\n\n            long long slot = offset / step;\n            if (slot < 0 || slot >= n) {\n                return false;\n            }\n            int index = static_cast<int>(slot);\n            if (used[index]) {\n                return false;\n            }\n            used[index] = true;\n        }\n\n        return true;\n    }\n\nprivate:\n    static constexpr int minRequiredLength = 2;\n};"
