      "code": "class Solution {\npublic:\n    int intersectionSizeTwo(vector<vector<int>>& intervals) {\n        sort(intervals.begin(), intervals.end(), compareInterval);\n\n        vector<int> chosen;\n        chosen.reserve(intervals.size() * requiredPoints);\n\n        for (const vector<int>& interval : intervals) {\n            int start = interval[startIndex];\n            int end = interval[endIndex];\n            int covered = countCovered(chosen, start);\n            int missing = requiredPoints - covered;\n\n            for (int point = end - missing + firstAddedOffset;\n                 point <= end;\n                 ++point) {\n                chosen.push_back(point);\n            }\n        }\n\n        return static_cast<int>(chosen.size());\n    }\n\nprivate:\n    static bool compareInterval(\n        const vector<int>& left,\n        const vector<int>& right\n    ) {\n        if (left[endIndex] != right[endIndex]) {\n            return left[endIndex] < right[endIndex];\n        }\n        return left[startIndex] > right[startIndex];\n    }\n\n    int countCovered(const vector<int>& chosen, int start) const {\n        int count = noCoveredPoint;\n        for (int i = static_cast<int>(chosen.size()) - lastOffset;\n             i >= firstIndex && chosen[i] >= start;\n             --i) {\n            ++count;\n            if (count == requiredPoints) {\n                break;\n            }\n        }\n        return count;\n    }\n\n    static constexpr int startIndex = 0;\n    static constexpr int endIndex = 1;\n    static constexpr int noCoveredPoint = 0;\n    static constexpr int requiredPoints = 2;\n    static constexpr int firstAddedOffset = 1;\n    static constexpr int firstIndex = 0;\n    static constexpr int lastOffset = 1;\n};"
