      "code": "class Solution {\npublic:\n    int longestIncreasingPath(vector<vector<int>>& matrix) {\n        if (matrix.empty() || matrix[0].empty()) {\n            return 0;\n        }\n\n        int rows = static_cast<int>(matrix.size());\n        int cols = static_cast<int>(matrix[0].size());\n        vector<vector<int>> memo(rows, vector<int>(cols, 0));\n        int best = 0;\n\n        for (int row = 0; row < rows; ++row) {\n            for (int col = 0; col < cols; ++col) {\n                best = max(best, dfs(matrix, memo, row, col));\n            }\n        }\n\n        return best;\n    }\n\nprivate:\n    static constexpr int directionCount = 4;\n\n    int dfs(\n        const vector<vector<int>>& matrix,\n        vector<vector<int>>& memo,\n        int row,\n        int col\n    ) {\n        if (memo[row][col] != 0) {\n            return memo[row][col];\n        }\n\n        static constexpr int rowDelta[directionCount] = {1, -1, 0, 0};\n        static constexpr int colDelta[directionCount] = {0, 0, 1, -1};\n        int rows = static_cast<int>(matrix.size());\n        int cols = static_cast<int>(matrix[0].size());\n        int best = 1;\n\n        for (int direction = 0; direction < directionCount; ++direction) {\n            int nextRow = row + rowDelta[direction];\n            int nextCol = col + colDelta[direction];\n            if (nextRow < 0 || nextRow >= rows ||\n                nextCol < 0 || nextCol >= cols) {\n                continue;\n            }\n            if (matrix[nextRow][nextCol] <= matrix[row][col]) {\n                continue;\n            }\n\n            best = max(best, 1 + dfs(matrix, memo, nextRow, nextCol));\n        }\n\n        memo[row][col] = best;\n        return best;\n    }\n};"
