      "code": "class Solution {\npublic:\n    int longestIncreasingPath(vector<vector<int>>& matrix) {\n        if (matrix.empty() || matrix[0].empty()) {\n            return 0;\n        }\n\n        int rows = static_cast<int>(matrix.size());\n        int cols = static_cast<int>(matrix[0].size());\n        vector<vector<int>> outDegree(rows, vector<int>(cols, 0));\n        queue<pair<int, int>> peaks;\n\n        for (int row = 0; row < rows; ++row) {\n            for (int col = 0; col < cols; ++col) {\n                outDegree[row][col] = countGreaterNeighbors(\n                    matrix,\n                    row,\n                    col\n                );\n                if (outDegree[row][col] == 0) {\n                    peaks.push({row, col});\n                }\n            }\n        }\n\n        int layers = 0;\n        while (!peaks.empty()) {\n            int layerSize = static_cast<int>(peaks.size());\n            ++layers;\n\n            for (int i = 0; i < layerSize; ++i) {\n                pair<int, int> cell = peaks.front();\n                peaks.pop();\n                int row = cell.first;\n                int col = cell.second;\n                pushSmallerNeighbors(\n                    matrix,\n                    outDegree,\n                    row,\n                    col,\n                    peaks\n                );\n            }\n        }\n\n        return layers;\n    }\n\nprivate:\n    static constexpr int directionCount = 4;\n\n    int countGreaterNeighbors(\n        const vector<vector<int>>& matrix,\n        int row,\n        int col\n    ) {\n        static constexpr int rowDelta[directionCount] = {1, -1, 0, 0};\n        static constexpr int colDelta[directionCount] = {0, 0, 1, -1};\n        int rows = static_cast<int>(matrix.size());\n        int cols = static_cast<int>(matrix[0].size());\n        int count = 0;\n\n        for (int direction = 0; direction < directionCount; ++direction) {\n            int nextRow = row + rowDelta[direction];\n            int nextCol = col + colDelta[direction];\n            if (nextRow < 0 || nextRow >= rows ||\n                nextCol < 0 || nextCol >= cols) {\n                continue;\n            }\n            if (matrix[nextRow][nextCol] > matrix[row][col]) {\n                ++count;\n            }\n        }\n\n        return count;\n    }\n\n    void pushSmallerNeighbors(\n        const vector<vector<int>>& matrix,\n        vector<vector<int>>& outDegree,\n        int row,\n        int col,\n        queue<pair<int, int>>& peaks\n    ) {\n        static constexpr int rowDelta[directionCount] = {1, -1, 0, 0};\n        static constexpr int colDelta[directionCount] = {0, 0, 1, -1};\n        int rows = static_cast<int>(matrix.size());\n        int cols = static_cast<int>(matrix[0].size());\n\n        for (int direction = 0; direction < directionCount; ++direction) {\n            int nextRow = row + rowDelta[direction];\n            int nextCol = col + colDelta[direction];\n            if (nextRow < 0 || nextRow >= rows ||\n                nextCol < 0 || nextCol >= cols) {\n                continue;\n            }\n            if (matrix[nextRow][nextCol] >= matrix[row][col]) {\n                continue;\n            }\n\n            --outDegree[nextRow][nextCol];\n            if (outDegree[nextRow][nextCol] == 0) {\n                peaks.push({nextRow, nextCol});\n            }\n        }\n    }\n};"
