      "code": "class Solution {\npublic:\n    void gameOfLife(vector<vector<int>>& board) {\n        if (board.empty() || board[0].empty()) {\n            return;\n        }\n\n        int rows = static_cast<int>(board.size());\n        int cols = static_cast<int>(board[0].size());\n\n        for (int row = 0; row < rows; ++row) {\n            for (int col = 0; col < cols; ++col) {\n                int liveNeighbors = countLiveNeighbors(board, row, col);\n\n                if (board[row][col] == liveCell) {\n                    bool shouldDie = liveNeighbors < liveMinNeighbors ||\n                        liveNeighbors > liveMaxNeighbors;\n                    if (shouldDie) {\n                        board[row][col] = liveToDead;\n                    }\n                } else if (liveNeighbors == reproduceNeighbors) {\n                    board[row][col] = deadToLive;\n                }\n            }\n        }\n\n        for (int row = 0; row < rows; ++row) {\n            for (int col = 0; col < cols; ++col) {\n                if (board[row][col] == liveToDead) {\n                    board[row][col] = deadCell;\n                } else if (board[row][col] == deadToLive) {\n                    board[row][col] = liveCell;\n                }\n            }\n        }\n    }\n\nprivate:\n    static constexpr int deadCell = 0;\n    static constexpr int liveCell = 1;\n    static constexpr int liveToDead = 2;\n    static constexpr int deadToLive = 3;\n    static constexpr int liveMinNeighbors = 2;\n    static constexpr int liveMaxNeighbors = 3;\n    static constexpr int reproduceNeighbors = 3;\n    static constexpr int directionCount = 8;\n\n    int countLiveNeighbors(\n        const vector<vector<int>>& board,\n        int row,\n        int col\n    ) {\n        static constexpr int rowDelta[directionCount] = {\n            -1, -1, -1, 0, 0, 1, 1, 1\n        };\n        static constexpr int colDelta[directionCount] = {\n            -1, 0, 1, -1, 1, -1, 0, 1\n        };\n        int rows = static_cast<int>(board.size());\n        int cols = static_cast<int>(board[0].size());\n        int liveNeighbors = 0;\n\n        for (int direction = 0; direction < directionCount; ++direction) {\n            int nextRow = row + rowDelta[direction];\n            int nextCol = col + colDelta[direction];\n\n            if (nextRow < 0 || nextRow >= rows ||\n                nextCol < 0 || nextCol >= cols) {\n                continue;\n            }\n            if (isOriginallyLive(board[nextRow][nextCol])) {\n                ++liveNeighbors;\n            }\n        }\n\n        return liveNeighbors;\n    }\n\n    bool isOriginallyLive(int state) {\n        return state == liveCell || state == liveToDead;\n    }\n};"
