      "code": "class Solution {\npublic:\n    bool exist(vector<vector<char>>& board, string word) {\n        if (board.empty() || board[0].empty()) {\n            return false;\n        }\n\n        int rows = static_cast<int>(board.size());\n        int cols = static_cast<int>(board[0].size());\n        int wordLength = static_cast<int>(word.size());\n        if (wordLength > rows * cols) {\n            return false;\n        }\n\n        for (int row = 0; row < rows; ++row) {\n            for (int col = 0; col < cols; ++col) {\n                if (board[row][col] == word[0] &&\n                    dfs(board, word, row, col, 0)) {\n                    return true;\n                }\n            }\n        }\n\n        return false;\n    }\n\nprivate:\n    static constexpr char visitedCell = '#';\n    static constexpr int directionCount = 4;\n\n    bool dfs(\n        vector<vector<char>>& board,\n        const string& word,\n        int row,\n        int col,\n        int index\n    ) {\n        int rows = static_cast<int>(board.size());\n        int cols = static_cast<int>(board[0].size());\n        if (row < 0 || row >= rows || col < 0 || col >= cols) {\n            return false;\n        }\n        if (board[row][col] == visitedCell ||\n            board[row][col] != word[index]) {\n            return false;\n        }\n\n        int lastIndex = static_cast<int>(word.size()) - 1;\n        if (index == lastIndex) {\n            return true;\n        }\n\n        char original = board[row][col];\n        board[row][col] = visitedCell;\n\n        static constexpr int rowDelta[directionCount] = {1, -1, 0, 0};\n        static constexpr int colDelta[directionCount] = {0, 0, 1, -1};\n        for (int direction = 0; direction < directionCount; ++direction) {\n            int nextRow = row + rowDelta[direction];\n            int nextCol = col + colDelta[direction];\n            if (dfs(board, word, nextRow, nextCol, index + 1)) {\n                board[row][col] = original;\n                return true;\n            }\n        }\n\n        board[row][col] = original;\n        return false;\n    }\n};"
