      "code": "class Solution {\nprivate:\n    static constexpr int alphabetSize = 26;\n    static constexpr int directionCount = 4;\n    static constexpr char firstLetter = 'a';\n    static constexpr char visitedCell = '#';\n\n    struct TrieNode {\n        array<TrieNode*, alphabetSize> children{};\n        string word;\n    };\n\npublic:\n    vector<string> findWords(\n        vector<vector<char>>& board,\n        vector<string>& words\n    ) {\n        if (board.empty() || board[0].empty() || words.empty()) {\n            return {};\n        }\n\n        storage.clear();\n        TrieNode* root = createNode();\n        for (const string& word : words) {\n            insert(root, word);\n        }\n\n        vector<string> answer;\n        int rows = static_cast<int>(board.size());\n        int cols = static_cast<int>(board[0].size());\n        for (int row = 0; row < rows; ++row) {\n            for (int col = 0; col < cols; ++col) {\n                dfs(board, row, col, root, answer);\n            }\n        }\n\n        return answer;\n    }\n\nprivate:\n    vector<unique_ptr<TrieNode>> storage;\n\n    TrieNode* createNode() {\n        storage.push_back(make_unique<TrieNode>());\n        return storage.back().get();\n    }\n\n    void insert(TrieNode* root, const string& word) {\n        TrieNode* node = root;\n        for (char ch : word) {\n            int letter = ch - firstLetter;\n            if (node->children[letter] == nullptr) {\n                node->children[letter] = createNode();\n            }\n            node = node->children[letter];\n        }\n        node->word = word;\n    }\n\n    void dfs(\n        vector<vector<char>>& board,\n        int row,\n        int col,\n        TrieNode* node,\n        vector<string>& answer\n    ) {\n        int rows = static_cast<int>(board.size());\n        int cols = static_cast<int>(board[0].size());\n        if (row < 0 || row >= rows || col < 0 || col >= cols) {\n            return;\n        }\n\n        char ch = board[row][col];\n        if (ch == visitedCell) {\n            return;\n        }\n\n        TrieNode* next = node->children[ch - firstLetter];\n        if (next == nullptr) {\n            return;\n        }\n\n        if (!next->word.empty()) {\n            answer.push_back(next->word);\n            next->word.clear();\n        }\n\n        board[row][col] = visitedCell;\n        static constexpr int rowDelta[directionCount] = {1, -1, 0, 0};\n        static constexpr int colDelta[directionCount] = {0, 0, 1, -1};\n        for (int direction = 0; direction < directionCount; ++direction) {\n            dfs(\n                board,\n                row + rowDelta[direction],\n                col + colDelta[direction],\n                next,\n                answer\n            );\n        }\n        board[row][col] = ch;\n    }\n};"
