      "code": "class Solution {\npublic:\n    int widthOfBinaryTree(TreeNode* root) {\n        if (root == nullptr) {\n            return 0;\n        }\n\n        using Index = unsigned long long;\n        queue<pair<TreeNode*, Index>> nodes;\n        nodes.push({root, 0});\n        Index bestWidth = 0;\n\n        while (!nodes.empty()) {\n            int levelSize = static_cast<int>(nodes.size());\n            Index base = nodes.front().second;\n            Index firstIndex = 0;\n            Index lastIndex = 0;\n\n            for (int i = 0; i < levelSize; ++i) {\n                auto [node, rawIndex] = nodes.front();\n                nodes.pop();\n\n                Index index = rawIndex - base;\n                if (i == 0) {\n                    firstIndex = index;\n                }\n                if (i == levelSize - 1) {\n                    lastIndex = index;\n                }\n\n                if (node->left != nullptr) {\n                    nodes.push({node->left, index * 2});\n                }\n                if (node->right != nullptr) {\n                    nodes.push({node->right, index * 2 + 1});\n                }\n            }\n\n            bestWidth = max(bestWidth, lastIndex - firstIndex + 1);\n        }\n\n        return static_cast<int>(bestWidth);\n    }\n};"
