      "sourceUrl": "https://leetcode.cn/problems/valid-number/description/",
      "code": "class Solution {\npublic:\n    bool isNumber(string s) {\n        bool seenDigit = false;\n        bool seenDot = false;\n        bool seenExponent = false;\n        bool digitAfterExponent = true;\n        int n = s.size();\n\n        for (int i = 0; i < n; ++i) {\n            char ch = s[i];\n\n            if (isDigit(ch)) {\n                seenDigit = true;\n                if (seenExponent) {\n                    digitAfterExponent = true;\n                }\n                continue;\n            }\n\n            if (ch == plusChar || ch == minusChar) {\n                bool atBeginning = i == 0;\n                bool afterExponent = i > 0 && isExponent(s[i - 1]);\n                if (!atBeginning && !afterExponent) {\n                    return false;\n                }\n                continue;\n            }\n\n            if (ch == dotChar) {\n                if (seenDot || seenExponent) {\n                    return false;\n                }\n                seenDot = true;\n                continue;\n            }\n\n            if (isExponent(ch)) {\n                // The base must already contain at least one digit.\n                if (seenExponent || !seenDigit) {\n                    return false;\n                }\n                seenExponent = true;\n\n                // The exponent starts a new integer requirement.\n                digitAfterExponent = false;\n                continue;\n            }\n\n            return false;\n        }\n\n        return seenDigit && digitAfterExponent;\n    }\n\nprivate:\n    static constexpr char zeroChar = '0';\n    static constexpr char nineChar = '9';\n    static constexpr char plusChar = '+';\n    static constexpr char minusChar = '-';\n    static constexpr char dotChar = '.';\n    static constexpr char lowerExponentChar = 'e';\n    static constexpr char upperExponentChar = 'E';\n\n    bool isDigit(char ch) {\n        return ch >= zeroChar && ch <= nineChar;\n    }\n\n    bool isExponent(char ch) {\n        return ch == lowerExponentChar || ch == upperExponentChar;\n    }\n};"
