      "code": "class Solution {\npublic:\n    vector<int> plusOne(vector<int>& digits) {\n        return addNonNegativeValue(digits, incrementValue);\n    }\n\nprivate:\n    static constexpr int decimalBase = 10;\n    static constexpr int incrementValue = 1;\n\n    vector<int> addNonNegativeValue(vector<int> digits, int value) {\n        int carry = value;\n\n        for (int i = static_cast<int>(digits.size()) - 1;\n             i >= 0 && carry > 0;\n             --i) {\n            int sum = digits[i] + carry;\n            digits[i] = sum % decimalBase;\n            carry = sum / decimalBase;\n        }\n\n        if (carry == 0) {\n            return digits;\n        }\n\n        vector<int> prefix;\n        while (carry > 0) {\n            prefix.push_back(carry % decimalBase);\n            carry /= decimalBase;\n        }\n        reverse(prefix.begin(), prefix.end());\n\n        prefix.insert(prefix.end(), digits.begin(), digits.end());\n        return prefix;\n    }\n};"
