      "code": "class Solution {\npublic:\n    bool repeatedSubstringPattern(string s) {\n        int n = s.size();\n        if (n < minimumRepeatCount) {\n            return false;\n        }\n\n        for (int period = 1; period <= n / minimumRepeatCount; ++period) {\n            if (n % period != 0) {\n                continue;\n            }\n            if (matchesPeriod(s, period)) {\n                return true;\n            }\n        }\n\n        return false;\n    }\n\nprivate:\n    static constexpr int minimumRepeatCount = 2;\n\n    bool matchesPeriod(const string& s, int period) {\n        int n = s.size();\n        for (int i = period; i < n; ++i) {\n            if (s[i] != s[i % period]) {\n                return false;\n            }\n        }\n        return true;\n    }\n};"
