      "code": "class Solution {\npublic:\n    string addBinary(string a, string b) {\n        string answer;\n        answer.reserve(max(a.size(), b.size()) + 1);\n\n        int i = a.size() - 1;\n        int j = b.size() - 1;\n        int carry = 0;\n\n        while (i >= 0 || j >= 0 || carry > 0) {\n            int sum = carry;\n            if (i >= 0) {\n                sum += a[i] - zeroChar;\n                --i;\n            }\n            if (j >= 0) {\n                sum += b[j] - zeroChar;\n                --j;\n            }\n\n            int digit = sum % binaryBase;\n            answer.push_back(static_cast<char>(zeroChar + digit));\n            carry = sum / binaryBase;\n        }\n\n        reverse(answer.begin(), answer.end());\n        return trimLeadingZeros(answer);\n    }\n\nprivate:\n    static constexpr int binaryBase = 2;\n    static constexpr char zeroChar = '0';\n\n    string trimLeadingZeros(const string& value) {\n        size_t firstDigit = 0;\n        while (firstDigit + 1 < value.size() &&\n               value[firstDigit] == zeroChar) {\n            ++firstDigit;\n        }\n        return value.substr(firstDigit);\n    }\n};"
