      "code": "class Solution {\npublic:\n    int change(int amount, vector<int>& coins) {\n        int coinCount = static_cast<int>(coins.size());\n        vector<vector<int>> dp(\n            coinCount + 1,\n            vector<int>(amount + 1, 0)\n        );\n\n        for (int usedTypes = 0; usedTypes <= coinCount; ++usedTypes) {\n            dp[usedTypes][0] = 1;\n        }\n\n        for (int usedTypes = 1; usedTypes <= coinCount; ++usedTypes) {\n            int coin = coins[usedTypes - 1];\n            for (int currentAmount = 1; currentAmount <= amount;\n                 ++currentAmount) {\n                dp[usedTypes][currentAmount] =\n                    dp[usedTypes - 1][currentAmount];\n\n                if (currentAmount >= coin) {\n                    dp[usedTypes][currentAmount] +=\n                        dp[usedTypes][currentAmount - coin];\n                }\n            }\n        }\n\n        return dp[coinCount][amount];\n    }\n};"
