      "code": "class Solution {\npublic:\n    int maxPathSum(TreeNode* root) {\n        best = root->val;\n        gain(root);\n        return best;\n    }\n\nprivate:\n    int best = 0;\n\n    int gain(TreeNode* node) {\n        if (node == nullptr) {\n            return 0;\n        }\n\n        int leftGain = max(0, gain(node->left));\n        int rightGain = max(0, gain(node->right));\n        best = max(best, node->val + leftGain + rightGain);\n\n        return node->val + max(leftGain, rightGain);\n    }\n};"
