      "code": "/**\n * Definition for a binary tree node.\n * struct TreeNode {\n *     int val;\n *     TreeNode *left;\n *     TreeNode *right;\n *     TreeNode(int x) : val(x), left(NULL), right(NULL) {}\n * };\n */\nclass Codec {\npublic:\n    string serialize(TreeNode* root) {\n        if (root == nullptr) {\n            return nullToken;\n        }\n\n        vector<string> tokens;\n        queue<TreeNode*> nodes;\n        nodes.push(root);\n\n        while (!nodes.empty()) {\n            TreeNode* node = nodes.front();\n            nodes.pop();\n\n            if (node == nullptr) {\n                tokens.push_back(nullToken);\n                continue;\n            }\n\n            tokens.push_back(to_string(node->val));\n            nodes.push(node->left);\n            nodes.push(node->right);\n        }\n\n        return join(tokens);\n    }\n\n    TreeNode* deserialize(string data) {\n        if (data.empty() || data == nullToken) {\n            return nullptr;\n        }\n\n        vector<string> tokens = split(data);\n        if (tokens.empty() || tokens[0] == nullToken) {\n            return nullptr;\n        }\n\n        TreeNode* root = new TreeNode(stoi(tokens[0]));\n        queue<TreeNode*> parents;\n        parents.push(root);\n        int index = 1;\n\n        while (!parents.empty() && index < static_cast<int>(tokens.size())) {\n            TreeNode* parent = parents.front();\n            parents.pop();\n\n            if (index < static_cast<int>(tokens.size()) &&\n                tokens[index] != nullToken) {\n                parent->left = new TreeNode(stoi(tokens[index]));\n                parents.push(parent->left);\n            }\n            ++index;\n\n            if (index < static_cast<int>(tokens.size()) &&\n                tokens[index] != nullToken) {\n                parent->right = new TreeNode(stoi(tokens[index]));\n                parents.push(parent->right);\n            }\n            ++index;\n        }\n\n        return root;\n    }\n\nprivate:\n    static constexpr char delimiter = ',';\n    static constexpr const char* nullToken = \"#\";\n\n    string join(const vector<string>& tokens) {\n        string result;\n        for (int i = 0; i < static_cast<int>(tokens.size()); ++i) {\n            if (i > 0) {\n                result.push_back(delimiter);\n            }\n            result += tokens[i];\n        }\n        return result;\n    }\n\n    vector<string> split(const string& data) {\n        vector<string> tokens;\n        string token;\n        stringstream stream(data);\n\n        while (getline(stream, token, delimiter)) {\n            tokens.push_back(token);\n        }\n        return tokens;\n    }\n};\n\n// Your Codec object will be instantiated and called as such:\n// Codec ser, deser;\n// TreeNode* ans = deser.deserialize(ser.serialize(root));"
