      "code": "class Solution {\npublic:\n    int calculate(string s) {\n        vector<int> terms;\n        int number = 0;\n        char previousOperator = plusOperator;\n\n        for (int i = 0; i <= static_cast<int>(s.size()); ++i) {\n            char ch = i < static_cast<int>(s.size()) ? s[i] : plusOperator;\n\n            if (ch == spaceChar) {\n                continue;\n            }\n            if (isDigit(ch)) {\n                number = number * decimalBase + (ch - zeroDigit);\n                continue;\n            }\n\n            applyOperator(terms, previousOperator, number);\n            previousOperator = ch;\n            number = 0;\n        }\n\n        int result = 0;\n        for (int term : terms) {\n            result += term;\n        }\n        return result;\n    }\n\nprivate:\n    static constexpr int decimalBase = 10;\n    static constexpr char zeroDigit = '0';\n    static constexpr char nineDigit = '9';\n    static constexpr char spaceChar = ' ';\n    static constexpr char plusOperator = '+';\n    static constexpr char minusOperator = '-';\n    static constexpr char multiplyOperator = '*';\n    static constexpr char divideOperator = '/';\n\n    bool isDigit(char ch) const {\n        return ch >= zeroDigit && ch <= nineDigit;\n    }\n\n    void applyOperator(\n        vector<int>& terms,\n        char previousOperator,\n        int number\n    ) const {\n        if (previousOperator == plusOperator) {\n            terms.push_back(number);\n            return;\n        }\n        if (previousOperator == minusOperator) {\n            terms.push_back(-number);\n            return;\n        }\n\n        int lastTerm = terms.back();\n        terms.pop_back();\n        if (previousOperator == multiplyOperator) {\n            terms.push_back(lastTerm * number);\n        } else {\n            terms.push_back(lastTerm / number);\n        }\n    }\n};"
