      "code": "class Solution {\npublic:\n    int maxCoins(vector<int>& nums) {\n        int n = static_cast<int>(nums.size());\n        if (n == 0) {\n            return 0;\n        }\n\n        int total = n + sentinelCount;\n        vector<int> val(total, sentinelValue);\n        for (int i = 0; i < n; ++i) {\n            val[i + firstRealIndex] = nums[i];\n        }\n\n        vector<vector<int>> dp(total, vector<int>(total, 0));\n\n        for (int width = smallestNonEmptyWidth; width < total; ++width) {\n            for (int left = 0; left + width < total; ++left) {\n                int right = left + width;\n\n                for (int last = left + 1; last < right; ++last) {\n                    int gain = val[left] * val[last] * val[right];\n                    int candidate = dp[left][last] + gain + dp[last][right];\n                    dp[left][right] = max(dp[left][right], candidate);\n                }\n            }\n        }\n\n        return dp[0][total - 1];\n    }\n\nprivate:\n    static constexpr int sentinelValue = 1;\n    static constexpr int sentinelCount = 2;\n    static constexpr int firstRealIndex = 1;\n    static constexpr int smallestNonEmptyWidth = 2;\n};"
