      "code": "class Solution {\n    class FenwickTree {\n    public:\n        explicit FenwickTree(int size) : tree(size + 1, 0) {}\n\n        void add(int index, int delta) {\n            int treeSize = static_cast<int>(tree.size());\n            for (int i = index; i < treeSize; i += lowbit(i)) {\n                tree[i] += delta;\n            }\n        }\n\n        int sum(int index) const {\n            int total = 0;\n            for (int i = index; i > 0; i -= lowbit(i)) {\n                total += tree[i];\n            }\n            return total;\n        }\n\n    private:\n        vector<int> tree;\n\n        static int lowbit(int index) {\n            return index & -index;\n        }\n    };\n\npublic:\n    vector<int> countSmaller(vector<int>& nums) {\n        const int n = static_cast<int>(nums.size());\n        vector<int> answer(n, 0);\n        if (n == 0) {\n            return answer;\n        }\n\n        vector<int> values = nums;\n        sort(values.begin(), values.end());\n        values.erase(unique(values.begin(), values.end()), values.end());\n\n        FenwickTree tree(static_cast<int>(values.size()));\n        for (int i = n - 1; i >= 0; --i) {\n            int rank = lower_bound(values.begin(), values.end(), nums[i]) -\n                values.begin() + firstRank;\n\n            // Query only smaller ranks, so equal values are not counted.\n            answer[i] = tree.sum(rank - 1);\n            tree.add(rank, oneOccurrence);\n        }\n\n        return answer;\n    }\n\nprivate:\n    static constexpr int firstRank = 1;\n    static constexpr int oneOccurrence = 1;\n};"
