      "code": "class Solution {\npublic:\n    vector<string> removeInvalidParentheses(string s) {\n        vector<string> answer;\n        unordered_set<string> visited;\n        queue<string> pending;\n\n        visited.insert(s);\n        pending.push(s);\n        bool found = false;\n\n        while (!pending.empty() && !found) {\n            int levelSize = static_cast<int>(pending.size());\n            for (int step = 0; step < levelSize; ++step) {\n                string current = pending.front();\n                pending.pop();\n\n                if (isValid(current)) {\n                    answer.push_back(current);\n                    found = true;\n                    continue;\n                }\n                if (found) {\n                    continue;\n                }\n\n                int length = static_cast<int>(current.size());\n                for (int i = 0; i < length; ++i) {\n                    if (!isParenthesis(current[i])) {\n                        continue;\n                    }\n\n                    string next = current.substr(0, i) +\n                        current.substr(i + 1);\n                    if (visited.insert(next).second) {\n                        pending.push(next);\n                    }\n                }\n            }\n        }\n\n        return answer;\n    }\n\nprivate:\n    static constexpr char openParen = '(';\n    static constexpr char closeParen = ')';\n\n    bool isParenthesis(char ch) const {\n        return ch == openParen || ch == closeParen;\n    }\n\n    bool isValid(const string& text) const {\n        int balance = 0;\n        for (char ch : text) {\n            if (ch == openParen) {\n                ++balance;\n            } else if (ch == closeParen) {\n                if (balance == 0) {\n                    return false;\n                }\n                --balance;\n            }\n        }\n\n        return balance == 0;\n    }\n};"
