      "code": "class Solution {\npublic:\n    vector<string> removeInvalidParentheses(string s) {\n        int removeLeft = 0;\n        int removeRight = 0;\n        countRemovals(s, removeLeft, removeRight);\n\n        vector<string> answer;\n        unordered_set<string> seenAnswer;\n        string path;\n        path.reserve(s.size());\n\n        dfs(0, removeLeft, removeRight, 0, s, path, answer, seenAnswer);\n        return answer;\n    }\n\nprivate:\n    static constexpr char openParen = '(';\n    static constexpr char closeParen = ')';\n\n    void countRemovals(\n        const string& s,\n        int& removeLeft,\n        int& removeRight\n    ) const {\n        for (char ch : s) {\n            if (ch == openParen) {\n                ++removeLeft;\n            } else if (ch == closeParen) {\n                if (removeLeft > 0) {\n                    --removeLeft;\n                } else {\n                    ++removeRight;\n                }\n            }\n        }\n    }\n\n    void dfs(\n        int index,\n        int removeLeft,\n        int removeRight,\n        int balance,\n        const string& s,\n        string& path,\n        vector<string>& answer,\n        unordered_set<string>& seenAnswer\n    ) const {\n        int n = static_cast<int>(s.size());\n        if (removeLeft + removeRight > n - index) {\n            return;\n        }\n        if (index == n) {\n            bool complete = removeLeft == 0 && removeRight == 0 &&\n                balance == 0;\n            if (complete && seenAnswer.insert(path).second) {\n                answer.push_back(path);\n            }\n            return;\n        }\n\n        char ch = s[index];\n        if (ch == openParen) {\n            if (removeLeft > 0) {\n                dfs(\n                    index + 1,\n                    removeLeft - 1,\n                    removeRight,\n                    balance,\n                    s,\n                    path,\n                    answer,\n                    seenAnswer\n                );\n            }\n\n            path.push_back(ch);\n            dfs(\n                index + 1,\n                removeLeft,\n                removeRight,\n                balance + 1,\n                s,\n                path,\n                answer,\n                seenAnswer\n            );\n            path.pop_back();\n            return;\n        }\n\n        if (ch == closeParen) {\n            if (removeRight > 0) {\n                dfs(\n                    index + 1,\n                    removeLeft,\n                    removeRight - 1,\n                    balance,\n                    s,\n                    path,\n                    answer,\n                    seenAnswer\n                );\n            }\n\n            if (balance > 0) {\n                path.push_back(ch);\n                dfs(\n                    index + 1,\n                    removeLeft,\n                    removeRight,\n                    balance - 1,\n                    s,\n                    path,\n                    answer,\n                    seenAnswer\n                );\n                path.pop_back();\n            }\n            return;\n        }\n\n        path.push_back(ch);\n        dfs(\n            index + 1,\n            removeLeft,\n            removeRight,\n            balance,\n            s,\n            path,\n            answer,\n            seenAnswer\n        );\n        path.pop_back();\n    }\n};"
