      "code": "class Solution {\npublic:\n    string minWindow(string s, string t) {\n        if (t.empty() || s.empty()) {\n            return \"\";\n        }\n\n        unordered_map<char, int> need;\n        unordered_map<char, int> window;\n        for (char ch : t) {\n            ++need[ch];\n        }\n\n        int requiredKinds = need.size();\n        int satisfiedKinds = 0;\n        int left = 0;\n        int bestStart = 0;\n        int bestLength = numeric_limits<int>::max();\n\n        for (int right = 0; right < s.size(); ++right) {\n            char added = s[right];\n            if (need.count(added) > 0) {\n                ++window[added];\n                if (window[added] == need[added]) {\n                    ++satisfiedKinds;\n                }\n            }\n\n            while (satisfiedKinds == requiredKinds) {\n                int currentLength = right - left + 1;\n                if (currentLength < bestLength) {\n                    bestStart = left;\n                    bestLength = currentLength;\n                }\n\n                char removed = s[left];\n                if (need.count(removed) > 0) {\n                    if (window[removed] == need[removed]) {\n                        --satisfiedKinds;\n                    }\n                    --window[removed];\n                }\n                ++left;\n            }\n        }\n\n        if (bestLength == numeric_limits<int>::max()) {\n            return \"\";\n        }\n        return s.substr(bestStart, bestLength);\n    }\n};"
