      "code": "class Solution {\n    static constexpr int remainderKinds = 3;\n    static constexpr int unreachable = -1000000000;\n\npublic:\n    int maxSumDivThree(vector<int>& nums) {\n        int dp[remainderKinds] = {0, unreachable, unreachable};\n\n        for (int value : nums) {\n            int old[remainderKinds];\n            for (int remainder = 0; remainder < remainderKinds; ++remainder) {\n                old[remainder] = dp[remainder];\n            }\n\n            int valueRemainder = value % remainderKinds;\n            for (int remainder = 0; remainder < remainderKinds; ++remainder) {\n                if (old[remainder] == unreachable) {\n                    continue;\n                }\n\n                int nextRemainder =\n                    (remainder + valueRemainder) % remainderKinds;\n                dp[nextRemainder] =\n                    max(dp[nextRemainder], old[remainder] + value);\n            }\n        }\n\n        return dp[0];\n    }\n};"
