      "code": "class Solution {\n    static constexpr int divisor = 3;\n    static constexpr int removedSlots = 2;\n    static constexpr int unavailable = 1000000000;\n    static constexpr int smallestIndex = 0;\n    static constexpr int secondSmallestIndex = 1;\n    static constexpr int divisibleRemainder = 0;\n    static constexpr int remainderOne = 1;\n    static constexpr int remainderTwo = 2;\n\npublic:\n    int maxSumDivThree(vector<int>& nums) {\n        array<int, removedSlots> minRemainderOne = {\n            unavailable,\n            unavailable\n        };\n        array<int, removedSlots> minRemainderTwo = {\n            unavailable,\n            unavailable\n        };\n        int total = 0;\n\n        for (int value : nums) {\n            total += value;\n            int remainder = value % divisor;\n\n            if (remainder == remainderOne) {\n                rememberSmallest(minRemainderOne, value);\n            } else if (remainder == remainderTwo) {\n                rememberSmallest(minRemainderTwo, value);\n            }\n        }\n\n        int totalRemainder = total % divisor;\n        if (totalRemainder == divisibleRemainder) {\n            return total;\n        }\n        if (totalRemainder == remainderOne) {\n            return max(\n                removeOne(total, minRemainderOne),\n                removeTwo(total, minRemainderTwo)\n            );\n        }\n        return max(\n            removeOne(total, minRemainderTwo),\n            removeTwo(total, minRemainderOne)\n        );\n    }\n\nprivate:\n    void rememberSmallest(\n        array<int, removedSlots>& values,\n        int candidate\n    ) {\n        if (candidate < values[smallestIndex]) {\n            values[secondSmallestIndex] = values[smallestIndex];\n            values[smallestIndex] = candidate;\n            return;\n        }\n        if (candidate < values[secondSmallestIndex]) {\n            values[secondSmallestIndex] = candidate;\n        }\n    }\n\n    int removeOne(int total, const array<int, removedSlots>& values) {\n        if (values[smallestIndex] == unavailable) {\n            return 0;\n        }\n        return total - values[smallestIndex];\n    }\n\n    int removeTwo(int total, const array<int, removedSlots>& values) {\n        if (values[secondSmallestIndex] == unavailable) {\n            return 0;\n        }\n        return total - values[smallestIndex] - values[secondSmallestIndex];\n    }\n};"
