      "code": "class Solution {\npublic:\n    int longestPalindromeSubseq(string s) {\n        int n = s.size();\n        if (n == 0) {\n            return 0;\n        }\n\n        vector<vector<int>> dp(n, vector<int>(n));\n\n        for (int left = n - 1; left >= 0; --left) {\n            dp[left][left] = 1;\n            for (int right = left + 1; right < n; ++right) {\n                if (s[left] == s[right]) {\n                    dp[left][right] = dp[left + 1][right - 1] + 2;\n                } else {\n                    int skipLeft = dp[left + 1][right];\n                    int skipRight = dp[left][right - 1];\n                    dp[left][right] = max(skipLeft, skipRight);\n                }\n            }\n        }\n\n        return dp[0][n - 1];\n    }\n};"
