      "code": "class Solution {\npublic:\n    string simplifyPath(string path) {\n        const string currentDirectory = \".\";\n        const string parentDirectory = \"..\";\n        const string rootPath = \"/\";\n\n        vector<string> directories;\n        int n = path.size();\n        int start = 0;\n\n        while (start < n) {\n            while (start < n && path[start] == separator) {\n                ++start;\n            }\n\n            int end = start;\n            while (end < n && path[end] != separator) {\n                ++end;\n            }\n\n            if (start < end) {\n                string component = path.substr(start, end - start);\n                if (component == parentDirectory) {\n                    if (!directories.empty()) {\n                        directories.pop_back();\n                    }\n                } else if (component != currentDirectory) {\n                    directories.push_back(component);\n                }\n            }\n\n            start = end;\n        }\n\n        if (directories.empty()) {\n            return rootPath;\n        }\n\n        string answer;\n        for (const string& directory : directories) {\n            answer.push_back(separator);\n            answer += directory;\n        }\n        return answer;\n    }\n\nprivate:\n    static constexpr char separator = '/';\n};"
