      "code": "class Solution {\npublic:\n    string longestDupSubstring(string s) {\n        const int n = static_cast<int>(s.size());\n        if (n < minLengthWithDuplicate) {\n            return emptyAnswer;\n        }\n\n        vector<int> suffixArray = buildSuffixArray(s);\n        vector<int> rank(n, 0);\n        for (int order = 0; order < n; ++order) {\n            rank[suffixArray[order]] = order;\n        }\n\n        int bestLength = 0;\n        int bestStart = 0;\n        int matched = 0;\n\n        for (int start = 0; start < n; ++start) {\n            const int order = rank[start];\n            if (order == n - 1) {\n                matched = 0;\n                continue;\n            }\n\n            const int nextStart = suffixArray[order + 1];\n            while (start + matched < n && nextStart + matched < n &&\n                   s[start + matched] == s[nextStart + matched]) {\n                ++matched;\n            }\n\n            if (matched > bestLength) {\n                bestLength = matched;\n                bestStart = start;\n            }\n            if (matched > 0) {\n                --matched;\n            }\n        }\n\n        if (bestLength == 0) {\n            return emptyAnswer;\n        }\n        return s.substr(bestStart, bestLength);\n    }\n\nprivate:\n    vector<int> buildSuffixArray(const string& s) {\n        const int n = static_cast<int>(s.size());\n        vector<int> suffixArray(n);\n        vector<int> rank(n);\n        vector<int> nextRank(n);\n\n        iota(suffixArray.begin(), suffixArray.end(), 0);\n        for (int i = 0; i < n; ++i) {\n            rank[i] = static_cast<unsigned char>(s[i]);\n        }\n\n        for (int length = 1; length < n; length *= 2) {\n            sort(suffixArray.begin(), suffixArray.end(), [&](int left, int right) {\n                if (rank[left] != rank[right]) {\n                    return rank[left] < rank[right];\n                }\n\n                const int leftNext = left + length < n ? rank[left + length] : noRank;\n                const int rightNext = right + length < n ? rank[right + length] : noRank;\n                return leftNext < rightNext;\n            });\n\n            nextRank[suffixArray[0]] = 0;\n            for (int i = 1; i < n; ++i) {\n                nextRank[suffixArray[i]] = nextRank[suffixArray[i - 1]];\n                if (isDifferentPair(suffixArray[i - 1], suffixArray[i], length, rank)) {\n                    ++nextRank[suffixArray[i]];\n                }\n            }\n\n            rank.swap(nextRank);\n            if (rank[suffixArray.back()] == n - 1) {\n                break;\n            }\n        }\n\n        return suffixArray;\n    }\n\n    bool isDifferentPair(\n        int left,\n        int right,\n        int length,\n        const vector<int>& rank\n    ) const {\n        if (rank[left] != rank[right]) {\n            return true;\n        }\n\n        const int n = static_cast<int>(rank.size());\n        const int leftNext = left + length < n ? rank[left + length] : noRank;\n        const int rightNext = right + length < n ? rank[right + length] : noRank;\n        return leftNext != rightNext;\n    }\n\n    static constexpr int noRank = -1;\n    static constexpr int minLengthWithDuplicate = 2;\n    static constexpr const char* emptyAnswer = \"\";\n};"
