      "code": "class Solution {\npublic:\n    vector<int> twoSum(vector<int>& numbers, int target) {\n        int n = numbers.size();\n\n        for (int first = 0; first < n; ++first) {\n            int complement = target - numbers[first];\n            auto begin = numbers.begin() + first + 1;\n            auto found = lower_bound(begin, numbers.end(), complement);\n\n            if (found != numbers.end() && *found == complement) {\n                int second = static_cast<int>(found - numbers.begin());\n                return {first + indexOffset, second + indexOffset};\n            }\n        }\n\n        return {};\n    }\n\nprivate:\n    static constexpr int indexOffset = 1;\n};"
