      "code": "class Solution {\npublic:\n    int maxProfit(int k, vector<int>& prices) {\n        int n = prices.size();\n        if (k == 0 || n < minDaysPerTransaction) {\n            return 0;\n        }\n        if (k >= n / minDaysPerTransaction) {\n            return maxProfitWithoutLimit(prices);\n        }\n\n        vector<int> buy(k + 1, impossibleProfit);\n        vector<int> sell(k + 1, 0);\n\n        for (int price : prices) {\n            for (int transaction = 1; transaction <= k; ++transaction) {\n                buy[transaction] = max(\n                    buy[transaction],\n                    sell[transaction - 1] - price\n                );\n                sell[transaction] = max(\n                    sell[transaction],\n                    buy[transaction] + price\n                );\n            }\n        }\n\n        return sell[k];\n    }\n\nprivate:\n    static constexpr int minDaysPerTransaction = 2;\n    static constexpr int impossibleProfit = -1000000000;\n\n    int maxProfitWithoutLimit(const vector<int>& prices) {\n        int profit = 0;\n        for (int day = 1; day < prices.size(); ++day) {\n            int gain = prices[day] - prices[day - 1];\n            if (gain > 0) {\n                profit += gain;\n            }\n        }\n        return profit;\n    }\n};"
