      "code": "class Solution {\npublic:\n    int reversePairs(vector<int>& nums) {\n        if (nums.empty()) {\n            return noPairs;\n        }\n\n        vector<int> buffer(nums.size());\n        return sortAndCount(\n            nums,\n            buffer,\n            firstIndex,\n            static_cast<int>(nums.size()) - lastIndexOffset\n        );\n    }\n\nprivate:\n    int sortAndCount(\n        vector<int>& nums,\n        vector<int>& buffer,\n        int left,\n        int right\n    ) {\n        if (left >= right) {\n            return noPairs;\n        }\n\n        int mid = left + (right - left) / twoParts;\n        int answer = sortAndCount(nums, buffer, left, mid);\n        answer += sortAndCount(nums, buffer, mid + nextIndexStep, right);\n        answer += countCrossPairs(nums, left, mid, right);\n        mergeSortedHalves(nums, buffer, left, mid, right);\n        return answer;\n    }\n\n    int countCrossPairs(\n        const vector<int>& nums,\n        int left,\n        int mid,\n        int right\n    ) const {\n        int answer = noPairs;\n        int rightIndex = mid + nextIndexStep;\n\n        for (int leftIndex = left; leftIndex <= mid; ++leftIndex) {\n            while (\n                rightIndex <= right &&\n                static_cast<long long>(nums[leftIndex])\n                    > doubleMultiplier * nums[rightIndex]\n            ) {\n                ++rightIndex;\n            }\n            answer += rightIndex - (mid + nextIndexStep);\n        }\n\n        return answer;\n    }\n\n    void mergeSortedHalves(\n        vector<int>& nums,\n        vector<int>& buffer,\n        int left,\n        int mid,\n        int right\n    ) const {\n        int leftIndex = left;\n        int rightIndex = mid + nextIndexStep;\n        int writeIndex = left;\n\n        while (leftIndex <= mid && rightIndex <= right) {\n            if (nums[leftIndex] <= nums[rightIndex]) {\n                buffer[writeIndex] = nums[leftIndex];\n                ++leftIndex;\n            } else {\n                buffer[writeIndex] = nums[rightIndex];\n                ++rightIndex;\n            }\n            ++writeIndex;\n        }\n\n        while (leftIndex <= mid) {\n            buffer[writeIndex] = nums[leftIndex];\n            ++leftIndex;\n            ++writeIndex;\n        }\n        while (rightIndex <= right) {\n            buffer[writeIndex] = nums[rightIndex];\n            ++rightIndex;\n            ++writeIndex;\n        }\n\n        for (int index = left; index <= right; ++index) {\n            nums[index] = buffer[index];\n        }\n    }\n\n    static constexpr int noPairs = 0;\n    static constexpr int firstIndex = 0;\n    static constexpr int nextIndexStep = 1;\n    static constexpr int lastIndexOffset = 1;\n    static constexpr int twoParts = 2;\n    static constexpr long long doubleMultiplier = 2LL;\n};"
