      "code": "class FenwickTree {\npublic:\n    explicit FenwickTree(int size)\n        : counts(size + oneBasedExtra, noNumbers) {}\n\n    void add(int index, int delta) {\n        while (index < static_cast<int>(counts.size())) {\n            counts[index] += delta;\n            index += lowbit(index);\n        }\n    }\n\n    int prefixSum(int index) const {\n        int total = noNumbers;\n        while (index > noIndex) {\n            total += counts[index];\n            index -= lowbit(index);\n        }\n        return total;\n    }\n\nprivate:\n    static int lowbit(int value) {\n        return value & -value;\n    }\n\n    static constexpr int oneBasedExtra = 1;\n    static constexpr int noNumbers = 0;\n    static constexpr int noIndex = 0;\n\n    vector<int> counts;\n};\n\nclass Solution {\npublic:\n    int reversePairs(vector<int>& nums) {\n        vector<long long> values;\n        values.reserve(nums.size() * valuesPerNumber);\n\n        for (int num : nums) {\n            long long value = num;\n            values.push_back(value);\n            values.push_back(value * doubleMultiplier);\n        }\n\n        sort(values.begin(), values.end());\n        values.erase(unique(values.begin(), values.end()), values.end());\n\n        FenwickTree seenDoubledValues(static_cast<int>(values.size()));\n        int answer = noPairs;\n\n        for (int index = static_cast<int>(nums.size()) - lastIndexOffset;\n             index >= firstIndex;\n             --index) {\n            long long current = nums[index];\n            int currentRank = rankOf(values, current);\n            answer += seenDoubledValues.prefixSum(\n                currentRank - previousRankStep\n            );\n\n            int doubledRank = rankOf(values, current * doubleMultiplier);\n            seenDoubledValues.add(doubledRank, oneNumber);\n        }\n\n        return answer;\n    }\n\nprivate:\n    int rankOf(const vector<long long>& values, long long value) const {\n        auto it = lower_bound(values.begin(), values.end(), value);\n        return static_cast<int>(it - values.begin()) + oneBasedOffset;\n    }\n\n    static constexpr int noPairs = 0;\n    static constexpr int firstIndex = 0;\n    static constexpr int lastIndexOffset = 1;\n    static constexpr int previousRankStep = 1;\n    static constexpr int oneBasedOffset = 1;\n    static constexpr int valuesPerNumber = 2;\n    static constexpr int oneNumber = 1;\n    static constexpr long long doubleMultiplier = 2LL;\n};"
