      "code": "class Solution {\npublic:\n    ListNode* reverseKGroup(ListNode* head, int k) {\n        ListNode* kth = head;\n        for (int step = 0; step < k; ++step) {\n            if (!kth) {\n                return head;\n            }\n            kth = kth->next;\n        }\n\n        ListNode* prev = reverseKGroup(kth, k);\n        ListNode* cur = head;\n\n        while (cur != kth) {\n            ListNode* next = cur->next;\n            cur->next = prev;\n            prev = cur;\n            cur = next;\n        }\n\n        return prev;\n    }\n};"
