      "code": "class Solution {\npublic:\n    vector<int> findAnagrams(string s, string p) {\n        const int alphabetSize = 26;\n        int n = s.size();\n        int windowSize = p.size();\n        vector<int> answer;\n\n        if (windowSize > n) {\n            return answer;\n        }\n\n        array<int, alphabetSize> target{};\n        array<int, alphabetSize> window{};\n        for (char ch : p) {\n            ++target[ch - 'a'];\n        }\n\n        for (int right = 0; right < n; ++right) {\n            ++window[s[right] - 'a'];\n            if (right >= windowSize) {\n                --window[s[right - windowSize] - 'a'];\n            }\n            if (right + 1 >= windowSize && window == target) {\n                answer.push_back(right - windowSize + 1);\n            }\n        }\n\n        return answer;\n    }\n};"
