      "code": "class Solution {\npublic:\n    vector<int> findAnagrams(string s, string p) {\n        int n = s.size();\n        int windowSize = p.size();\n        vector<int> answer;\n\n        if (windowSize > n) {\n            return answer;\n        }\n\n        sort(p.begin(), p.end());\n        for (int left = 0; left + windowSize <= n; ++left) {\n            string candidate = s.substr(left, windowSize);\n            sort(candidate.begin(), candidate.end());\n            if (candidate == p) {\n                answer.push_back(left);\n            }\n        }\n\n        return answer;\n    }\n};"
