      "sourceUrl": "https://leetcode.cn/problems/lowest-common-ancestor-of-a-binary-tree/description/",
      "code": "class Solution {\npublic:\n    TreeNode* lowestCommonAncestor(\n        TreeNode* root,\n        TreeNode* p,\n        TreeNode* q\n    ) {\n        vector<TreeNode*> pathP;\n        vector<TreeNode*> pathQ;\n        buildPath(root, p, pathP);\n        buildPath(root, q, pathQ);\n\n        TreeNode* answer = nullptr;\n        size_t limit = min(pathP.size(), pathQ.size());\n        for (size_t i = 0; i < limit && pathP[i] == pathQ[i]; ++i) {\n            answer = pathP[i];\n        }\n        return answer;\n    }\n\nprivate:\n    bool buildPath(\n        TreeNode* root,\n        TreeNode* target,\n        vector<TreeNode*>& path\n    ) {\n        vector<pair<TreeNode*, bool>> pending;\n        pending.push_back({root, false});\n\n        while (!pending.empty()) {\n            auto [node, exit] = pending.back();\n            pending.pop_back();\n            if (node == nullptr) {\n                continue;\n            }\n\n            if (exit) {\n                path.pop_back();\n                continue;\n            }\n\n            path.push_back(node);\n            if (node == target) {\n                return true;\n            }\n\n            pending.push_back({node, true});\n            pending.push_back({node->right, false});\n            pending.push_back({node->left, false});\n        }\n\n        return false;\n    }\n};"
