      "code": "class Solution {\npublic:\n    int deleteAndEarn(vector<int>& nums) {\n        unordered_map<int, int> pointsByValue;\n        for (int value : nums) {\n            pointsByValue[value] += value;\n        }\n\n        vector<int> values;\n        values.reserve(pointsByValue.size());\n        for (const auto& entry : pointsByValue) {\n            values.push_back(entry.first);\n        }\n        sort(values.begin(), values.end());\n\n        int take = 0;\n        int skip = 0;\n        int previousValue = -1;\n        bool hasPreviousValue = false;\n\n        for (int value : values) {\n            int points = pointsByValue[value];\n            int bestBefore = max(take, skip);\n            bool conflictsWithPrevious =\n                hasPreviousValue && value == previousValue + 1;\n\n            if (conflictsWithPrevious) {\n                take = skip + points;\n            } else {\n                take = bestBefore + points;\n            }\n            skip = bestBefore;\n            previousValue = value;\n            hasPreviousValue = true;\n        }\n\n        return max(take, skip);\n    }\n};"
