      "code": "class Solution {\npublic:\n    int rob(vector<int>& nums) {\n        int n = nums.size();\n        if (n == 0) {\n            return 0;\n        }\n        if (n == 1) {\n            return nums[0];\n        }\n\n        return max(\n            robWithMemo(nums, 0, n - 2),\n            robWithMemo(nums, 1, n - 1)\n        );\n    }\n\nprivate:\n    static constexpr int uncomputed = -1;\n\n    int robWithMemo(const vector<int>& nums, int left, int right) {\n        vector<int> memo(nums.size(), uncomputed);\n        return dfs(nums, left, right, memo);\n    }\n\n    int dfs(\n        const vector<int>& nums,\n        int index,\n        int right,\n        vector<int>& memo\n    ) {\n        if (index > right) {\n            return 0;\n        }\n        if (memo[index] != uncomputed) {\n            return memo[index];\n        }\n\n        int take = nums[index] + dfs(nums, index + 2, right, memo);\n        int skip = dfs(nums, index + 1, right, memo);\n        memo[index] = max(take, skip);\n        return memo[index];\n    }\n};"
