      "code": "class Solution {\npublic:\n    bool makesquare(vector<int>& matchsticks) {\n        int n = matchsticks.size();\n        if (n < sideCount) {\n            return false;\n        }\n\n        int totalLength = accumulate(matchsticks.begin(), matchsticks.end(), 0);\n        if (totalLength % sideCount != 0) {\n            return false;\n        }\n\n        int targetSide = totalLength / sideCount;\n        sort(matchsticks.begin(), matchsticks.end(), greater<int>());\n        if (matchsticks.front() > targetSide) {\n            return false;\n        }\n        if (targetSide == 0) {\n            return true;\n        }\n\n        vector<int> sides(sideCount);\n        return fillSides(matchsticks, 0, targetSide, sides);\n    }\n\nprivate:\n    static constexpr int sideCount = 4;\n\n    bool fillSides(\n        const vector<int>& matchsticks,\n        int stickIndex,\n        int targetSide,\n        vector<int>& sides\n    ) {\n        if (stickIndex == matchsticks.size()) {\n            for (int side : sides) {\n                if (side != targetSide) {\n                    return false;\n                }\n            }\n            return true;\n        }\n\n        int stick = matchsticks[stickIndex];\n        int previousSide = -1;\n        for (int sideIndex = 0; sideIndex < sideCount; ++sideIndex) {\n            if (sides[sideIndex] == previousSide) {\n                continue;\n            }\n            if (sides[sideIndex] + stick > targetSide) {\n                continue;\n            }\n\n            previousSide = sides[sideIndex];\n            sides[sideIndex] += stick;\n            if (fillSides(matchsticks, stickIndex + 1, targetSide, sides)) {\n                return true;\n            }\n            sides[sideIndex] -= stick;\n\n            if (sides[sideIndex] == 0) {\n                break;\n            }\n        }\n\n        return false;\n    }\n};"
