      "code": "class Solution {\npublic:\n    int findTargetSumWays(vector<int>& nums, int target) {\n        memo.assign(nums.size(), unordered_map<int, int>());\n        return dfs(nums, 0, target);\n    }\n\nprivate:\n    static constexpr int targetReached = 0;\n    static constexpr int oneWay = 1;\n    static constexpr int noWay = 0;\n\n    vector<unordered_map<int, int>> memo;\n\n    int dfs(const vector<int>& nums, int index, int remaining) {\n        int n = static_cast<int>(nums.size());\n        if (index == n) {\n            return remaining == targetReached ? oneWay : noWay;\n        }\n\n        auto& states = memo[index];\n        auto it = states.find(remaining);\n        if (it != states.end()) {\n            return it->second;\n        }\n\n        int value = nums[index];\n        int withPlus = dfs(nums, index + 1, remaining - value);\n        int withMinus = dfs(nums, index + 1, remaining + value);\n        int ways = withPlus + withMinus;\n        states[remaining] = ways;\n        return ways;\n    }\n};"
