      "code": "class Solution {\npublic:\n    int findTargetSumWays(vector<int>& nums, int target) {\n        int total = accumulate(nums.begin(), nums.end(), 0);\n        if (target > total || target < -total) {\n            return noWay;\n        }\n\n        int doubledPositiveSum = total + target;\n        if (doubledPositiveSum % splitDivisor != 0) {\n            return noWay;\n        }\n\n        int positiveSum = doubledPositiveSum / splitDivisor;\n        vector<int> dp(positiveSum + 1, noWay);\n        dp[emptySum] = oneWay;\n\n        for (int num : nums) {\n            for (int sum = positiveSum; sum >= num; --sum) {\n                dp[sum] += dp[sum - num];\n            }\n        }\n\n        return dp[positiveSum];\n    }\n\nprivate:\n    static constexpr int noWay = 0;\n    static constexpr int oneWay = 1;\n    static constexpr int emptySum = 0;\n    static constexpr int splitDivisor = 2;\n};"
