      "code": "class Solution {\npublic:\n    int numSquares(int n) {\n        vector<int> squares;\n        for (int base = 1; base * base <= n; ++base) {\n            squares.push_back(base * base);\n        }\n\n        queue<int> remainders;\n        vector<bool> visited(n + 1);\n        remainders.push(n);\n        visited[n] = true;\n\n        int depth = 0;\n        while (!remainders.empty()) {\n            ++depth;\n            int levelSize = remainders.size();\n            for (int i = 0; i < levelSize; ++i) {\n                int current = remainders.front();\n                remainders.pop();\n\n                for (int square : squares) {\n                    if (square > current) {\n                        break;\n                    }\n                    int next = current - square;\n                    if (next == 0) {\n                        return depth;\n                    }\n                    if (!visited[next]) {\n                        visited[next] = true;\n                        remainders.push(next);\n                    }\n                }\n            }\n        }\n\n        return depth;\n    }\n};"
