      "code": "class Solution {\npublic:\n    vector<string> topKFrequent(vector<string>& words, int k) {\n        unordered_map<string, int> frequencyByWord;\n        for (const string& word : words) {\n            ++frequencyByWord[word];\n        }\n\n        vector<string> uniqueWords;\n        uniqueWords.reserve(frequencyByWord.size());\n        for (const auto& entry : frequencyByWord) {\n            uniqueWords.push_back(entry.first);\n        }\n\n        // The sort comparator says which word appears earlier.\n        sort(uniqueWords.begin(), uniqueWords.end(),\n            [&](const string& left, const string& right) {\n                int leftFrequency = frequencyByWord.at(left);\n                int rightFrequency = frequencyByWord.at(right);\n                if (leftFrequency != rightFrequency) {\n                    return leftFrequency > rightFrequency;\n                }\n                return left < right;\n            }\n        );\n\n        uniqueWords.resize(k);\n        return uniqueWords;\n    }\n};"
