      "code": "class Solution {\nprivate:\n    struct Candidate {\n        string word;\n        int frequency;\n    };\n\n    // Keep the worst candidate at priority_queue::top().\n    struct WorstFirst {\n        bool operator()(const Candidate& left, const Candidate& right) const {\n            if (left.frequency != right.frequency) {\n                return left.frequency > right.frequency;\n            }\n            return left.word < right.word;\n        }\n    };\n\npublic:\n    vector<string> topKFrequent(vector<string>& words, int k) {\n        unordered_map<string, int> frequencyByWord;\n        for (const string& word : words) {\n            ++frequencyByWord[word];\n        }\n\n        priority_queue<Candidate, vector<Candidate>, WorstFirst> heap;\n        for (const auto& [word, frequency] : frequencyByWord) {\n            heap.push({word, frequency});\n            if (static_cast<int>(heap.size()) > k) {\n                heap.pop();\n            }\n        }\n\n        vector<string> answer;\n        answer.reserve(k);\n        while (!heap.empty()) {\n            answer.push_back(heap.top().word);\n            heap.pop();\n        }\n\n        // The heap stores the right set, then this restores answer order.\n        sort(answer.begin(), answer.end(),\n            [&](const string& left, const string& right) {\n                int leftFrequency = frequencyByWord.at(left);\n                int rightFrequency = frequencyByWord.at(right);\n                if (leftFrequency != rightFrequency) {\n                    return leftFrequency > rightFrequency;\n                }\n                return left < right;\n            }\n        );\n\n        return answer;\n    }\n};"
