      "code": "class Solution {\npublic:\n    int triangleNumber(vector<int>& nums) {\n        int n = static_cast<int>(nums.size());\n        if (n < sideCount) {\n            return 0;\n        }\n\n        sort(nums.begin(), nums.end());\n\n        int answer = 0;\n        for (int largest = n - 1; largest >= firstLargestIndex; --largest) {\n            int left = 0;\n            int right = largest - 1;\n\n            while (left < right) {\n                long long sideSum =\n                    static_cast<long long>(nums[left]) + nums[right];\n                if (sideSum > nums[largest]) {\n                    answer += right - left;\n                    --right;\n                } else {\n                    ++left;\n                }\n            }\n        }\n\n        return answer;\n    }\n\nprivate:\n    static constexpr int sideCount = 3;\n    static constexpr int firstLargestIndex = sideCount - 1;\n};"
