      "code": "class Solution {\npublic:\n    vector<int> intersection(vector<int>& nums1, vector<int>& nums2) {\n        bool firstIsSmaller = nums1.size() <= nums2.size();\n        const vector<int>& smaller = firstIsSmaller ? nums1 : nums2;\n        const vector<int>& larger = firstIsSmaller ? nums2 : nums1;\n\n        unordered_set<int> values(smaller.begin(), smaller.end());\n        unordered_set<int> intersectionValues;\n\n        for (int value : larger) {\n            if (values.count(value) > 0) {\n                intersectionValues.insert(value);\n            }\n        }\n\n        return vector<int>(\n            intersectionValues.begin(),\n            intersectionValues.end()\n        );\n    }\n};"
