      "code": "class Solution {\npublic:\n    bool canPartition(vector<int>& nums) {\n        int total = accumulate(nums.begin(), nums.end(), 0);\n        if (total % 2 != 0) {\n            return false;\n        }\n\n        int n = nums.size();\n        int target = total / 2;\n        vector<vector<bool>> dp(n + 1, vector<bool>(target + 1, false));\n        dp[0][0] = true;\n\n        for (int i = 1; i <= n; ++i) {\n            dp[i][0] = true;\n            int num = nums[i - 1];\n            for (int sum = 1; sum <= target; ++sum) {\n                dp[i][sum] = dp[i - 1][sum];\n                if (sum >= num) {\n                    dp[i][sum] = dp[i][sum] || dp[i - 1][sum - num];\n                }\n            }\n        }\n\n        return dp[n][target];\n    }\n};"
