      "code": "class Solution {\npublic:\n    int minSubArrayLen(int target, vector<int>& nums) {\n        int n = nums.size();\n        int left = 0;\n        int windowSum = 0;\n        int bestLength = n + 1;\n\n        for (int right = 0; right < n; ++right) {\n            windowSum += nums[right];\n            while (windowSum >= target) {\n                bestLength = min(bestLength, right - left + 1);\n                windowSum -= nums[left];\n                ++left;\n            }\n        }\n\n        if (bestLength == n + 1) {\n            return 0;\n        }\n        return bestLength;\n    }\n};"
