      "code": "class Solution {\npublic:\n    int minSubArrayLen(int target, vector<int>& nums) {\n        int n = nums.size();\n        vector<int> prefix(n + 1, 0);\n        for (int i = 0; i < n; ++i) {\n            prefix[i + 1] = prefix[i] + nums[i];\n        }\n\n        int bestLength = n + 1;\n        for (int left = 0; left < n; ++left) {\n            int need = prefix[left] + target;\n            auto it = lower_bound(prefix.begin(), prefix.end(), need);\n            if (it != prefix.end()) {\n                int right = it - prefix.begin();\n                bestLength = min(bestLength, right - left);\n            }\n        }\n\n        if (bestLength == n + 1) {\n            return 0;\n        }\n        return bestLength;\n    }\n};"
