      "code": "class Solution {\npublic:\n    int minimumDeleteSum(string s1, string s2) {\n        int rows = s1.size();\n        int cols = s2.size();\n        vector<vector<int>> dp(rows + 1, vector<int>(cols + 1));\n\n        for (int i = rows - 1; i >= 0; --i) {\n            dp[i][cols] = charCost(s1[i]) + dp[i + 1][cols];\n        }\n        for (int j = cols - 1; j >= 0; --j) {\n            dp[rows][j] = charCost(s2[j]) + dp[rows][j + 1];\n        }\n\n        for (int i = rows - 1; i >= 0; --i) {\n            for (int j = cols - 1; j >= 0; --j) {\n                if (s1[i] == s2[j]) {\n                    dp[i][j] = dp[i + 1][j + 1];\n                } else {\n                    int deleteFirst = charCost(s1[i]) + dp[i + 1][j];\n                    int deleteSecond = charCost(s2[j]) + dp[i][j + 1];\n                    dp[i][j] = min(deleteFirst, deleteSecond);\n                }\n            }\n        }\n\n        return dp[0][0];\n    }\n\nprivate:\n    int charCost(char ch) {\n        return static_cast<int>(static_cast<unsigned char>(ch));\n    }\n};"
