      "sourceUrl": "https://leetcode.cn/problems/n-queens/description/",
      "code": "class Solution {\npublic:\n    vector<vector<string>> solveNQueens(int n) {\n        vector<vector<string>> answers;\n        vector<string> board(n, string(n, '.'));\n        vector<bool> usedColumn(n, false);\n        vector<bool> usedMainDiagonal(2 * n - 1, false);\n        vector<bool> usedAntiDiagonal(2 * n - 1, false);\n\n        auto dfs = [&](this auto&& dfs, int row) -> void {\n            if (row == n) {\n                answers.push_back(board);\n                return;\n            }\n\n            for (int col = 0; col < n; ++col) {\n                int mainDiagonal = row - col + n - 1;\n                int antiDiagonal = row + col;\n                if (usedColumn[col] || usedMainDiagonal[mainDiagonal] ||\n                    usedAntiDiagonal[antiDiagonal]) {\n                    continue;\n                }\n\n                usedColumn[col] = true;\n                usedMainDiagonal[mainDiagonal] = true;\n                usedAntiDiagonal[antiDiagonal] = true;\n                board[row][col] = 'Q';\n\n                dfs(row + 1);\n\n                board[row][col] = '.';\n                usedColumn[col] = false;\n                usedMainDiagonal[mainDiagonal] = false;\n                usedAntiDiagonal[antiDiagonal] = false;\n            }\n        };\n\n        dfs(0);\n        return answers;\n    }\n};"
