      "code": "class Solution {\n    static constexpr int digitBase = 10;\n    static constexpr char zeroDigit = '0';\n\npublic:\n    string multiply(string num1, string num2) {\n        num1 = stripLeadingZeros(num1);\n        num2 = stripLeadingZeros(num2);\n        if (isZero(num1) || isZero(num2)) {\n            return string(1, zeroDigit);\n        }\n\n        int m = static_cast<int>(num1.size());\n        int n = static_cast<int>(num2.size());\n        vector<int> digits(m + n);\n\n        for (int i = m - 1; i >= 0; --i) {\n            for (int j = n - 1; j >= 0; --j) {\n                int product = (num1[i] - zeroDigit) * (num2[j] - zeroDigit);\n                int lowPosition = i + j + 1;\n                int highPosition = i + j;\n                int sum = digits[lowPosition] + product;\n                digits[lowPosition] = sum % digitBase;\n                digits[highPosition] += sum / digitBase;\n            }\n        }\n\n        string answer;\n        int index = 0;\n        while (index < digits.size() && digits[index] == 0) {\n            ++index;\n        }\n        while (index < digits.size()) {\n            answer.push_back(zeroDigit + digits[index]);\n            ++index;\n        }\n        return answer.empty() ? string(1, zeroDigit) : answer;\n    }\n\nprivate:\n    string stripLeadingZeros(const string& value) {\n        size_t firstDigit = value.find_first_not_of(zeroDigit);\n        if (firstDigit == string::npos) {\n            return string(1, zeroDigit);\n        }\n        return value.substr(firstDigit);\n    }\n\n    bool isZero(const string& value) {\n        return value.size() == 1 && value[0] == zeroDigit;\n    }\n};"
