      "code": "class Solution {\n    static constexpr int digitBase = 10;\n    static constexpr char zeroDigit = '0';\n\npublic:\n    string multiply(string num1, string num2) {\n        num1 = stripLeadingZeros(num1);\n        num2 = stripLeadingZeros(num2);\n\n        string result(1, zeroDigit);\n        while (!isZero(num2)) {\n            result = add(result, num1);\n            num2 = subtractOne(num2);\n        }\n        return result;\n    }\n\nprivate:\n    string stripLeadingZeros(const string& value) {\n        size_t firstDigit = value.find_first_not_of(zeroDigit);\n        if (firstDigit == string::npos) {\n            return string(1, zeroDigit);\n        }\n        return value.substr(firstDigit);\n    }\n\n    bool isZero(const string& value) {\n        return value.size() == 1 && value[0] == zeroDigit;\n    }\n\n    string add(const string& left, const string& right) {\n        string result;\n        int carry = 0;\n        int i = static_cast<int>(left.size()) - 1;\n        int j = static_cast<int>(right.size()) - 1;\n\n        while (i >= 0 || j >= 0 || carry > 0) {\n            int sum = carry;\n            if (i >= 0) {\n                sum += left[i] - zeroDigit;\n                --i;\n            }\n            if (j >= 0) {\n                sum += right[j] - zeroDigit;\n                --j;\n            }\n            result.push_back(zeroDigit + sum % digitBase);\n            carry = sum / digitBase;\n        }\n\n        reverse(result.begin(), result.end());\n        return result;\n    }\n\n    string subtractOne(string value) {\n        int index = static_cast<int>(value.size()) - 1;\n        while (value[index] == zeroDigit) {\n            value[index] = zeroDigit + digitBase - 1;\n            --index;\n        }\n        --value[index];\n        return stripLeadingZeros(value);\n    }\n};"
