      "code": "class Solution {\npublic:\n    vector<int> largestDivisibleSubset(vector<int>& nums) {\n        if (nums.empty()) {\n            return {};\n        }\n\n        sort(nums.begin(), nums.end());\n\n        int n = nums.size();\n        vector<int> memo(n, unknownLength);\n        vector<int> nextIndex(n, noNextIndex);\n        int bestStart = 0;\n\n        for (int i = 0; i < n; ++i) {\n            if (dfs(i, nums, memo, nextIndex) >\n                dfs(bestStart, nums, memo, nextIndex)) {\n                bestStart = i;\n            }\n        }\n\n        vector<int> answer;\n        for (int index = bestStart; index != noNextIndex;\n             index = nextIndex[index]) {\n            answer.push_back(nums[index]);\n        }\n        return answer;\n    }\n\nprivate:\n    static constexpr int unknownLength = 0;\n    static constexpr int singleNumberLength = 1;\n    static constexpr int noNextIndex = -1;\n\n    int dfs(\n        int index,\n        const vector<int>& nums,\n        vector<int>& memo,\n        vector<int>& nextIndex\n    ) {\n        if (memo[index] != unknownLength) {\n            return memo[index];\n        }\n\n        int bestLength = singleNumberLength;\n        int n = nums.size();\n        for (int next = index + 1; next < n; ++next) {\n            if (nums[next] % nums[index] != 0) {\n                continue;\n            }\n\n            int candidateLength = dfs(next, nums, memo, nextIndex) + 1;\n            if (candidateLength > bestLength) {\n                bestLength = candidateLength;\n                nextIndex[index] = next;\n            }\n        }\n\n        memo[index] = bestLength;\n        return bestLength;\n    }\n};"
