      "code": "class Solution {\npublic:\n    string decodeString(string s) {\n        vector<int> counts;\n        vector<string> prefixes;\n        string current;\n        int count = 0;\n\n        for (char ch : s) {\n            if (isdigit(ch)) {\n                count = count * 10 + ch - '0';\n            } else if (ch == '[') {\n                counts.push_back(count);\n                prefixes.push_back(current);\n                count = 0;\n                current.clear();\n            } else if (ch == ']') {\n                int repeat = counts.back();\n                counts.pop_back();\n\n                string decoded = prefixes.back();\n                prefixes.pop_back();\n                while (repeat > 0) {\n                    decoded += current;\n                    --repeat;\n                }\n                current = decoded;\n            } else {\n                current.push_back(ch);\n            }\n        }\n\n        return current;\n    }\n};"
