      "code": "class Solution {\npublic:\n    int pathSum(TreeNode* root, int targetSum) {\n        unordered_map<long long, int> countByPrefix;\n        countByPrefix[emptyPrefixSum] = 1;\n        long long target = targetSum;\n        return dfs(root, emptyPrefixSum, target, countByPrefix);\n    }\n\nprivate:\n    static constexpr long long emptyPrefixSum = 0;\n\n    int dfs(\n        TreeNode* node,\n        long long currentSum,\n        long long targetSum,\n        unordered_map<long long, int>& countByPrefix\n    ) {\n        if (node == nullptr) {\n            return 0;\n        }\n\n        currentSum += node->val;\n        long long neededPrefix = currentSum - targetSum;\n        int paths = 0;\n        auto it = countByPrefix.find(neededPrefix);\n        if (it != countByPrefix.end()) {\n            paths += it->second;\n        }\n\n        ++countByPrefix[currentSum];\n        paths += dfs(node->left, currentSum, targetSum, countByPrefix);\n        paths += dfs(node->right, currentSum, targetSum, countByPrefix);\n\n        auto currentIt = countByPrefix.find(currentSum);\n        --currentIt->second;\n        if (currentIt->second == 0) {\n            countByPrefix.erase(currentIt);\n        }\n\n        return paths;\n    }\n};"
