      "code": "class Solution {\npublic:\n    bool isMatch(string s, string p) {\n        int m = s.size();\n        int n = p.size();\n        vector<vector<bool>> dp(m + 1, vector<bool>(n + 1));\n        dp[0][0] = true;\n\n        for (int j = 2; j <= n; ++j) {\n            if (p[j - 1] == '*') {\n                dp[0][j] = dp[0][j - 2];\n            }\n        }\n\n        for (int i = 1; i <= m; ++i) {\n            for (int j = 1; j <= n; ++j) {\n                if (p[j - 1] != '*') {\n                    if (matches(s[i - 1], p[j - 1])) {\n                        dp[i][j] = dp[i - 1][j - 1];\n                    }\n                    continue;\n                }\n\n                if (j < 2) {\n                    continue;\n                }\n                dp[i][j] = dp[i][j - 2];\n                if (matches(s[i - 1], p[j - 2])) {\n                    dp[i][j] = dp[i][j] || dp[i - 1][j];\n                }\n            }\n        }\n\n        return dp[m][n];\n    }\n\nprivate:\n    bool matches(char text, char pattern) {\n        return pattern == '.' || pattern == text;\n    }\n};"
