      "code": "class Solution {\npublic:\n    vector<int> getBiggestThree(vector<vector<int>>& grid) {\n        int rows = grid.size();\n        int cols = grid[0].size();\n        set<int, greater<int>> bestSums;\n\n        for (int centerRow = 0; centerRow < rows; ++centerRow) {\n            for (int centerCol = 0; centerCol < cols; ++centerCol) {\n                addSum(bestSums, grid[centerRow][centerCol]);\n\n                int maxRadius = min({\n                    centerRow,\n                    rows - 1 - centerRow,\n                    centerCol,\n                    cols - 1 - centerCol\n                });\n                for (int radius = 1; radius <= maxRadius; ++radius) {\n                    int sum = borderSum(grid, centerRow, centerCol, radius);\n                    addSum(bestSums, sum);\n                }\n            }\n        }\n\n        return vector<int>(bestSums.begin(), bestSums.end());\n    }\n\nprivate:\n    static constexpr int keepCount = 3;\n    static constexpr int sideCount = 4;\n\n    void addSum(set<int, greater<int>>& bestSums, int value) {\n        bestSums.insert(value);\n        if (bestSums.size() > keepCount) {\n            bestSums.erase(prev(bestSums.end()));\n        }\n    }\n\n    int borderSum(\n        const vector<vector<int>>& grid,\n        int centerRow,\n        int centerCol,\n        int radius\n    ) {\n        const array<int, sideCount> rowDelta = {1, 1, -1, -1};\n        const array<int, sideCount> colDelta = {1, -1, -1, 1};\n\n        int row = centerRow - radius;\n        int col = centerCol;\n        int sum = 0;\n\n        for (int side = 0; side < sideCount; ++side) {\n            for (int step = 0; step < radius; ++step) {\n                sum += grid[row][col];\n                row += rowDelta[side];\n                col += colDelta[side];\n            }\n        }\n\n        return sum;\n    }\n};"
