      "sourceUrl": "https://leetcode.cn/problems/longest-balanced-subarray-ii/description/",
      "code": "class Solution {\npublic:\n    int longestBalanced(vector<int>& nums) {\n        int n = nums.size();\n        SegmentTree tree(n);\n        unordered_map<int, int> lastPosition;\n        int best = 0;\n\n        for (int index = 0; index < n; ++index) {\n            int position = index + firstPosition;\n            int value = nums[index];\n            int delta = value % parityBase == 0 ? evenDelta : oddDelta;\n\n            auto it = lastPosition.find(value);\n            if (it != lastPosition.end()) {\n                tree.add(it->second, n, -delta);\n            }\n            tree.add(position, n, delta);\n            lastPosition[value] = position;\n\n            int currentState = tree.query(position);\n            int left = tree.findFirst(noPosition, position - 1, currentState);\n            if (left != notFound) {\n                best = max(best, position - left);\n            }\n        }\n\n        return best;\n    }\n\nprivate:\n    struct SegmentTree {\n        struct Node {\n            int mn = 0;\n            int mx = 0;\n            int lazy = 0;\n        };\n\n        explicit SegmentTree(int maxIndex)\n            : maxIndex(maxIndex), tree(nodeFactor * (maxIndex + 1)) {}\n\n        void add(int left, int right, int delta) {\n            if (left > right) {\n                return;\n            }\n            add(rootNode, 0, maxIndex, left, right, delta);\n        }\n\n        int query(int index) {\n            return query(rootNode, 0, maxIndex, index);\n        }\n\n        int findFirst(int left, int right, int target) {\n            if (left > right) {\n                return notFound;\n            }\n            return findFirst(rootNode, 0, maxIndex, left, right, target);\n        }\n\n        int maxIndex = 0;\n        vector<Node> tree;\n\n        void apply(int node, int delta) {\n            tree[node].mn += delta;\n            tree[node].mx += delta;\n            tree[node].lazy += delta;\n        }\n\n        void push(int node) {\n            int delta = tree[node].lazy;\n            if (delta == 0) {\n                return;\n            }\n            apply(node * leftChildMultiplier, delta);\n            apply(node * leftChildMultiplier + rightChildOffset, delta);\n            tree[node].lazy = 0;\n        }\n\n        void pull(int node) {\n            int left = node * leftChildMultiplier;\n            int right = left + rightChildOffset;\n            tree[node].mn = min(tree[left].mn, tree[right].mn);\n            tree[node].mx = max(tree[left].mx, tree[right].mx);\n        }\n\n        void add(\n            int node,\n            int nodeLeft,\n            int nodeRight,\n            int queryLeft,\n            int queryRight,\n            int delta\n        ) {\n            if (queryRight < nodeLeft || nodeRight < queryLeft) {\n                return;\n            }\n            if (queryLeft <= nodeLeft && nodeRight <= queryRight) {\n                apply(node, delta);\n                return;\n            }\n\n            push(node);\n            int middle = nodeLeft + (nodeRight - nodeLeft) / halfDivisor;\n            add(node * leftChildMultiplier, nodeLeft, middle,\n                queryLeft, queryRight, delta);\n            add(node * leftChildMultiplier + rightChildOffset,\n                middle + 1, nodeRight, queryLeft, queryRight, delta);\n            pull(node);\n        }\n\n        int query(int node, int nodeLeft, int nodeRight, int index) {\n            if (nodeLeft == nodeRight) {\n                return tree[node].mn;\n            }\n\n            push(node);\n            int middle = nodeLeft + (nodeRight - nodeLeft) / halfDivisor;\n            if (index <= middle) {\n                return query(node * leftChildMultiplier,\n                    nodeLeft, middle, index);\n            }\n            return query(node * leftChildMultiplier + rightChildOffset,\n                middle + 1, nodeRight, index);\n        }\n\n        int findFirst(\n            int node,\n            int nodeLeft,\n            int nodeRight,\n            int queryLeft,\n            int queryRight,\n            int target\n        ) {\n            if (queryRight < nodeLeft || nodeRight < queryLeft) {\n                return notFound;\n            }\n            if (target < tree[node].mn || target > tree[node].mx) {\n                return notFound;\n            }\n            if (nodeLeft == nodeRight) {\n                return nodeLeft;\n            }\n\n            push(node);\n            int middle = nodeLeft + (nodeRight - nodeLeft) / halfDivisor;\n            int leftAnswer = findFirst(node * leftChildMultiplier,\n                nodeLeft, middle, queryLeft, queryRight, target);\n            if (leftAnswer != notFound) {\n                return leftAnswer;\n            }\n            return findFirst(node * leftChildMultiplier + rightChildOffset,\n                middle + 1, nodeRight, queryLeft, queryRight, target);\n        }\n    };\n\n    static constexpr int noPosition = 0;\n    static constexpr int firstPosition = 1;\n    static constexpr int notFound = -1;\n    static constexpr int oddDelta = 1;\n    static constexpr int evenDelta = -1;\n    static constexpr int parityBase = 2;\n    static constexpr int rootNode = 1;\n    static constexpr int nodeFactor = 4;\n    static constexpr int halfDivisor = 2;\n    static constexpr int leftChildMultiplier = 2;\n    static constexpr int rightChildOffset = 1;\n};"
