      "code": "class Solution {\npublic:\n    vector<int> shuffle(vector<int>& nums, int n) {\n        int total = 2 * n;\n\n        for (int i = 0; i < n; ++i) {\n            int first = nums[i] % valueBase;\n            int second = nums[i + n] % valueBase;\n            nums[i] = first + second * valueBase;\n        }\n\n        for (int i = n - 1; i >= 0; --i) {\n            int encoded = nums[i];\n            nums[2 * i] = encoded % valueBase;\n            nums[2 * i + 1] = encoded / valueBase;\n        }\n\n        nums.resize(total);\n        return nums;\n    }\n\nprivate:\n    static constexpr int valueBase = 1001;\n};"
