      "code": "class Solution {\npublic:\n    int minSumOfLengths(vector<int>& arr, int target) {\n        int n = arr.size();\n        const int missing = n + 1;\n        vector<int> best(n, missing);\n\n        int answer = missing;\n        int bestLength = missing;\n        int left = 0;\n        int sum = 0;\n\n        for (int right = 0; right < n; ++right) {\n            sum += arr[right];\n\n            while (sum > target && left <= right) {\n                sum -= arr[left];\n                ++left;\n            }\n\n            if (sum == target) {\n                int currentLength = right - left + 1;\n\n                if (left > 0 && best[left - 1] != missing) {\n                    answer = min(answer, best[left - 1] + currentLength);\n                }\n\n                bestLength = min(bestLength, currentLength);\n            }\n\n            best[right] = bestLength;\n        }\n\n        if (answer == missing) {\n            return -1;\n        }\n        return answer;\n    }\n};"
