      "code": "class Solution {\npublic:\n    int minArrivalsToDiscard(vector<int>& arrivals, int w, int m) {\n        unordered_map<int, int> keptCount;\n        int n = arrivals.size();\n        vector<int> kept(n, 0);\n        int discards = 0;\n\n        for (int day = 0; day < n; ++day) {\n            // Remove the day that is no longer in the latest w days.\n            int leavingDay = day - w;\n            if (leavingDay >= 0 && kept[leavingDay] == 1) {\n                int leavingType = arrivals[leavingDay];\n                --keptCount[leavingType];\n                if (keptCount[leavingType] == 0) {\n                    keptCount.erase(leavingType);\n                }\n            }\n\n            int type = arrivals[day];\n            // If all m slots are already used, keeping today would break the rule.\n            if (keptCount[type] >= m) {\n                ++discards;\n                continue;\n            }\n\n            kept[day] = 1;\n            ++keptCount[type];\n        }\n\n        return discards;\n    }\n};"
