      "code": "class Solution {\npublic:\n    int maxCollectedFruits(vector<vector<int>>& fruits) {\n        int n = static_cast<int>(fruits.size());\n        if (n == singleCellSize) {\n            return fruits[firstIndex][firstIndex];\n        }\n\n        int diagonalFruits = noFruits;\n        for (int index = firstIndex; index < n; ++index) {\n            diagonalFruits += fruits[index][index];\n        }\n\n        vector<vector<int>> dpTop(n, vector<int>(n, unreachable));\n        dpTop[firstIndex][n - oneStep] = fruits[firstIndex][n - oneStep];\n\n        for (int row = firstIndex + oneStep; row < n - oneStep; ++row) {\n            for (int col = row + oneStep; col < n; ++col) {\n                int bestPrevious = unreachable;\n                for (int delta = -oneStep; delta <= oneStep; ++delta) {\n                    int previousCol = col + delta;\n                    if (previousCol < firstIndex || previousCol >= n) {\n                        continue;\n                    }\n                    bestPrevious = max(\n                        bestPrevious,\n                        dpTop[row - oneStep][previousCol]\n                    );\n                }\n\n                if (bestPrevious == unreachable) {\n                    continue;\n                }\n                // Only upper-triangle cells are added here. Diagonal cells\n                // were already collected by the fixed child from (0, 0).\n                dpTop[row][col] = bestPrevious + fruits[row][col];\n            }\n        }\n\n        vector<vector<int>> dpLeft(n, vector<int>(n, unreachable));\n        dpLeft[n - oneStep][firstIndex] = fruits[n - oneStep][firstIndex];\n\n        for (int col = firstIndex + oneStep; col < n - oneStep; ++col) {\n            for (int row = col + oneStep; row < n; ++row) {\n                int bestPrevious = unreachable;\n                for (int delta = -oneStep; delta <= oneStep; ++delta) {\n                    int previousRow = row + delta;\n                    if (previousRow < firstIndex || previousRow >= n) {\n                        continue;\n                    }\n                    bestPrevious = max(\n                        bestPrevious,\n                        dpLeft[previousRow][col - oneStep]\n                    );\n                }\n\n                if (bestPrevious == unreachable) {\n                    continue;\n                }\n                // This is the symmetric lower-triangle DP for the child that\n                // starts at (n - 1, 0).\n                dpLeft[row][col] = bestPrevious + fruits[row][col];\n            }\n        }\n\n        return diagonalFruits + dpTop[n - twoSteps][n - oneStep] +\n            dpLeft[n - oneStep][n - twoSteps];\n    }\n\nprivate:\n    static constexpr int firstIndex = 0;\n    static constexpr int noFruits = 0;\n    static constexpr int singleCellSize = 1;\n    static constexpr int oneStep = 1;\n    static constexpr int twoSteps = 2;\n    static constexpr int unreachable = -1000000000;\n};"
