      "code": "class Solution {\npublic:\n    vector<double> statisticsProbability(int num) {\n        const int faces = 6;\n        int maxSum = faces * num;\n        vector<vector<long long>> dp(num + 1, vector<long long>(maxSum + 1, 0));\n        dp[0][0] = 1;\n\n        for (int dice = 1; dice <= num; ++dice) {\n            for (int sum = dice; sum <= faces * dice; ++sum) {\n                for (int face = 1; face <= faces; ++face) {\n                    int previousSum = sum - face;\n                    if (previousSum < 0) {\n                        break;\n                    }\n                    dp[dice][sum] += dp[dice - 1][previousSum];\n                }\n            }\n        }\n\n        double totalWays = 1.0;\n        for (int dice = 0; dice < num; ++dice) {\n            totalWays *= faces;\n        }\n\n        vector<double> answer;\n        answer.reserve(maxSum - num + 1);\n        for (int sum = num; sum <= maxSum; ++sum) {\n            answer.push_back(dp[num][sum] / totalWays);\n        }\n        return answer;\n    }\n};"
