      "code": "class Solution {\npublic:\n    long long maxSumTrionic(vector<int>& nums) {\n        long long inc1 = invalidSum;\n        long long dec = invalidSum;\n        long long inc2 = invalidSum;\n        long long answer = invalidSum;\n\n        for (int i = firstComparableIndex;\n             i < static_cast<int>(nums.size());\n             ++i) {\n            long long previous = nums[i - previousIndexStep];\n            long long current = nums[i];\n            long long nextInc1 = invalidSum;\n            long long nextDec = invalidSum;\n            long long nextInc2 = invalidSum;\n\n            if (previous < current) {\n                nextInc1 = max(\n                    previous + current,\n                    extend(inc1, current)\n                );\n                nextInc2 = max(\n                    extend(dec, current),\n                    extend(inc2, current)\n                );\n                answer = max(answer, nextInc2);\n            } else if (previous > current) {\n                nextDec = max(\n                    extend(inc1, current),\n                    extend(dec, current)\n                );\n            }\n\n            inc1 = nextInc1;\n            dec = nextDec;\n            inc2 = nextInc2;\n        }\n\n        return answer;\n    }\n\nprivate:\n    long long extend(long long sum, long long value) const {\n        if (sum == invalidSum) {\n            return invalidSum;\n        }\n        return sum + value;\n    }\n\n    static constexpr long long invalidSum = LLONG_MIN / 4;\n    static constexpr int firstComparableIndex = 1;\n    static constexpr int previousIndexStep = 1;\n};"
