      "code": "class Solution {\npublic:\n    long long maxSumTrionic(vector<int>& nums) {\n        vector<Run> runs = buildRuns(nums);\n        vector<long long> prefix(nums.size() + extraSlot, zeroSum);\n        for (int i = 0; i < static_cast<int>(nums.size()); ++i) {\n            prefix[i + extraSlot] = prefix[i] + nums[i];\n        }\n\n        long long answer = invalidSum;\n        for (int i = 0; i + neededRuns <= static_cast<int>(runs.size()); ++i) {\n            const Run& first = runs[i];\n            const Run& second = runs[i + secondRunOffset];\n            const Run& third = runs[i + thirdRunOffset];\n\n            if (first.sign != increasing\n                || second.sign != decreasing\n                || third.sign != increasing) {\n                continue;\n            }\n            if (first.endEdge + nextEdgeStep != second.startEdge\n                || second.endEdge + nextEdgeStep != third.startEdge) {\n                continue;\n            }\n\n            int peak = first.endEdge + nextIndexStep;\n            int valley = second.endEdge + nextIndexStep;\n            int rightEnd = third.endEdge + nextIndexStep;\n\n            long long left = bestSuffixEndingAt(\n                nums,\n                first.startEdge,\n                peak\n            );\n            long long middle = rangeSum(prefix, peak + nextIndexStep, valley);\n            long long right = bestPrefixStartingAfterValley(\n                nums,\n                valley,\n                rightEnd\n            );\n            answer = max(answer, left + middle + right);\n        }\n\n        return answer;\n    }\n\nprivate:\n    struct Run {\n        int sign;\n        int startEdge;\n        int endEdge;\n    };\n\n    vector<Run> buildRuns(const vector<int>& nums) const {\n        vector<Run> runs;\n        int currentSign = flat;\n\n        for (int edge = firstEdge;\n             edge + nextIndexStep < static_cast<int>(nums.size());\n             ++edge) {\n            int sign = compare(nums[edge], nums[edge + nextIndexStep]);\n            if (sign == flat) {\n                currentSign = flat;\n                continue;\n            }\n            if (sign != currentSign) {\n                runs.push_back({sign, edge, edge});\n                currentSign = sign;\n            } else {\n                runs.back().endEdge = edge;\n            }\n        }\n\n        return runs;\n    }\n\n    int compare(int left, int right) const {\n        if (left < right) {\n            return increasing;\n        }\n        if (left > right) {\n            return decreasing;\n        }\n        return flat;\n    }\n\n    long long bestSuffixEndingAt(\n        const vector<int>& nums,\n        int left,\n        int right\n    ) const {\n        long long best = invalidSum;\n        long long sum = zeroSum;\n        for (int i = right; i >= left; --i) {\n            sum += nums[i];\n            if (i < right) {\n                best = max(best, sum);\n            }\n        }\n        return best;\n    }\n\n    long long bestPrefixStartingAfterValley(\n        const vector<int>& nums,\n        int valley,\n        int right\n    ) const {\n        long long best = invalidSum;\n        long long sum = zeroSum;\n        for (int i = valley + nextIndexStep; i <= right; ++i) {\n            sum += nums[i];\n            best = max(best, sum);\n        }\n        return best;\n    }\n\n    long long rangeSum(\n        const vector<long long>& prefix,\n        int left,\n        int right\n    ) const {\n        if (left > right) {\n            return zeroSum;\n        }\n        return prefix[right + extraSlot] - prefix[left];\n    }\n\n    static constexpr long long invalidSum = LLONG_MIN / 4;\n    static constexpr long long zeroSum = 0;\n    static constexpr int increasing = 1;\n    static constexpr int decreasing = -1;\n    static constexpr int flat = 0;\n    static constexpr int firstEdge = 0;\n    static constexpr int extraSlot = 1;\n    static constexpr int nextEdgeStep = 1;\n    static constexpr int nextIndexStep = 1;\n    static constexpr int neededRuns = 3;\n    static constexpr int secondRunOffset = 1;\n    static constexpr int thirdRunOffset = 2;\n};"
