      "code": "class Solution {\npublic:\n    int longestArithmetic(vector<int>& nums) {\n        int n = nums.size();\n        if (n <= minimumDirectLength) {\n            return n;\n        }\n\n        vector<long long> diff = buildDiff(nums);\n        vector<int> bestEnding = buildBestEnding(diff);\n        vector<int> bestStarting = buildBestStarting(diff);\n\n        int answer = longestWithoutChange(bestEnding, bestStarting);\n        for (int changed = 0; changed < n; ++changed) {\n            answer = max(\n                answer,\n                tryChangeAt(changed, nums, diff, bestEnding, bestStarting)\n            );\n        }\n        return min(answer, n);\n    }\n\nprivate:\n    vector<long long> buildDiff(const vector<int>& nums) const {\n        vector<long long> diff(nums.size(), zeroDiff);\n        for (int i = firstComparableIndex;\n             i < static_cast<int>(nums.size());\n             ++i) {\n            diff[i] = static_cast<long long>(nums[i]) - nums[i - indexStep];\n        }\n        return diff;\n    }\n\n    vector<int> buildBestEnding(const vector<long long>& diff) const {\n        vector<int> bestEnding(diff.size(), singleLength);\n        for (int i = firstComparableIndex;\n             i < static_cast<int>(diff.size());\n             ++i) {\n            bestEnding[i] = pairLength;\n            if (i >= firstTripleIndex && diff[i] == diff[i - indexStep]) {\n                bestEnding[i] = bestEnding[i - indexStep] + lengthStep;\n            }\n        }\n        return bestEnding;\n    }\n\n    vector<int> buildBestStarting(const vector<long long>& diff) const {\n        int n = diff.size();\n        vector<int> bestStarting(n, singleLength);\n        for (int i = n - secondLastOffset; i >= 0; --i) {\n            bestStarting[i] = pairLength;\n            if (i + firstTripleIndex < n\n                && diff[i + indexStep] == diff[i + firstTripleIndex]) {\n                bestStarting[i] = bestStarting[i + indexStep] + lengthStep;\n            }\n        }\n        return bestStarting;\n    }\n\n    int longestWithoutChange(\n        const vector<int>& bestEnding,\n        const vector<int>& bestStarting\n    ) const {\n        int answer = singleLength;\n        for (int length : bestEnding) {\n            answer = max(answer, length);\n        }\n        for (int length : bestStarting) {\n            answer = max(answer, length);\n        }\n        return answer;\n    }\n\n    int tryChangeAt(\n        int changed,\n        const vector<int>& nums,\n        const vector<long long>& diff,\n        const vector<int>& bestEnding,\n        const vector<int>& bestStarting\n    ) const {\n        int n = nums.size();\n        int best = singleLength;\n\n        if (changed > 0) {\n            best = max(best, bestEnding[changed - indexStep] + lengthStep);\n        }\n        if (changed + indexStep < n) {\n            best = max(best, bestStarting[changed + indexStep] + lengthStep);\n        }\n        if (changed == 0 || changed + indexStep == n) {\n            return best;\n        }\n\n        long long gap = static_cast<long long>(nums[changed + indexStep])\n            - nums[changed - indexStep];\n        if (gap % middleDivisor != 0) {\n            return best;\n        }\n\n        long long commonDiff = gap / middleDivisor;\n        int merged = middleTripleLength;\n        if (changed >= firstTripleIndex\n            && diff[changed - indexStep] == commonDiff) {\n            merged += bestEnding[changed - indexStep] - lengthStep;\n        }\n        if (changed + firstTripleIndex < n\n            && diff[changed + firstTripleIndex] == commonDiff) {\n            merged += bestStarting[changed + indexStep] - lengthStep;\n        }\n        return max(best, merged);\n    }\n\n    static constexpr long long zeroDiff = 0;\n    static constexpr int singleLength = 1;\n    static constexpr int pairLength = 2;\n    static constexpr int middleTripleLength = 3;\n    static constexpr int minimumDirectLength = 2;\n    static constexpr int firstComparableIndex = 1;\n    static constexpr int firstTripleIndex = 2;\n    static constexpr int secondLastOffset = 2;\n    static constexpr int indexStep = 1;\n    static constexpr int lengthStep = 1;\n    static constexpr int middleDivisor = 2;\n};"
