      "code": "class Solution {\npublic:\n    int minimumPairRemoval(vector<int>& nums) {\n        int operations = noOperation;\n\n        while (!isNondecreasing(nums)) {\n            int left = findLeftmostMinimumPair(nums);\n            nums[left] += nums[left + nextIndexStep];\n            nums.erase(nums.begin() + left + nextIndexStep);\n            ++operations;\n        }\n\n        return operations;\n    }\n\nprivate:\n    bool isNondecreasing(const vector<int>& nums) const {\n        for (int i = firstComparableIndex;\n             i < static_cast<int>(nums.size());\n             ++i) {\n            if (nums[i - previousIndexStep] > nums[i]) {\n                return false;\n            }\n        }\n        return true;\n    }\n\n    int findLeftmostMinimumPair(const vector<int>& nums) const {\n        int bestLeft = firstIndex;\n        long long bestSum = static_cast<long long>(nums[firstIndex])\n            + nums[firstIndex + nextIndexStep];\n\n        for (int left = firstIndex + nextIndexStep;\n             left + nextIndexStep < static_cast<int>(nums.size());\n             ++left) {\n            long long sum = static_cast<long long>(nums[left])\n                + nums[left + nextIndexStep];\n            if (sum < bestSum) {\n                bestSum = sum;\n                bestLeft = left;\n            }\n        }\n\n        return bestLeft;\n    }\n\n    static constexpr int firstIndex = 0;\n    static constexpr int firstComparableIndex = 1;\n    static constexpr int previousIndexStep = 1;\n    static constexpr int nextIndexStep = 1;\n    static constexpr int noOperation = 0;\n};"
