      "sourceUrl": "https://leetcode.cn/problems/minimum-pair-removal-to-sort-array-i/description/",
      "code": "class Solution {\npublic:\n    int minimumPairRemoval(vector<int>& nums) {\n        int n = static_cast<int>(nums.size());\n        if (n <= singleElementSize) {\n            return noOperation;\n        }\n\n        values.assign(nums.begin(), nums.end());\n        previous.resize(n);\n        next.resize(n);\n        alive.assign(n, true);\n\n        priority_queue<Pair, vector<Pair>, ComparePair> heap;\n        for (int index = firstIndex; index < n; ++index) {\n            previous[index] = index - previousIndexStep;\n            next[index] = index + nextIndexStep;\n        }\n        next[n - lastIndexOffset] = missingIndex;\n\n        int badPairs = noBadPair;\n        for (int left = firstIndex; left < n; ++left) {\n            if (isBadPair(left)) {\n                ++badPairs;\n            }\n            pushPair(left, heap);\n        }\n\n        int operations = noOperation;\n        while (badPairs > noBadPair) {\n            Pair current = popCurrentPair(heap);\n            int left = current.left;\n            int right = current.right;\n            int beforeLeft = previous[left];\n            int afterRight = next[right];\n\n            removeBadPair(beforeLeft, badPairs);\n            removeBadPair(left, badPairs);\n            removeBadPair(right, badPairs);\n\n            values[left] += values[right];\n            alive[right] = false;\n            next[left] = afterRight;\n            if (afterRight != missingIndex) {\n                previous[afterRight] = left;\n            }\n\n            addBadPair(beforeLeft, badPairs);\n            addBadPair(left, badPairs);\n\n            pushPair(beforeLeft, heap);\n            pushPair(left, heap);\n            ++operations;\n        }\n\n        return operations;\n    }\n\nprivate:\n    struct Pair {\n        long long sum;\n        int left;\n        int right;\n    };\n\n    struct ComparePair {\n        bool operator()(const Pair& left, const Pair& right) const {\n            if (left.sum != right.sum) {\n                return left.sum > right.sum;\n            }\n            return left.left > right.left;\n        }\n    };\n\n    Pair popCurrentPair(\n        priority_queue<Pair, vector<Pair>, ComparePair>& heap\n    ) const {\n        while (true) {\n            Pair current = heap.top();\n            heap.pop();\n            if (isCurrentPair(current)) {\n                return current;\n            }\n        }\n    }\n\n    bool isCurrentPair(const Pair& pair) const {\n        int left = pair.left;\n        if (left < firstIndex || left >= static_cast<int>(values.size())) {\n            return false;\n        }\n        if (!alive[left] || next[left] != pair.right) {\n            return false;\n        }\n\n        int right = pair.right;\n        if (right == missingIndex || !alive[right]) {\n            return false;\n        }\n\n        // A stale heap record can survive after one endpoint changes.\n        return pair.sum == values[left] + values[right];\n    }\n\n    void pushPair(\n        int left,\n        priority_queue<Pair, vector<Pair>, ComparePair>& heap\n    ) const {\n        if (left == missingIndex || !alive[left]) {\n            return;\n        }\n\n        int right = next[left];\n        if (right == missingIndex || !alive[right]) {\n            return;\n        }\n\n        heap.push(Pair{values[left] + values[right], left, right});\n    }\n\n    bool isBadPair(int left) const {\n        if (left == missingIndex || !alive[left]) {\n            return false;\n        }\n\n        int right = next[left];\n        return right != missingIndex\n            && alive[right]\n            && values[left] > values[right];\n    }\n\n    void removeBadPair(int left, int& badPairs) const {\n        if (isBadPair(left)) {\n            --badPairs;\n        }\n    }\n\n    void addBadPair(int left, int& badPairs) const {\n        if (isBadPair(left)) {\n            ++badPairs;\n        }\n    }\n\n    vector<long long> values;\n    vector<int> previous;\n    vector<int> next;\n    vector<bool> alive;\n\n    static constexpr int firstIndex = 0;\n    static constexpr int singleElementSize = 1;\n    static constexpr int previousIndexStep = 1;\n    static constexpr int nextIndexStep = 1;\n    static constexpr int lastIndexOffset = 1;\n    static constexpr int missingIndex = -1;\n    static constexpr int noBadPair = 0;\n    static constexpr int noOperation = 0;\n};"
