      "code": "class Solution {\npublic:\n    bool verifyTreeOrder(vector<int>& postorder) {\n        stack<int> ancestors;\n        long long upperBound = numeric_limits<long long>::max();\n\n        for (int index = static_cast<int>(postorder.size()) - lastIndexOffset;\n             index >= firstIndex;\n             --index) {\n            int value = postorder[index];\n            if (value > upperBound) {\n                return false;\n            }\n\n            while (!ancestors.empty() && value < ancestors.top()) {\n                // Moving from a right subtree into its ancestor's left side.\n                upperBound = ancestors.top();\n                ancestors.pop();\n            }\n\n            ancestors.push(value);\n        }\n\n        return true;\n    }\n\nprivate:\n    static constexpr int firstIndex = 0;\n    static constexpr int lastIndexOffset = 1;\n};"
