      "code": "class Solution {\npublic:\n    TreeNode* inorderSuccessor(TreeNode* root, TreeNode* p) {\n        TreeNode* successor = nullptr;\n        TreeNode* node = root;\n\n        while (node != nullptr) {\n            if (node->val > p->val) {\n                // This node is valid; the left side may be smaller.\n                successor = node;\n                node = node->left;\n            } else {\n                // This node and its left side are not greater than p.\n                node = node->right;\n            }\n        }\n\n        return successor;\n    }\n};"
