      "code": "class Solution {\npublic:\n    TreeNode* inorderSuccessor(TreeNode* root, TreeNode* p) {\n        stack<TreeNode*> nodes;\n        TreeNode* node = root;\n        bool previousIsTarget = false;\n\n        while (node != nullptr || !nodes.empty()) {\n            while (node != nullptr) {\n                nodes.push(node);\n                node = node->left;\n            }\n\n            node = nodes.top();\n            nodes.pop();\n\n            if (previousIsTarget) {\n                return node;\n            }\n            if (node == p) {\n                // The next inorder node will be the successor.\n                previousIsTarget = true;\n            }\n\n            node = node->right;\n        }\n\n        return nullptr;\n    }\n};"
