      "code": "class Solution {\npublic:\n    double separateSquares(vector<vector<int>>& squares) {\n        long double low =\n            static_cast<long double>(squares[firstIndex][bottomIndex]);\n        long double high = low;\n        long double totalArea = noArea;\n\n        for (const vector<int>& square : squares) {\n            long double bottom =\n                static_cast<long double>(square[bottomIndex]);\n            long double side =\n                static_cast<long double>(square[sideIndex]);\n            long double top = bottom + side;\n\n            low = min(low, bottom);\n            high = max(high, top);\n            totalArea += side * side;\n        }\n\n        long double targetArea = totalArea / equalParts;\n\n        for (int iteration = firstIteration;\n             iteration < binarySearchIterations;\n             ++iteration) {\n            long double mid = low + (high - low) / equalParts;\n\n            if (areaBelow(squares, mid) >= targetArea) {\n                high = mid;\n            } else {\n                low = mid;\n            }\n        }\n\n        return static_cast<double>(high);\n    }\n\nprivate:\n    long double areaBelow(\n        const vector<vector<int>>& squares,\n        long double lineY\n    ) const {\n        long double area = noArea;\n\n        for (const vector<int>& square : squares) {\n            long double bottom =\n                static_cast<long double>(square[bottomIndex]);\n            long double side =\n                static_cast<long double>(square[sideIndex]);\n            long double top = bottom + side;\n\n            if (lineY <= bottom) {\n                continue;\n            }\n            if (lineY >= top) {\n                area += side * side;\n                continue;\n            }\n\n            area += (lineY - bottom) * side;\n        }\n\n        return area;\n    }\n\n    static constexpr int firstIndex = 0;\n    static constexpr int bottomIndex = 1;\n    static constexpr int sideIndex = 2;\n    static constexpr int firstIteration = 0;\n    static constexpr int binarySearchIterations = 80;\n    static constexpr long double noArea = 0.0L;\n    static constexpr long double equalParts = 2.0L;\n};"
