      "code": "class Solution {\npublic:\n    double separateSquares(vector<vector<int>>& squares) {\n        vector<Event> events;\n        events.reserve(squares.size() * eventsPerSquare);\n\n        long double totalArea = noArea;\n        for (const vector<int>& square : squares) {\n            long long bottom = square[bottomIndex];\n            long long side = square[sideIndex];\n            long long top = bottom + side;\n            long double width = static_cast<long double>(side);\n\n            totalArea += width * width;\n            events.push_back(Event{bottom, width});\n            events.push_back(Event{top, -width});\n        }\n\n        sort(events.begin(), events.end(), [](const Event& left,\n                                              const Event& right) {\n            return left.y < right.y;\n        });\n\n        long double targetArea = totalArea / equalParts;\n        long double currentArea = noArea;\n        long double activeWidth = noWidth;\n        long long currentY = events[firstIndex].y;\n        int eventIndex = firstIndex;\n\n        while (eventIndex < static_cast<int>(events.size())) {\n            long long nextY = events[eventIndex].y;\n            long double height =\n                static_cast<long double>(nextY - currentY);\n            long double nextArea = currentArea + activeWidth * height;\n\n            if (activeWidth > noWidth && nextArea >= targetArea) {\n                long double extraHeight =\n                    (targetArea - currentArea) / activeWidth;\n                return static_cast<double>(\n                    static_cast<long double>(currentY) + extraHeight\n                );\n            }\n\n            currentArea = nextArea;\n            currentY = nextY;\n\n            while (eventIndex < static_cast<int>(events.size())\n                   && events[eventIndex].y == currentY) {\n                activeWidth += events[eventIndex].slopeDelta;\n                ++eventIndex;\n            }\n\n            if (currentArea >= targetArea) {\n                return static_cast<double>(currentY);\n            }\n        }\n\n        return static_cast<double>(currentY);\n    }\n\nprivate:\n    struct Event {\n        long long y;\n        long double slopeDelta;\n    };\n\n    static constexpr int firstIndex = 0;\n    static constexpr int bottomIndex = 1;\n    static constexpr int sideIndex = 2;\n    static constexpr int eventsPerSquare = 2;\n    static constexpr long double noArea = 0.0L;\n    static constexpr long double noWidth = 0.0L;\n    static constexpr long double equalParts = 2.0L;\n};"
