      "code": "class Codec {\npublic:\n    string serialize(TreeNode* root) {\n        if (root == nullptr) {\n            return string(nullTokenSize, nullMarker);\n        }\n\n        string data;\n        queue<TreeNode*> nodes;\n        nodes.push(root);\n\n        while (!nodes.empty()) {\n            TreeNode* node = nodes.front();\n            nodes.pop();\n\n            if (node == nullptr) {\n                // The marker keeps left-only and right-only shapes distinct.\n                data.push_back(nullMarker);\n                data.push_back(delimiter);\n                continue;\n            }\n\n            data += to_string(node->val);\n            data.push_back(delimiter);\n            nodes.push(node->left);\n            nodes.push(node->right);\n        }\n\n        return data;\n    }\n\n    TreeNode* deserialize(string data) {\n        vector<string> tokens = split(data);\n        if (tokens.empty() || isNullToken(tokens[firstTokenIndex])) {\n            return nullptr;\n        }\n\n        TreeNode* root = new TreeNode(stoi(tokens[firstTokenIndex]));\n        queue<TreeNode*> nodes;\n        nodes.push(root);\n\n        int tokenIndex = firstChildTokenIndex;\n        while (!nodes.empty()\n               && tokenIndex < static_cast<int>(tokens.size())) {\n            TreeNode* parent = nodes.front();\n            nodes.pop();\n\n            attachChild(parent->left, nodes, tokens[tokenIndex]);\n            ++tokenIndex;\n            if (tokenIndex >= static_cast<int>(tokens.size())) {\n                break;\n            }\n\n            attachChild(parent->right, nodes, tokens[tokenIndex]);\n            ++tokenIndex;\n        }\n\n        return root;\n    }\n\nprivate:\n    vector<string> split(const string& data) const {\n        vector<string> tokens;\n        stringstream input(data);\n        string token;\n\n        while (getline(input, token, delimiter)) {\n            if (!token.empty()) {\n                tokens.push_back(token);\n            }\n        }\n\n        return tokens;\n    }\n\n    void attachChild(\n        TreeNode*& child,\n        queue<TreeNode*>& nodes,\n        const string& token\n    ) const {\n        if (isNullToken(token)) {\n            child = nullptr;\n            return;\n        }\n\n        child = new TreeNode(stoi(token));\n        nodes.push(child);\n    }\n\n    bool isNullToken(const string& token) const {\n        return token.size() == nullTokenSize\n               && token[firstTokenChar] == nullMarker;\n    }\n\n    static constexpr char delimiter = ',';\n    static constexpr char nullMarker = '#';\n    static constexpr int firstTokenChar = 0;\n    static constexpr int nullTokenSize = 1;\n    static constexpr int firstTokenIndex = 0;\n    static constexpr int firstChildTokenIndex = 1;\n};"
