      "code": "class Solution {\npublic:\n    int xorAfterQueries(vector<int>& nums, vector<vector<int>>& queries) {\n        int n = static_cast<int>(nums.size());\n        int block = static_cast<int>(sqrt(n)) + 1;\n\n        vector<vector<vector<Event>>> events(block + 1);\n        for (int step = 1; step <= block; ++step) {\n            events[step].resize(step);\n        }\n\n        for (const vector<int>& query : queries) {\n            int left = query[leftIndex];\n            int right = query[rightIndex];\n            int step = query[stepIndex];\n            int multiplier = query[multiplierIndex];\n\n            if (step > block) {\n                applyDirect(nums, left, right, step, multiplier);\n                continue;\n            }\n\n            int residue = left % step;\n            int leftPosition = (left - residue) / step;\n            int rightPosition = (right - residue) / step;\n\n            // In this step/residue sequence, the touched positions are\n            // continuous, so one range event can represent the whole query.\n            events[step][residue].push_back({leftPosition, multiplier});\n\n            int sequenceLength = (n - 1 - residue) / step + 1;\n            int afterRight = rightPosition + 1;\n            if (afterRight < sequenceLength) {\n                int inverse = static_cast<int>(\n                    modPower(multiplier, mod - 2)\n                );\n                events[step][residue].push_back({afterRight, inverse});\n            }\n        }\n\n        applySmallStepEvents(nums, events);\n\n        int answer = 0;\n        for (int value : nums) {\n            answer ^= value;\n        }\n        return answer;\n    }\n\nprivate:\n    struct Event {\n        int position;\n        int multiplier;\n    };\n\n    void applyDirect(\n        vector<int>& nums,\n        int left,\n        int right,\n        int step,\n        int multiplier\n    ) const {\n        for (int index = left; index <= right; index += step) {\n            nums[index] = static_cast<int>(\n                static_cast<long long>(nums[index]) * multiplier % mod\n            );\n        }\n    }\n\n    void applySmallStepEvents(\n        vector<int>& nums,\n        vector<vector<vector<Event>>>& events\n    ) const {\n        int n = static_cast<int>(nums.size());\n        int block = static_cast<int>(events.size()) - 1;\n\n        for (int step = 1; step <= block; ++step) {\n            for (int residue = 0; residue < step; ++residue) {\n                vector<Event>& group = events[step][residue];\n                if (group.empty()) {\n                    continue;\n                }\n\n                sort(group.begin(), group.end(), [](const Event& left,\n                                                    const Event& right) {\n                    return left.position < right.position;\n                });\n\n                long long runningMultiplier = 1;\n                int nextEvent = 0;\n                int position = 0;\n\n                for (int index = residue; index < n; index += step) {\n                    while (nextEvent < static_cast<int>(group.size())\n                           && group[nextEvent].position == position) {\n                        // Multiplying by an inverse event turns off the range.\n                        runningMultiplier =\n                            runningMultiplier * group[nextEvent].multiplier\n                            % mod;\n                        ++nextEvent;\n                    }\n\n                    nums[index] = static_cast<int>(\n                        static_cast<long long>(nums[index])\n                        * runningMultiplier\n                        % mod\n                    );\n                    ++position;\n                }\n            }\n        }\n    }\n\n    long long modPower(long long base, int exponent) const {\n        long long result = 1;\n        base %= mod;\n\n        while (exponent > 0) {\n            if ((exponent & 1) != 0) {\n                result = result * base % mod;\n            }\n            base = base * base % mod;\n            exponent >>= 1;\n        }\n\n        return result;\n    }\n\n    static constexpr int mod = 1000000007;\n    static constexpr int leftIndex = 0;\n    static constexpr int rightIndex = 1;\n    static constexpr int stepIndex = 2;\n    static constexpr int multiplierIndex = 3;\n};"
